-- Schema for Domain: inventory | Business: Manufacturing | Version: v1_ecm
-- Generated on: 2026-04-16 07:42:34

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `manufacturing_ecm`.`inventory` COMMENT 'SSOT for all inventory positions, SKU stock levels, inventory transactions, warehouse locations, and WMS operations. Manages raw materials, WIP, finished goods, and MRO stock across all plant and distribution center locations. Covers cycle counting, ABC classification, safety stock, reorder points, and inventory valuation.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `manufacturing_ecm`.`inventory`.`stock_position` (
    `stock_position_id` BIGINT COMMENT 'Unique surrogate identifier for each stock position record in the inventory data product. Serves as the primary key for the stock_position entity in the Databricks Silver Layer.',
    `component_id` BIGINT COMMENT 'Foreign key linking to engineering.component. Business justification: Stock positions track on-hand quantities by component. MRP systems use component lead times, BOMs, and lifecycle states to calculate material requirements and trigger replenishment.',
    `inventory_sku_id` BIGINT COMMENT 'Foreign key linking to inventory.sku. Business justification: stock_position.sku (STRING) is a denormalized SKU code. Normalizing to sku_id FK against the sku master eliminates redundant descriptive columns. The sku master is the SSOT for material_description, m',
    `lot_batch_id` BIGINT COMMENT 'Foreign key linking to inventory.lot_batch. Business justification: stock_position.batch_number is a denormalized batch reference. Normalizing to lot_batch_id FK against the lot_batch master enables full batch traceability from the stock position.',
    `reorder_policy_id` BIGINT COMMENT 'Foreign key linking to inventory.reorder_policy. Business justification: stock_position tracks reorder_point and safety_stock_quantity which are governed by reorder_policy. Adding reorder_policy_id FK links each stock position to its governing replenishment policy, enablin',
    `sales_price_list_id` BIGINT COMMENT 'Foreign key linking to sales.price_list. Business justification: Stock positions reference price lists to determine inventory valuation and available-to-promise pricing. Warehouse systems check price lists when reserving stock for sales orders to calculate order va',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: stock_position.storage_location_code is a denormalized location code. Normalizing to storage_location_id FK against the storage_location master eliminates the redundant code column.',
    `warehouse_id` BIGINT COMMENT 'Foreign key linking to inventory.warehouse. Business justification: stock_position.warehouse_number is a denormalized warehouse code. Normalizing to warehouse_id FK against the warehouse master eliminates the redundant code column and enables joins to full warehouse a',
    `abc_classification` STRING COMMENT 'ABC classification of the material based on consumption value or usage frequency. A-items are high-value/high-usage requiring tight control; B-items are medium; C-items are low-value/low-usage. D may indicate dead stock. Drives cycle counting frequency and replenishment strategy.. Valid values are `A|B|C|D`',
    `atp_quantity` DECIMAL(18,2) COMMENT 'Quantity of the material available to commit to new customer orders or production demands, calculated as unrestricted quantity minus reserved quantity. Supports ATP (Available-to-Promise) and CTP (Capable-to-Promise) checks in order management.',
    `blocked_quantity` DECIMAL(18,2) COMMENT 'Quantity of the material that has been blocked and is not available for any use, typically due to quality rejection, damage, or regulatory hold. Corresponds to SAP MARD-SPEME (blocked stock).',
    `consignment_quantity` DECIMAL(18,2) COMMENT 'Quantity of the material held at the companys premises but owned by the supplier (vendor consignment stock). Liability is incurred only upon consumption. Corresponds to SAP special stock type K (vendor consignment).',
    `count_variance_quantity` DECIMAL(18,2) COMMENT 'The difference between the physically counted quantity and the system book quantity at the time of the last physical inventory or cycle count. Positive values indicate surplus; negative values indicate shortage. Used for inventory accuracy KPI reporting.',
    `country_of_origin` STRING COMMENT 'ISO 3166-1 alpha-3 country code indicating the country where the material was manufactured or produced. Required for customs declarations, import/export compliance, REACH/RoHS regulatory reporting, and trade preference determination.. Valid values are `^[A-Z]{3}$`',
    `goods_receipt_date` DATE COMMENT 'The date on which the most recent goods receipt was posted for this stock position. Used for FIFO valuation, aging analysis, and supplier delivery performance tracking. Corresponds to SAP MSEG-BUDAT (posting date of goods movement).. Valid values are `^d{4}-d{2}-d{2}$`',
    `hazardous_material_indicator` BOOLEAN COMMENT 'Flag indicating whether the material is classified as hazardous and subject to special storage, handling, and transportation regulations. Drives compliance with OSHA, EPA, REACH, RoHS, and dangerous goods regulations.. Valid values are `true|false`',
    `in_transit_quantity` DECIMAL(18,2) COMMENT 'Quantity of the material that has been shipped from a source location but has not yet been received at the destination location. Includes stock in transfer orders between plants or from suppliers. Corresponds to SAP stock in transit (MARD-UMLME).',
    `last_count_date` DATE COMMENT 'The date on which the most recent physical inventory count or cycle count was performed for this stock position. Used to assess count freshness and schedule next cycle count. Corresponds to SAP MARD-LSOBS (date of last count).. Valid values are `^d{4}-d{2}-d{2}$`',
    `last_movement_date` DATE COMMENT 'The date of the most recent inventory movement (goods receipt, goods issue, transfer, or adjustment) for this stock position. Used to identify slow-moving or obsolete inventory for write-down analysis.. Valid values are `^d{4}-d{2}-d{2}$`',
    `lot_size_procedure` STRING COMMENT 'The lot-sizing rule applied during MRP planning to determine the replenishment order quantity. Options include exact lot size (order exactly what is needed), fixed lot size, economic order quantity (EOQ), and period-based lot sizing.. Valid values are `exact|fixed|economic_order_quantity|period|min_max|replenish_to_max`',
    `maximum_stock_level` DECIMAL(18,2) COMMENT 'The upper inventory quantity threshold beyond which stock should not be replenished, used to prevent overstock and excess carrying costs. Corresponds to SAP MARC-MABST (maximum stock level).',
    `mrp_type` STRING COMMENT 'Defines the planning procedure used for this materials replenishment. Determines whether the material is planned via MRP (demand-driven), consumption-based reorder point, forecast-based planning, or managed manually. Corresponds to SAP MARC-DISMM.. Valid values are `consumption_based|mrp|manual|no_planning|reorder_point|forecast_based`',
    `on_hand_quantity` DECIMAL(18,2) COMMENT 'Total physical quantity of the material currently present at the storage location, regardless of stock type. Represents the gross inventory count before any reservations or holds are applied. Sourced from SAP MARD-LABST + EINME + SPEME.',
    `plant_code` STRING COMMENT 'Identifier for the manufacturing plant or distribution center where the stock position is held. Corresponds to the SAP Plant organizational unit. Enables multi-plant inventory visibility and reporting.. Valid values are `^[A-Z0-9]{1,10}$`',
    `position_snapshot_timestamp` TIMESTAMP COMMENT 'The exact date and time at which this stock position record was captured or last refreshed from the source systems (SAP S/4HANA MM and Infor WMS). Enables point-in-time inventory reporting and audit trail for the Silver Layer data product.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `quality_inspection_quantity` DECIMAL(18,2) COMMENT 'Quantity of the material currently held in quality inspection and not yet released for use. Pending QM (Quality Management) inspection lot disposition. Corresponds to SAP MARD-EINME.',
    `reorder_point` DECIMAL(18,2) COMMENT 'The minimum stock level at which a replenishment order should be triggered to avoid stockout. Used in MRP (Material Requirements Planning) reorder point planning. Corresponds to SAP MARC-MINBE.',
    `reserved_quantity` DECIMAL(18,2) COMMENT 'Quantity of the material that has been reserved for specific production orders, sales orders, or project requirements and is therefore not available for other demands. Sourced from SAP reservation management (RESB).',
    `safety_stock_quantity` DECIMAL(18,2) COMMENT 'The buffer stock quantity maintained to protect against demand variability and supply uncertainty, preventing stockouts. Corresponds to SAP MARC-EISBE (safety stock). A key input to MRP planning runs.',
    `shelf_life_expiration_date` DATE COMMENT 'The date on which the current batch or stock position expires and can no longer be used. Applicable to batch-managed materials with shelf-life management enabled. Drives FEFO (First Expired First Out) picking strategies.. Valid values are `^d{4}-d{2}-d{2}$`',
    `slow_moving_indicator` BOOLEAN COMMENT 'Flag indicating whether this stock position has been classified as slow-moving based on the absence of inventory movements over a defined threshold period. Triggers review for potential write-down or disposal actions.. Valid values are `true|false`',
    `stock_category` STRING COMMENT 'Indicates the ownership or special stock category of the inventory position. Distinguishes company-owned stock from consignment stock, returnable packaging, pipeline stock, and customer/project-specific stock.. Valid values are `own|consignment|returnable_packaging|pipeline|project_stock|sales_order_stock`',
    `stock_type` STRING COMMENT 'Classification of the stock by its usability and availability status. Unrestricted stock is available for use; quality inspection stock is pending QM release; blocked stock is not available; in-transit stock is between locations. Drives ATP (Available-to-Promise) calculations.. Valid values are `unrestricted|quality_inspection|blocked|restricted|in_transit|consignment|project|sales_order`',
    `total_stock_value` DECIMAL(18,2) COMMENT 'Total monetary value of the on-hand stock position, calculated as on-hand quantity multiplied by the valuation price. Expressed in the valuation currency. Used for balance sheet inventory reporting and financial close processes.',
    `unit_of_measure` STRING COMMENT 'The base unit of measure in which all stock quantities for this material are expressed (e.g., EA for each, KG for kilogram, L for liter, M for meter). Corresponds to SAP MARA-MEINS (base unit of measure).. Valid values are `EA|KG|G|LB|L|ML|M|M2|M3|FT|IN|PC|BOX|PAL|ROL|SET|HR|MIN`',
    `unrestricted_quantity` DECIMAL(18,2) COMMENT 'Quantity of the material that is freely available for use, sales order fulfillment, or production consumption without any quality or usage restrictions. Corresponds to SAP MARD-LABST (unrestricted-use stock).',
    `valuation_currency` STRING COMMENT 'ISO 4217 three-letter currency code in which the inventory valuation price and stock value are expressed (e.g., USD, EUR, GBP). Supports multi-currency reporting for multinational operations.. Valid values are `^[A-Z]{3}$`',
    `valuation_method` STRING COMMENT 'The costing method applied to value the inventory position. Standard price uses a fixed planned cost; moving average price recalculates with each goods receipt. FIFO and LIFO are used in specific regulatory contexts.. Valid values are `standard_price|moving_average_price|fifo|lifo|weighted_average`',
    `valuation_price` DECIMAL(18,2) COMMENT 'The per-unit price used to value the inventory position, based on the materials valuation method (standard price or moving average price). Corresponds to SAP MBEW-STPRS (standard price) or MBEW-VERPR (moving average price).',
    `valuation_type` STRING COMMENT 'Sub-classification of a material for split valuation purposes, allowing different batches or procurement types (e.g., domestic vs. imported) to be valued separately within the same material and plant.',
    `wip_quantity` DECIMAL(18,2) COMMENT 'Quantity of the material currently in the production process as Work-in-Progress (WIP), issued to production orders but not yet completed as finished goods. Tracked via Siemens Opcenter MES and SAP PP production orders.',
    CONSTRAINT pk_stock_position PRIMARY KEY(`stock_position_id`)
) COMMENT 'SSOT for current inventory positions across all SKUs, storage locations, plants, and distribution centers. Captures on-hand quantity, reserved quantity, available-to-promise (ATP) quantity, WIP stock, and in-transit stock for raw materials, finished goods, semi-finished goods, and MRO items. Aligned with SAP S/4HANA MM stock overview and Infor WMS inventory balance records.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`inventory`.`storage_location` (
    `storage_location_id` BIGINT COMMENT 'Unique surrogate identifier for each storage location record within the warehouse or plant facility. Serves as the primary key for the storage_location data product in the Databricks Silver Layer.',
    `warehouse_id` BIGINT COMMENT 'Foreign key linking to inventory.warehouse. Business justification: storage_location.warehouse_code is a denormalized warehouse code. A storage location (aisle/rack/bin) physically belongs to exactly one warehouse facility. Normalizing to warehouse_id FK establishes t',
    `abc_class` STRING COMMENT 'ABC inventory classification assigned to the storage location based on the velocity and value of materials typically stored there. Drives slotting optimization — A-class locations are positioned for fastest access, supporting lean and JIT replenishment strategies.. Valid values are `A|B|C|X`',
    `aisle` STRING COMMENT 'Alphanumeric identifier for the aisle within the warehouse where this storage location is physically situated. Used for navigation, putaway routing, and picking path optimization.. Valid values are `^[A-Z0-9-]{1,10}$`',
    `bin` STRING COMMENT 'Specific bin or slot identifier within a rack level, representing the most granular physical storage unit. Corresponds to the SAP WM storage bin and Infor WMS bin location.. Valid values are `^[A-Z0-9-]{1,10}$`',
    `block_reason` STRING COMMENT 'Reason code explaining why a storage location has been blocked or taken out of service. Required for quality management traceability and corrective action processes (CAPA).. Valid values are `damage|contamination|quarantine|maintenance|capacity_exceeded|hazmat_inspection|audit_hold|`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the country where this storage location is physically situated. Supports multi-country inventory reporting, regulatory compliance, and cross-border logistics management.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp recording when this storage location master record was first created in the system. Supports data lineage, audit trail requirements, and master data governance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `cycle_count_indicator` STRING COMMENT 'Cycle counting frequency classification assigned to this storage location, determining how often physical inventory counts are performed. A-class locations are counted most frequently. Supports inventory accuracy programs and audit compliance.. Valid values are `A|B|C|excluded|`',
    `decommission_date` DATE COMMENT 'Date on which this storage location was or is scheduled to be permanently decommissioned and removed from active warehouse operations. Supports warehouse layout lifecycle management and historical reporting.. Valid values are `^d{4}-d{2}-d{2}$`',
    `effective_date` DATE COMMENT 'Date from which this storage location record became or becomes operationally active. Supports temporal validity management for location master data and warehouse layout change tracking.. Valid values are `^d{4}-d{2}-d{2}$`',
    `external_location_code` STRING COMMENT 'Location identifier used in external or third-party systems such as 3PL warehouse management systems, customer portals, or EDI integrations. Enables cross-system location reconciliation for multi-system environments.',
    `fire_protection_class` STRING COMMENT 'Fire protection classification assigned to the storage location based on the type of materials stored and applicable fire suppression systems. Supports HSE compliance and emergency response planning.. Valid values are `class_a|class_b|class_c|class_d|class_k|none|not_applicable`',
    `hazmat_class` STRING COMMENT 'UN/DOT hazardous materials classification for the storage location, indicating the category of dangerous goods that may be stored. Drives segregation rules, safety signage requirements, and regulatory compliance for hazmat storage zones.. Valid values are `class_1|class_2|class_3|class_4|class_5|class_6|class_7|class_8|class_9|none`',
    `height_mm` DECIMAL(18,2) COMMENT 'Internal height dimension of the storage location in millimeters. Critical for tall or oversized SKU putaway validation and rack clearance compliance.. Valid values are `^d{1,7}(.d{1,2})?$`',
    `last_cycle_count_date` DATE COMMENT 'Date on which the most recent physical cycle count was performed for this storage location. Used to schedule upcoming counts, assess inventory accuracy, and support audit trail requirements.. Valid values are `^d{4}-d{2}-d{2}$`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this storage location master record. Used for change tracking, data synchronization between SAP WM and Infor WMS, and audit trail compliance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `length_mm` DECIMAL(18,2) COMMENT 'Internal length dimension of the storage location in millimeters. Used for dimensional compatibility checks during putaway to ensure SKU packaging fits within the bin.. Valid values are `^d{1,7}(.d{1,2})?$`',
    `level` STRING COMMENT 'Vertical level or tier designation within a rack or shelving unit (e.g., floor level, level 1, level 2). Used for ergonomic slotting, weight distribution planning, and picking efficiency.. Valid values are `^[A-Z0-9-]{1,10}$`',
    `location_code` STRING COMMENT 'Business-facing alphanumeric code uniquely identifying the storage location within a warehouse or plant. Used in SAP WM as the storage bin number and in Infor WMS as the location ID for putaway and picking operations.. Valid values are `^[A-Z0-9-.]{1,30}$`',
    `location_name` STRING COMMENT 'Descriptive human-readable name or label for the storage location, used for display in warehouse management interfaces, picking lists, and operational reports.',
    `location_type` STRING COMMENT 'Indicates whether the storage location is fixed (assigned to a specific SKU), random (dynamically assigned), dedicated, shared, or virtual. Determines slotting strategy and WMS putaway logic.. Valid values are `fixed|random|dedicated|shared|overflow|virtual`',
    `max_pallet_count` STRING COMMENT 'Maximum number of pallets or handling units that can be stored simultaneously in this location. Used for pallet-level capacity management and putaway strategy in Infor WMS.. Valid values are `^d{1,4}$`',
    `max_temperature_c` DECIMAL(18,2) COMMENT 'Maximum allowable temperature in degrees Celsius for this storage location. Enforced for hazardous material storage compliance and product quality preservation.. Valid values are `^-?d{1,3}(.d{1,2})?$`',
    `max_volume_m3` DECIMAL(18,2) COMMENT 'Maximum volumetric capacity of the storage location in cubic meters. Used for volumetric putaway checks and space utilization analytics.. Valid values are `^d{1,6}(.d{1,4})?$`',
    `max_weight_kg` DECIMAL(18,2) COMMENT 'Maximum allowable weight in kilograms that the storage location can safely hold. Enforced during putaway to prevent structural overloading and ensure workplace safety compliance.. Valid values are `^d{1,7}(.d{1,3})?$`',
    `min_temperature_c` DECIMAL(18,2) COMMENT 'Minimum allowable temperature in degrees Celsius for this storage location. Used for environmental compliance monitoring and material storage condition validation.. Valid values are `^-?d{1,3}(.d{1,2})?$`',
    `mixed_lot_allowed` BOOLEAN COMMENT 'Indicates whether multiple lot or batch numbers of the same SKU may be stored together in this location. Critical for pharmaceutical, food, and regulated component traceability and FIFO/FEFO compliance.. Valid values are `true|false`',
    `mixed_sku_allowed` BOOLEAN COMMENT 'Indicates whether multiple distinct SKUs may be co-located within this storage location simultaneously. When false, the location is restricted to a single SKU to prevent picking errors and inventory commingling.. Valid values are `true|false`',
    `next_cycle_count_date` DATE COMMENT 'Planned date for the next physical cycle count at this storage location. Drives cycle count scheduling workflows in SAP MM and Infor WMS to maintain inventory accuracy targets.. Valid values are `^d{4}-d{2}-d{2}$`',
    `picking_strategy` STRING COMMENT 'Picking strategy assigned to this storage location, determining the sequence and method by which stock is retrieved for outbound orders. Supports FIFO/FEFO compliance for perishable and regulated materials.. Valid values are `fifo|fefo|lifo|nearest|zone_pick|batch_pick|wave_pick|`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing or distribution facility where this storage location physically resides. Supports multi-plant inventory segregation and reporting.. Valid values are `^[A-Z0-9]{1,10}$`',
    `putaway_strategy` STRING COMMENT 'Putaway strategy assigned to this storage location, governing how incoming stock is directed to this bin. Supports FIFO, FEFO, and zone-directed strategies aligned with Infor WMS and SAP WM putaway rules.. Valid values are `fixed|nearest_empty|bulk_storage|fifo|fefo|lifo|chaotic|zone_directed|`',
    `rack` STRING COMMENT 'Identifier for the rack or shelving unit within the aisle where this storage location is positioned. Supports physical navigation and structural capacity management.. Valid values are `^[A-Z0-9-]{1,10}$`',
    `replenishment_strategy` STRING COMMENT 'Replenishment strategy governing how this storage location is restocked from reserve or bulk storage. Supports Kanban, min-max, and demand-driven replenishment models aligned with JIT and MRP principles.. Valid values are `min_max|kanban|demand_driven|fixed_quantity|none`',
    `site_region` STRING COMMENT 'Geographic or organizational region designation for the site where this storage location resides (e.g., EMEA, APAC, Americas). Supports regional inventory reporting, supply chain analytics, and organizational hierarchy alignment.',
    `status` STRING COMMENT 'Current operational status of the storage location. Blocked or inactive locations are excluded from putaway and picking strategies. Supports lifecycle management and WMS operational control.. Valid values are `active|inactive|blocked|reserved|under_maintenance|decommissioned`',
    `storage_section_code` STRING COMMENT 'Code identifying the storage section within a storage type, used to group bins with similar characteristics for putaway strategy optimization in SAP WM and Infor WMS.. Valid values are `^[A-Z0-9-]{1,10}$`',
    `storage_type_code` STRING COMMENT 'Code representing the physical storage type classification within the warehouse structure, such as high-rack, open storage, fixed bin, or automated storage. Corresponds to SAP WM storage type and Infor WMS location type.. Valid values are `^[A-Z0-9]{1,10}$`',
    `temperature_zone` STRING COMMENT 'Temperature classification of the storage location defining the environmental control requirements. Ensures temperature-sensitive materials (chemicals, adhesives, electronic components) are stored in compliant conditions.. Valid values are `ambient|chilled|frozen|controlled_room_temp|heated|ultra_low`',
    `width_mm` DECIMAL(18,2) COMMENT 'Internal width dimension of the storage location in millimeters. Used alongside length and height for volumetric capacity calculations and putaway compatibility validation.. Valid values are `^d{1,7}(.d{1,2})?$`',
    `zone_type` STRING COMMENT 'Functional zone classification of the storage location defining its operational purpose within the warehouse. Drives putaway and picking strategies, compliance controls, and inventory segregation rules in Infor WMS and SAP WM.. Valid values are `bulk|pick|reserve|quarantine|hazmat|staging|receiving|shipping|returns|cold_storage|ambient|overflow`',
    CONSTRAINT pk_storage_location PRIMARY KEY(`storage_location_id`)
) COMMENT 'Granular storage location master defining aisles, racks, bins, shelves, and zones within a warehouse or plant. Captures location code, warehouse association, zone type (bulk, pick, reserve, quarantine, hazmat), bin dimensions, weight capacity, temperature zone, and active status. Supports putaway and picking strategies in Infor WMS and SAP WM storage bin management.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`inventory`.`transaction` (
    `transaction_id` BIGINT COMMENT 'Unique system-generated identifier for each inventory movement event. Serves as the primary key for the inventory_transaction data product and enables precise traceability of every stock movement across the enterprise.',
    `application_id` BIGINT COMMENT 'Foreign key linking to technology.application. Business justification: Every inventory transaction originates from a specific application (ERP, WMS, MES). Audit trails and data reconciliation require tracking which system created each transaction for compliance and troub',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Material issues and consumption must be charged to specific cost centers for departmental cost tracking. Controllers use this for variance analysis and overhead allocation.',
    `employee_id` BIGINT COMMENT 'The system user ID of the person or automated process that posted the inventory transaction. Used for audit trail, accountability tracking, and segregation of duties compliance. Does not contain personal name data.',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Every inventory movement (receipt, issue, transfer) must post to a GL account for financial reporting. Accounting department uses this for inventory valuation and COGS calculation daily.',
    `inventory_sku_id` BIGINT COMMENT 'Foreign key linking to inventory.sku. Business justification: inventory_transaction.sku_number is a denormalized SKU code. Every inventory movement event is for a specific SKU. Normalizing to sku_id FK eliminates redundant descriptive columns and links transacti',
    `lot_batch_id` BIGINT COMMENT 'Foreign key linking to inventory.lot_batch. Business justification: inventory_transaction.batch_number is a denormalized batch reference. Normalizing to lot_batch_id FK enables full batch traceability for every inventory movement event.',
    `serialized_unit_id` BIGINT COMMENT 'Foreign key linking to inventory.serialized_unit. Business justification: inventory_transaction.serial_number is a denormalized serial number reference. Normalizing to serialized_unit_id FK links serialized inventory movements to the serialized unit master for full unit-lev',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: inventory_transaction.storage_location_code is a denormalized location code. Normalizing to storage_location_id FK links each transaction to the granular bin/rack location master.',
    `warehouse_id` BIGINT COMMENT 'Foreign key linking to inventory.warehouse. Business justification: inventory_transaction.warehouse_number is a denormalized warehouse code. Normalizing to warehouse_id FK links each transaction to the warehouse master for facility-level reporting.',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to asset.work_order. Business justification: Inventory transactions record spare parts issued to maintenance work orders. Every parts withdrawal for equipment repair creates an inventory transaction linked to the work order for cost tracking and',
    `company_code` STRING COMMENT 'The SAP company code representing the legal entity for which this inventory transaction is posted. Enables multi-entity financial reporting and intercompany inventory reconciliation for multinational operations.',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the plant or warehouse location where the inventory transaction occurred. Supports multi-country regulatory compliance reporting, customs documentation, and geographic inventory analytics.. Valid values are `^[A-Z]{3}$`',
    `currency_code` STRING COMMENT 'The ISO 4217 three-letter currency code in which the valuation amount is expressed (e.g., USD, EUR, GBP). Supports multi-currency inventory valuation for multinational operations.. Valid values are `^[A-Z]{3}$`',
    `delivery_note_number` STRING COMMENT 'The external delivery note or packing slip number from the supplier or logistics provider associated with this goods receipt or transfer transaction. Used for three-way matching and inbound logistics reconciliation.',
    `destination_plant_code` STRING COMMENT 'For stock transfer transactions, the receiving plant code to which the material is being transferred. Populated only for inter-plant transfer movements (e.g., SAP movement types 301, 303, 351).',
    `destination_storage_location` STRING COMMENT 'For stock transfer transactions, the receiving storage location within the destination plant. Populated for intra-plant and inter-plant transfer postings to identify the exact destination of the transferred stock.',
    `document_date` DATE COMMENT 'The date on the source document (e.g., delivery note, goods receipt slip, transfer order) that triggered the inventory transaction. May differ from the posting date when documents are processed with a delay.. Valid values are `^[0-9]{4}-[0-9]{2}-[0-9]{2}$`',
    `goods_receipt_number` STRING COMMENT 'The Goods Receipt Note (GRN) number associated with this transaction when the movement represents an inbound goods receipt. Cross-references the procurement GRN document for three-way matching (PO, GRN, invoice).',
    `material_document_line` STRING COMMENT 'The line item number within the SAP material document corresponding to this inventory transaction. A single material document may contain multiple line items representing different materials or storage locations.. Valid values are `^[0-9]{1,4}$`',
    `material_document_number` STRING COMMENT 'The SAP MM material document number assigned to this inventory transaction at the time of posting. Serves as the primary cross-reference to the source system of record for goods movements.',
    `material_document_year` STRING COMMENT 'The fiscal year associated with the SAP material document number. Required in combination with material_document_number to uniquely identify a document in SAP MM, as document numbers are reset annually.. Valid values are `^[0-9]{4}$`',
    `movement_category` STRING COMMENT 'High-level business classification of the inventory movement event. Groups SAP movement types into business-meaningful categories for simplified reporting and analytics (e.g., goods_receipt covers GRN against PO, production, and returns from customer).. Valid values are `goods_receipt|goods_issue|stock_transfer|return|scrapping|adjustment|production_confirmation|inventory_count`',
    `movement_type_code` STRING COMMENT 'SAP MM movement type code that classifies the nature of the inventory transaction (e.g., 101=Goods Receipt against PO, 201=Goods Issue to Cost Center, 261=Goods Issue to Production Order, 301=Transfer Posting, 551=Scrapping). Drives account determination and stock update logic.. Valid values are `101|102|121|122|201|202|261|262|301|302|303|304|311|312|313|314|315|316|321|322|331|332|341|342|343|344|351|352|411|412|501|502|551|552|553|554|555|556|557|558|561|562|601|602|641|642|643|644|645|646|647|648|651|652|653|654|655|656|657|658|661|662|711|712|721|722|731|732|741|742|751|752|753|754|755|756|757|758|761|762|771|772|781|782|791|792|901|902|951|952|953|954|955|956|957|958|961|962|971|972|981|982`',
    `movement_type_description` STRING COMMENT 'Human-readable description of the inventory movement type corresponding to the movement_type_code. Provides business context for reporting and analytics without requiring a lookup join.',
    `order_unit_of_measure` STRING COMMENT 'The unit of measure used in the reference order document (PO, production order, sales order) for this transaction. May differ from the base unit of measure when conversion factors apply.. Valid values are `EA|KG|G|LB|OZ|L|ML|M|CM|MM|M2|M3|FT|IN|PC|PAL|BOX|BAG|ROL|SET|HR|MIN|KWH|TON|MT`',
    `plant_code` STRING COMMENT 'The SAP plant code identifying the manufacturing facility, distribution center, or warehouse where the inventory transaction occurred. Plant is the primary organizational unit for inventory management and production planning.',
    `posting_date` DATE COMMENT 'The accounting date on which the inventory transaction is posted to the general ledger and stock ledger. Determines the fiscal period for inventory valuation and financial reporting. May differ from the document date or actual physical movement date.. Valid values are `^[0-9]{4}-[0-9]{2}-[0-9]{2}$`',
    `posting_timestamp` TIMESTAMP COMMENT 'The precise date and time at which the inventory transaction was posted in the system, including timezone offset. Used for audit trails, sequencing of concurrent transactions, and intraday inventory position reporting.. Valid values are `^[0-9]{4}-[0-9]{2}-[0-9]{2}T[0-9]{2}:[0-9]{2}:[0-9]{2}.[0-9]{3}(Z|[+-][0-9]{2}:[0-9]{2})$`',
    `profit_center_code` STRING COMMENT 'The SAP controlling profit center associated with the inventory transaction. Enables profit center-level inventory valuation and profitability analysis across business segments.',
    `quantity` DECIMAL(18,2) COMMENT 'The quantity of material moved in this inventory transaction, expressed in the base unit of measure. Positive values indicate stock increases (receipts); negative values indicate stock decreases (issues, scrapping). Precision of 4 decimal places supports materials measured in fractional units.',
    `quantity_in_order_uom` DECIMAL(18,2) COMMENT 'The transaction quantity expressed in the order unit of measure (e.g., purchase order UoM or sales order UoM), which may differ from the base unit of measure. Supports reconciliation with reference documents such as POs and SOs.',
    `reason_code` STRING COMMENT 'Business reason code explaining why the inventory transaction was performed, particularly for adjustments, scrapping, and returns. Supports root cause analysis, quality management reporting, and inventory loss investigation.. Valid values are `damaged|expired|quality_rejection|overstock|cycle_count_adjustment|system_correction|customer_return|vendor_return|production_scrap|obsolete|theft_loss|other`',
    `reference_document_line` STRING COMMENT 'The line item number within the reference document (PO, production order, sales order) associated with this inventory transaction. Required for precise reconciliation between inventory movements and order line items.',
    `reference_document_number` STRING COMMENT 'The document number of the business document that triggered this inventory transaction (e.g., PO number for goods receipt, production order number for goods issue, sales order number for outbound delivery). Enables end-to-end process traceability.',
    `reference_document_type` STRING COMMENT 'The type of business document that triggered or is referenced by this inventory transaction (e.g., purchase_order for GRN, production_order for goods issue to manufacturing, sales_order for outbound delivery). Enables cross-domain traceability.. Valid values are `purchase_order|production_order|sales_order|delivery|transfer_order|reservation|cost_center|project|manual`',
    `reversal_indicator` BOOLEAN COMMENT 'Indicates whether this inventory transaction is a reversal (cancellation) of a previously posted transaction. Reversed transactions negate the original stock and accounting impact. Critical for audit trail integrity and inventory reconciliation.. Valid values are `true|false`',
    `reversed_document_number` STRING COMMENT 'The material document number of the original transaction that this record reverses. Populated only when reversal_indicator is true. Enables bidirectional linkage between original and reversal transactions for audit and reconciliation.',
    `special_stock_indicator` STRING COMMENT 'SAP special stock indicator identifying whether the material belongs to a special stock category such as sales order stock (E), vendor consignment (K), project stock (Q), or returnable packaging (V). Blank indicates standard own stock.. Valid values are `E|K|Q|V|W|O|M|P| `',
    `status` STRING COMMENT 'Current processing status of the inventory transaction record. Indicates whether the transaction has been fully posted, is pending approval, has been reversed, or is blocked for further processing.. Valid values are `posted|reversed|blocked|pending_approval|cancelled`',
    `stock_type` STRING COMMENT 'The stock category or special stock indicator defining the usability and ownership status of the inventory at the time of the transaction (e.g., unrestricted=available for use, quality_inspection=under QM hold, blocked=not available, in_transit=inter-plant transfer in progress).. Valid values are `unrestricted|quality_inspection|blocked|restricted|in_transit|consignment|project|sales_order`',
    `storage_bin` STRING COMMENT 'The specific bin, rack, or slot within the warehouse where the material was placed or picked during this transaction. Enables precise bin-level inventory tracking and supports warehouse slotting optimization.',
    `unit_of_measure` STRING COMMENT 'The base unit of measure in which the transaction quantity is expressed (e.g., EA=Each, KG=Kilogram, L=Liter, M=Meter). Aligned with SAP base unit of measure and ISO 80000 international units.. Valid values are `EA|KG|G|LB|OZ|L|ML|M|CM|MM|M2|M3|FT|IN|PC|PAL|BOX|BAG|ROL|SET|HR|MIN|KWH|TON|MT`',
    `valuation_amount` DECIMAL(18,2) COMMENT 'The monetary value of the inventory quantity moved in this transaction, calculated using the applicable valuation method (standard price, moving average price, or FIFO). Used for inventory accounting, COGS calculation, and financial reporting.',
    `valuation_price_per_unit` DECIMAL(18,2) COMMENT 'The unit price used to calculate the valuation amount for this transaction, expressed in the transaction currency. Reflects the standard price or moving average price at the time of posting. Higher precision (6 decimal places) supports materials with very low unit costs.',
    `valuation_type` STRING COMMENT 'The inventory valuation method applied to calculate the monetary value of this transaction (e.g., standard_price for manufactured goods, moving_average_price for purchased materials). Determines how cost variances are handled in financial accounting.. Valid values are `standard_price|moving_average_price|fifo|lifo|weighted_average`',
    `wms_transaction_reference` STRING COMMENT 'The transaction reference number from Infor WMS corresponding to this inventory movement. Used to cross-reference warehouse-level execution details with the ERP material document.',
    CONSTRAINT pk_transaction PRIMARY KEY(`transaction_id`)
) COMMENT 'Transactional record of every inventory movement event including goods receipts (GRN), goods issues, stock transfers, returns, scrapping, production confirmations, and adjustments. Captures movement type, quantity, unit of measure, source and destination locations, reference document (PO, production order, sales order), posting date, batch number, and posting user. Aligned with SAP MM material document and Infor WMS transaction history.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`inventory`.`stock_transfer` (
    `stock_transfer_id` BIGINT COMMENT 'Unique surrogate identifier for each stock transfer record in the inventory domain. Serves as the primary key for the stock_transfer data product.',
    `inventory_sku_id` BIGINT COMMENT 'Foreign key linking to inventory.sku. Business justification: stock_transfer.sku_number is a denormalized SKU code. Every inter-plant/inter-warehouse transfer is for a specific SKU. Normalizing to sku_id FK eliminates redundant descriptive columns.',
    `lot_batch_id` BIGINT COMMENT 'Foreign key linking to inventory.lot_batch. Business justification: stock_transfer.batch_number is a denormalized batch reference. Normalizing to lot_batch_id FK enables batch-level traceability for inter-location stock transfers.',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Stock transfers between warehouses or locations are requested by production planners, warehouse supervisors, or material handlers. Tracks accountability for transfer decisions and material movement au',
    `serialized_unit_id` BIGINT COMMENT 'Foreign key linking to inventory.serialized_unit. Business justification: stock_transfer.serial_number is a denormalized serial number reference. Normalizing to serialized_unit_id FK links serialized item transfers to the serialized unit master.',
    `shipment_id` BIGINT COMMENT 'Foreign key linking to logistics.shipment. Business justification: Inter-warehouse stock transfers require physical shipment between facilities. Supply chain operations link inventory transfers to logistics shipments for in-transit visibility and tracking.',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: stock_transfer.source_storage_location is a denormalized location code for the origin bin/rack. Normalizing to source_storage_location_id FK with a descriptive prefix distinguishes it from the destina',
    `warehouse_id` BIGINT COMMENT 'Foreign key linking to inventory.warehouse. Business justification: stock_transfer.source_warehouse_number is a denormalized warehouse code for the origin facility. Normalizing to source_warehouse_id FK with a descriptive prefix distinguishes it from the destination w',
    `actual_goods_issue_date` DATE COMMENT 'The actual calendar date on which the goods issue was posted at the source location, confirming physical departure of stock. Triggers inventory reduction at source and initiates in-transit stock accounting.. Valid values are `^d{4}-d{2}-d{2}$`',
    `actual_goods_receipt_date` DATE COMMENT 'The actual calendar date on which the goods receipt was posted at the destination location, confirming physical arrival and acceptance of transferred stock. Triggers inventory increase at destination and closes in-transit stock.. Valid values are `^d{4}-d{2}-d{2}$`',
    `company_code` STRING COMMENT 'SAP company code representing the legal entity initiating the stock transfer. Critical for intercompany transfer identification, financial accounting segregation, and regulatory reporting across multinational operations.. Valid values are `^[A-Z0-9]{1,10}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the stock transfer order was created in the source system (SAP MM or Infor WMS). Provides the starting point for transfer lifecycle duration analysis and audit trail compliance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code in which the transfer value and valuation price are expressed (e.g., USD, EUR, GBP). Supports multi-currency operations across global manufacturing plants and distribution centers.. Valid values are `^[A-Z]{3}$`',
    `customs_declaration_number` STRING COMMENT 'Official customs declaration or export/import document reference number for cross-border stock transfers. Required for regulatory compliance with customs authorities and trade compliance reporting in multinational operations.',
    `delivery_document_number` STRING COMMENT 'SAP outbound delivery document number (VL10) or Infor WMS shipment document number associated with the stock transfer. Links the inventory transfer to the logistics delivery process for goods issue posting and shipment tracking.. Valid values are `^[A-Z0-9-]{1,20}$`',
    `destination_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the destination plant or warehouse location. Used for cross-border transfer identification, import duty determination, customs compliance, and regulatory reporting.. Valid values are `^[A-Z]{3}$`',
    `destination_plant_code` STRING COMMENT 'Code identifying the receiving manufacturing plant or facility to which the stock is being transferred. Corresponds to the SAP receiving plant code. Used for inter-plant inventory reconciliation and cost center allocation.. Valid values are `^[A-Z0-9]{1,10}$`',
    `destination_storage_location` STRING COMMENT 'Specific storage location (bin, rack, zone, or area) within the destination warehouse where the transferred stock is to be received and putaway. Corresponds to SAP storage location or Infor WMS destination location code.. Valid values are `^[A-Z0-9]{1,10}$`',
    `destination_warehouse_number` STRING COMMENT 'Identifier of the receiving warehouse within the destination plant. Corresponds to the SAP warehouse number or Infor WMS warehouse code at the destination. Used for inbound planning and putaway operations.. Valid values are `^[A-Z0-9]{1,10}$`',
    `goods_issue_timestamp` TIMESTAMP COMMENT 'Precise date and time when the goods issue was posted at the source location. Provides sub-day precision for operational tracking, shift-level reporting, and audit trail requirements beyond the goods issue date.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `goods_receipt_timestamp` TIMESTAMP COMMENT 'Precise date and time when the goods receipt was posted at the destination location. Enables transit time calculation at sub-day precision and supports SLA compliance monitoring for inter-plant replenishment.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `is_cross_border` BOOLEAN COMMENT 'Boolean flag indicating whether the stock transfer crosses international borders, requiring customs documentation, export/import declarations, and compliance with trade regulations (e.g., CE Marking, REACH, RoHS, export control).. Valid values are `true|false`',
    `is_intercompany` BOOLEAN COMMENT 'Boolean flag indicating whether the stock transfer crosses legal entity boundaries (intercompany transfer). When true, the transfer requires intercompany billing, transfer pricing compliance, and consolidated financial elimination entries.. Valid values are `true|false`',
    `issued_quantity` DECIMAL(18,2) COMMENT 'Actual quantity of the SKU physically issued or picked from the source location and dispatched for transfer. May differ from the planned transfer quantity due to partial shipments or stock availability constraints.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Date and time of the most recent update to the stock transfer record in the source system. Used for change detection in data pipeline processing and audit trail maintenance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `movement_type_code` STRING COMMENT 'SAP MM movement type code that classifies the inventory transaction (e.g., 641 for goods issue for STO, 101 for goods receipt against STO). Determines the accounting entries and inventory update logic in SAP S/4HANA.. Valid values are `^[0-9]{3}$`',
    `planned_receipt_date` DATE COMMENT 'The scheduled calendar date on which the transferred stock is expected to arrive and be received at the destination location. Used for inbound planning, safety stock calculations, and Available to Promise (ATP) at the destination.. Valid values are `^d{4}-d{2}-d{2}$`',
    `planned_transfer_date` DATE COMMENT 'The scheduled calendar date on which the stock transfer is planned to be executed (goods issue from source). Used for production planning, MRP scheduling, and Available to Promise (ATP) calculations.. Valid values are `^d{4}-d{2}-d{2}$`',
    `priority` STRING COMMENT 'Business priority level assigned to the stock transfer order, used by warehouse and logistics teams to sequence picking, packing, and dispatch activities. Urgent transfers may be triggered by production line stoppages or critical customer orders.. Valid values are `urgent|high|normal|low`',
    `received_quantity` DECIMAL(18,2) COMMENT 'Actual quantity of the SKU confirmed as received at the destination location. Used to calculate transfer variance and update destination inventory positions. Triggers goods receipt posting in SAP MM.',
    `receiving_company_code` STRING COMMENT 'SAP company code of the receiving legal entity in an intercompany stock transfer. When this differs from the issuing company code, the transfer triggers intercompany billing and cross-company financial postings.. Valid values are `^[A-Z0-9]{1,10}$`',
    `source_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the source plant or warehouse location. Used for cross-border transfer identification, customs compliance, trade statistics, and regulatory reporting.. Valid values are `^[A-Z]{3}$`',
    `source_plant_code` STRING COMMENT 'Code identifying the originating manufacturing plant or facility from which the stock is being transferred. Corresponds to the SAP plant code (WERKS). Essential for inter-plant inventory movement tracking and cost allocation.. Valid values are `^[A-Z0-9]{1,10}$`',
    `source_system` STRING COMMENT 'Identifier of the operational system of record from which the stock transfer record originated (SAP S/4HANA MM, Infor WMS, or manual entry). Supports data lineage tracking and reconciliation between systems in the Silver layer.. Valid values are `SAP_S4HANA|INFOR_WMS|MANUAL`',
    `status` STRING COMMENT 'Current lifecycle status of the stock transfer order. Tracks progression from creation through in-transit movement to receipt confirmation or cancellation. Used for operational monitoring and inventory position accuracy.. Valid values are `draft|open|in_transit|partially_received|received|cancelled|blocked|closed`',
    `stock_type` STRING COMMENT 'Inventory stock category of the material being transferred, indicating its usability status: unrestricted (available for use), quality inspection (under QM hold), blocked (not available), restricted, in-transit, or consignment. Drives inventory availability calculations and MRP planning.. Valid values are `unrestricted|quality_inspection|blocked|restricted|in_transit|consignment`',
    `transfer_order_number` STRING COMMENT 'Business-facing document number assigned to the stock transfer order by the source system (SAP MM STO number or Infor WMS transfer order number). Used for cross-system traceability and communication with logistics and warehouse teams.. Valid values are `^[A-Z0-9-]{1,20}$`',
    `transfer_quantity` DECIMAL(18,2) COMMENT 'Ordered or planned quantity of the SKU to be transferred, expressed in the base unit of measure. This is the quantity requested on the transfer order document, which may differ from the actual received quantity.',
    `transfer_reason_code` STRING COMMENT 'Business reason code explaining why the stock transfer was initiated. Used for demand classification, cost allocation, and operational analytics to understand the drivers of inter-plant and inter-warehouse stock movements.. Valid values are `production_replenishment|safety_stock_replenishment|customer_order_fulfillment|intercompany_sale|quality_return|excess_stock_rebalancing|project_supply|mro_replenishment|other`',
    `transfer_type` STRING COMMENT 'Classification of the stock transfer indicating the scope and nature of the movement: plant-to-plant (inter-plant), warehouse-to-warehouse, storage location transfer within a plant, or a formal Stock Transport Order (STO) involving procurement and logistics. Drives process routing and document flow.. Valid values are `plant_to_plant|warehouse_to_warehouse|storage_location_transfer|stock_transport_order|cross_company|intercompany`',
    `transfer_value` DECIMAL(18,2) COMMENT 'Total monetary value of the stock transfer, calculated as transfer quantity multiplied by the valuation price. Used for financial reporting, intercompany billing, and inventory cost accounting. Stored as a raw business figure; aggregations are performed in the analytics layer.',
    `transport_reference_number` STRING COMMENT 'Reference number linking the stock transfer to the associated transport or shipment document (e.g., SAP shipment number, carrier waybill, or TMS reference). Enables traceability between inventory movement and physical logistics execution.. Valid values are `^[A-Z0-9-]{1,30}$`',
    `unit_of_measure` STRING COMMENT 'Base unit of measure in which the transfer quantity is expressed (e.g., EA for each, KG for kilogram, L for litre, PAL for pallet). Aligned with SAP base unit of measure and ISO 80000 measurement standards.. Valid values are `EA|KG|LB|L|ML|M|M2|M3|FT|GAL|PC|BOX|PAL|ROL|SET|TON`',
    `valuation_price` DECIMAL(18,2) COMMENT 'Unit price used to value the transferred stock at the time of transfer, based on the materials standard price or moving average price (MAP) in SAP. Used for inventory valuation, intercompany pricing, and financial accounting of stock movements.',
    CONSTRAINT pk_stock_transfer PRIMARY KEY(`stock_transfer_id`)
) COMMENT 'Records inter-plant, inter-warehouse, and inter-location stock transfer orders and their execution. Captures transfer order number, transfer type (plant-to-plant, warehouse-to-warehouse, storage location transfer, STO), source plant/warehouse/location, destination plant/warehouse/location, SKU, quantity, transfer status, planned date, actual transfer date, and transport reference. Aligned with SAP MM STO and Infor WMS transfer order.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`inventory`.`cycle_count` (
    `cycle_count_id` BIGINT COMMENT 'Unique system-generated identifier for each cycle count record within the inventory management system. Serves as the primary key for all cycle count transactions.',
    `employee_id` BIGINT COMMENT 'Employee identifier of the primary warehouse operative assigned to perform the physical count. Sourced from Kronos Workforce Central for labor tracking and accountability.',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: cycle_count.storage_location is a denormalized location code. Cycle counts are scoped to specific storage zones/locations. Normalizing to storage_location_id FK links the count to the granular locatio',
    `supervisor_employee_id` BIGINT COMMENT 'Employee identifier of the supervisor responsible for overseeing and approving the cycle count. Required for segregation of duties and audit compliance.',
    `warehouse_id` BIGINT COMMENT 'Foreign key linking to inventory.warehouse. Business justification: cycle_count.warehouse_number is a denormalized warehouse code. A cycle count program is scoped to a specific warehouse facility. Normalizing to warehouse_id FK links the count program to the warehouse',
    `abc_class` STRING COMMENT 'ABC inventory classification of the materials included in this cycle count. Class A items are high-value/high-velocity requiring most frequent counting; Class B is medium; Class C is low; Class D is inactive/obsolete.. Valid values are `A|B|C|D`',
    `actual_count_date` DATE COMMENT 'The actual calendar date on which the cycle count was physically performed. Used to measure schedule adherence and compliance with counting frequency requirements.. Valid values are `^d{4}-d{2}-d{2}$`',
    `assigned_counter_name` STRING COMMENT 'Full name of the warehouse employee assigned to perform the physical count. Used for operational reporting and accountability tracking.',
    `count_cycle_number` STRING COMMENT 'Business-facing alphanumeric identifier for the cycle count, used for cross-system reference between SAP MM and Infor WMS. Follows the format CC-YYYY-NNNNNN.. Valid values are `^CC-[0-9]{4}-[0-9]{6}$`',
    `count_end_timestamp` TIMESTAMP COMMENT 'Precise date and time when the physical counting activity was completed. Combined with count_start_timestamp to calculate count duration for labor and efficiency reporting.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `count_frequency` STRING COMMENT 'Frequency at which this cycle count is scheduled to recur. Drives the cycle count program calendar and aligns with ABC classification-based counting requirements in SAP MM.. Valid values are `daily|weekly|biweekly|monthly|quarterly|annual|event_driven`',
    `count_method` STRING COMMENT 'Physical counting method used by warehouse operatives during the cycle count. Includes manual paper-based, RF scanner, barcode scanning, RFID, or voice-directed counting. Impacts accuracy and efficiency metrics.. Valid values are `manual|rf_scanner|barcode|rfid|voice_directed`',
    `count_start_timestamp` TIMESTAMP COMMENT 'Precise date and time when the physical counting activity commenced. Used for duration tracking, labor reporting, and operational analytics.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `count_type` STRING COMMENT 'Type of cycle count being performed. Standard counts use system book quantities as reference; blind counts do not show expected quantities to counters; recounts are triggered by variance; audit counts are compliance-driven.. Valid values are `standard|blind|recount|audit|spot_check`',
    `count_zone` STRING COMMENT 'Logical or physical zone within the warehouse designated for this cycle count. Zones are defined in Infor WMS and used to segment counting activities for operational efficiency.',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the facility where the cycle count is performed. Supports multi-country regulatory compliance reporting and regional inventory analytics.. Valid values are `^[A-Z]{3}$`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the monetary values reported in this cycle count record (e.g., USD, EUR, GBP). Supports multi-currency operations for multinational facilities.. Valid values are `^[A-Z]{3}$`',
    `fiscal_period` STRING COMMENT 'Fiscal year and period (YYYY-MM) in which the cycle count is scheduled or completed. Used for financial period-end inventory reporting and alignment with SAP FI/CO period-close activities.. Valid values are `^d{4}-(0[1-9]|1[0-2])$`',
    `infor_wms_count_code` STRING COMMENT 'Native cycle count identifier from the Infor WMS system. Used for cross-system reconciliation between Infor WMS and SAP S/4HANA MM inventory records.',
    `inventory_adjustment_posted` BOOLEAN COMMENT 'Indicates whether the inventory adjustment resulting from the cycle count variance has been formally posted in SAP MM, updating the book inventory to reflect the physical count results.. Valid values are `true|false`',
    `inventory_category` STRING COMMENT 'Category of inventory being counted. Distinguishes between Raw Material, Work In Progress (WIP), Finished Goods, Maintenance Repair and Operations (MRO) stock, packaging, and semi-finished goods.. Valid values are `raw_material|wip|finished_goods|mro|packaging|semi_finished`',
    `items_exceeding_threshold` STRING COMMENT 'Count of SKU line items where the variance between book quantity and counted quantity exceeded the defined variance threshold, requiring recount or investigation.. Valid values are `^[0-9]+$`',
    `items_within_threshold` STRING COMMENT 'Count of SKU line items where the variance between book quantity and counted quantity fell within the defined variance threshold. Used to calculate count accuracy rate.. Valid values are `^[0-9]+$`',
    `material_group` STRING COMMENT 'SAP material group code used to filter the scope of materials included in the cycle count when sku_scope is set to material_group. Enables targeted counting by commodity category.',
    `notes` STRING COMMENT 'Free-text field for operational notes, observations, or exceptions recorded during the cycle count. May include reasons for variances, environmental conditions, or special circumstances affecting the count.',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility or distribution center where the cycle count is being performed. Aligns with SAP organizational structure.. Valid values are `^[A-Z0-9]{4}$`',
    `reconciliation_timestamp` TIMESTAMP COMMENT 'Date and time when the cycle count variances were reviewed, approved, and inventory adjustments were posted in SAP MM. Marks the formal closure of the count cycle.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `recount_count` STRING COMMENT 'Number of recount iterations performed for this cycle count record. Tracks how many times counting was repeated due to variance exceedances. A value of 0 indicates no recount was needed.. Valid values are `^[0-9]+$`',
    `recount_required` BOOLEAN COMMENT 'Indicates whether a recount has been triggered for one or more SKUs in this cycle count due to variances exceeding the defined threshold. Drives workflow escalation in Infor WMS.. Valid values are `true|false`',
    `sap_physical_inventory_doc` STRING COMMENT 'SAP MM physical inventory document number generated when the cycle count is initiated in SAP S/4HANA. Provides the cross-reference between the WMS cycle count and the SAP inventory posting document.',
    `scheduled_count_date` DATE COMMENT 'The planned calendar date on which the cycle count is scheduled to be performed. Used for workforce scheduling and operational planning.. Valid values are `^d{4}-d{2}-d{2}$`',
    `sku_scope` STRING COMMENT 'Defines the scope of Stock Keeping Units (SKUs) included in this cycle count. Determines whether all SKUs, a specific ABC class, a material group, or individual SKUs are counted.. Valid values are `all_skus|abc_class|material_group|specific_sku|storage_bin_range`',
    `status` STRING COMMENT 'Current operational status of the cycle count. Tracks the lifecycle from planning through execution to reconciliation. Aligned with SAP MM physical inventory document status and Infor WMS count status.. Valid values are `planned|in_progress|completed|reconciled|cancelled|on_hold`',
    `total_bins_counted` STRING COMMENT 'Total number of storage bins or locations physically counted during this cycle count. Used to measure count coverage and completeness against the planned scope.. Valid values are `^[0-9]+$`',
    `total_sku_count` STRING COMMENT 'Total number of distinct SKUs (Stock Keeping Units) included in the scope of this cycle count. Used for workload estimation and count completeness verification.. Valid values are `^[0-9]+$`',
    `total_variance_qty` DECIMAL(18,2) COMMENT 'Aggregate net quantity variance across all SKUs counted in this cycle count, calculated as the sum of (counted quantity minus book quantity). Positive values indicate overages; negative values indicate shortages.',
    `total_variance_value` DECIMAL(18,2) COMMENT 'Total monetary value of inventory variance identified during the cycle count, expressed in the local currency. Used for financial impact assessment and inventory adjustment postings in SAP FI/CO.',
    `variance_threshold_pct` DECIMAL(18,2) COMMENT 'Maximum allowable percentage variance between the system book quantity and the physically counted quantity before a recount or investigation is triggered. Expressed as a percentage of book quantity.. Valid values are `^d{1,3}(.d{1,2})?$`',
    `variance_threshold_qty` DECIMAL(18,2) COMMENT 'Maximum allowable absolute quantity variance between system book quantity and physically counted quantity before a recount or investigation is triggered. Complements the percentage threshold for high-value items.',
    CONSTRAINT pk_cycle_count PRIMARY KEY(`cycle_count_id`)
) COMMENT 'Manages cycle counting programs for continuous physical inventory verification without full warehouse shutdowns. Captures count cycle ID, warehouse, count zone, SKU scope, count frequency (daily, weekly, monthly), ABC class trigger, scheduled count date, actual count date, count status (planned, in-progress, completed, reconciled), assigned counter, and variance threshold. Aligned with SAP MM cycle counting configuration and Infor WMS cycle count module.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`inventory`.`cycle_count_result` (
    `cycle_count_result_id` BIGINT COMMENT 'Unique surrogate identifier for each cycle count result record at the SKU and storage location level. Serves as the primary key for this entity in the Databricks Silver Layer.',
    `employee_id` BIGINT COMMENT 'Employee identifier of the supervisor or inventory manager who approved the cycle count result and authorized the stock adjustment posting. Required for segregation of duties compliance.',
    `counter_employee_id` BIGINT COMMENT 'Employee identifier of the warehouse operative or cycle counter who performed the physical count. Used for accountability, training analysis, and counter performance tracking.',
    `cycle_count_id` BIGINT COMMENT 'Foreign key linking to inventory.cycle_count. Business justification: cycle_count_result is a child record of cycle_count. Each result captures the counted quantity for a specific SKU/bin within a count event. The cycle_count_id FK establishes the parent-child relations',
    `inventory_sku_id` BIGINT COMMENT 'Foreign key linking to inventory.sku. Business justification: cycle_count_result.sku_number is a denormalized SKU code. Each count result is for a specific SKU. Normalizing to sku_id FK eliminates redundant descriptive columns.',
    `lot_batch_id` BIGINT COMMENT 'Foreign key linking to inventory.lot_batch. Business justification: cycle_count_result.batch_number is a denormalized batch reference. Normalizing to lot_batch_id FK enables batch-level traceability in cycle count results.',
    `physical_inventory_id` BIGINT COMMENT 'Foreign key linking to inventory.physical_inventory. Business justification: cycle_count_result.physical_inventory_document_number references a physical inventory document. Normalizing to physical_inventory_id FK links count results to the physical inventory event that generat',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: cycle_count_result.storage_location_code is a denormalized location code. Normalizing to storage_location_id FK links each count result to the granular bin/rack location.',
    `warehouse_id` BIGINT COMMENT 'Foreign key linking to inventory.warehouse. Business justification: cycle_count_result.warehouse_number is a denormalized warehouse code. Normalizing to warehouse_id FK links each count result to the warehouse master.',
    `abc_classification` STRING COMMENT 'ABC inventory classification of the SKU based on consumption value or movement frequency. A-items are high-value/high-frequency; C-items are low-value/low-frequency. Drives cycle count frequency and priority.. Valid values are `A|B|C|D`',
    `adjustment_posted_flag` BOOLEAN COMMENT 'Indicates whether the inventory adjustment has been posted to the SAP material ledger following approval of the cycle count variance. When true, the book stock has been updated to reflect the counted quantity.. Valid values are `true|false`',
    `adjustment_posting_date` DATE COMMENT 'Accounting date on which the inventory adjustment was posted to the general ledger and material ledger. Determines the financial period in which the inventory variance is recognized.. Valid values are `^d{4}-d{2}-d{2}$`',
    `adjustment_posting_reference` STRING COMMENT 'SAP material document number generated when the inventory difference was posted to adjust the book stock to the counted quantity. Links the cycle count result to the financial and inventory adjustment transaction.',
    `approval_status` STRING COMMENT 'Current workflow status of the cycle count result. Drives the approval and stock adjustment posting workflow: pending awaits review, approved allows posting, recount_required triggers a new count round.. Valid values are `pending|approved|rejected|posted|cancelled|recount_required`',
    `approval_timestamp` TIMESTAMP COMMENT 'Date and time when the cycle count result was approved by the authorized supervisor. Supports audit trail and SLA compliance for inventory adjustment turnaround time.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `book_quantity` DECIMAL(18,2) COMMENT 'System-recorded (book) quantity of the SKU at the storage location at the time the physical inventory document was created. Represents the expected on-hand quantity before the physical count.',
    `count_date` DATE COMMENT 'Calendar date on which the physical cycle count was performed for this SKU and storage location. Used for inventory accuracy trending and compliance reporting.. Valid values are `^d{4}-d{2}-d{2}$`',
    `count_method` STRING COMMENT 'Method used to perform the physical count (e.g., manual paper-based, RF scanner, barcode scan, RFID). Supports analysis of count accuracy by method and drives process improvement initiatives.. Valid values are `manual|rf_scanner|barcode|rfid|automated`',
    `count_note` STRING COMMENT 'Free-text remarks entered by the counter or supervisor to explain unusual findings, discrepancies, or special circumstances observed during the cycle count (e.g., damaged goods, misplaced stock).',
    `count_round_number` STRING COMMENT 'Sequential round number of the count for this SKU and location (1 = initial count, 2 = first recount, 3 = second recount, etc.). Tracks the count iteration history for audit and accuracy analysis.. Valid values are `^[1-9][0-9]*$`',
    `count_status` STRING COMMENT 'Operational status of the individual count line item within the physical inventory document. Tracks progression from not yet counted through to final posting.. Valid values are `not_counted|counted|recounted|posted|cancelled`',
    `count_timestamp` TIMESTAMP COMMENT 'Precise date and time when the physical count entry was recorded in the system. Supports audit trail requirements and time-of-day analysis for count accuracy.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `counted_quantity` DECIMAL(18,2) COMMENT 'Actual physical quantity of the SKU recorded by the counter during the cycle count. This is the primary result of the count event and is compared against the book quantity to determine variance.',
    `counter_name` STRING COMMENT 'Full name of the warehouse employee who performed the physical count. Captured for audit trail and accountability purposes in cycle count documentation.',
    `exceeds_tolerance_flag` BOOLEAN COMMENT 'Indicates whether the variance percentage exceeds the configured tolerance threshold for this SKU. When true, triggers a recount workflow or supervisor approval before stock adjustment posting.. Valid values are `true|false`',
    `inventory_category` STRING COMMENT 'Classification of the inventory item by its role in the manufacturing process: raw material, work in progress (WIP), finished goods, or maintenance repair and operations (MRO) stock.. Valid values are `raw_material|wip|finished_goods|mro|semi_finished|trading_goods|spare_part`',
    `local_currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the local currency in which the variance value is expressed (e.g., USD, EUR, CNY). Supports multi-currency reporting for multinational operations.. Valid values are `^[A-Z]{3}$`',
    `physical_inventory_document_item` STRING COMMENT 'Line item number within the SAP physical inventory document identifying the specific SKU and storage location combination being counted.. Valid values are `^[0-9]{4}$`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility or distribution center where the cycle count was performed. Supports multi-plant inventory accuracy reporting.',
    `recount_flag` BOOLEAN COMMENT 'Indicates whether this count record is a recount (second or subsequent count) triggered by an out-of-tolerance variance from the initial count. Supports multi-round count workflows.. Valid values are `true|false`',
    `recount_quantity` DECIMAL(18,2) COMMENT 'Physical quantity recorded during the recount round, if a recount was performed. Populated only when recount_flag is true. Used to reconcile the final accepted quantity.',
    `stock_type` STRING COMMENT 'SAP stock category indicating the usability status of the inventory being counted (e.g., unrestricted use, quality inspection, blocked). Determines how the stock can be consumed or transferred.. Valid values are `unrestricted|quality_inspection|blocked|restricted|returns|in_transit`',
    `storage_bin` STRING COMMENT 'Specific bin or slot identifier within the warehouse where the material was physically located and counted. Provides the most granular location reference for inventory accuracy.',
    `tolerance_percentage` DECIMAL(18,2) COMMENT 'Configured acceptable variance percentage threshold for this SKU or ABC class. Variances within tolerance may be auto-approved; variances exceeding tolerance require supervisor review and recount.',
    `unit_of_measure` STRING COMMENT 'Base unit of measure in which the material quantity is expressed for the cycle count (e.g., EA, KG, L, M, PC). Aligns with the SAP material master base UoM.',
    `valuation_method` STRING COMMENT 'Inventory valuation method applied to calculate the financial value of the variance (e.g., standard price, moving average price, FIFO). Determines how the adjustment impacts the material ledger and P&L.. Valid values are `standard_price|moving_average_price|fifo|lifo|weighted_average`',
    `valuation_price` DECIMAL(18,2) COMMENT 'Unit price used to calculate the monetary value of the inventory variance, sourced from the SAP material master (standard price or moving average price). Reflects the inventory valuation method in use.',
    `variance_percentage` DECIMAL(18,2) COMMENT 'Variance quantity expressed as a percentage of the book quantity. Used to assess relative inventory accuracy and determine whether the variance exceeds the tolerance threshold for adjustment posting.',
    `variance_quantity` DECIMAL(18,2) COMMENT 'Difference between the counted quantity and the book quantity (counted_quantity minus book_quantity). A positive value indicates a surplus; a negative value indicates a shortage.',
    `variance_value_local_currency` DECIMAL(18,2) COMMENT 'Monetary value of the inventory variance in the plant local currency, calculated as variance quantity multiplied by the standard or moving average price. Used for financial impact assessment and P&L reporting.',
    `zero_count_flag` BOOLEAN COMMENT 'Indicates whether the counter explicitly confirmed a zero quantity count (as opposed to the count not yet being entered). Distinguishes between a confirmed zero stock and a missing count entry in SAP.. Valid values are `true|false`',
    CONSTRAINT pk_cycle_count_result PRIMARY KEY(`cycle_count_result_id`)
) COMMENT 'Captures the detailed results of each cycle count event at the SKU and storage location level. Records counted quantity, system book quantity, variance quantity, variance percentage, count date and time, counter identity, recount flag, recount quantity, approval status, and adjustment posting reference. Drives inventory accuracy KPIs and triggers stock adjustment postings when variances exceed tolerance. Aligned with SAP MM physical inventory document items.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`inventory`.`stock_adjustment` (
    `stock_adjustment_id` BIGINT COMMENT 'Unique system-generated identifier for each stock adjustment record in the inventory management system. Serves as the primary key for the stock_adjustment data product.',
    `employee_id` BIGINT COMMENT 'Employee ID of the individual who approved the stock adjustment. Used for authorization audit trails, segregation of duties reporting, and SOX compliance verification.. Valid values are `^[A-Z0-9]{4,12}$`',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Stock adjustments (write-offs, scrap, obsolescence) create financial impacts that must post to specific GL accounts. Required for accurate inventory valuation and P&L reporting.',
    `inventory_sku_id` BIGINT COMMENT 'Foreign key linking to inventory.sku. Business justification: stock_adjustment.sku (STRING) is a denormalized SKU code. Every stock adjustment corrects the book quantity for a specific SKU. Normalizing to sku_id FK eliminates redundant descriptive columns.',
    `lot_batch_id` BIGINT COMMENT 'Foreign key linking to inventory.lot_batch. Business justification: stock_adjustment.batch_number is a denormalized batch reference. Normalizing to lot_batch_id FK enables batch-level traceability for inventory adjustments.',
    `physical_inventory_id` BIGINT COMMENT 'Foreign key linking to inventory.physical_inventory. Business justification: stock_adjustment.physical_inventory_document references the physical inventory document that triggered the adjustment. Normalizing to physical_inventory_id FK links adjustments to the physical invento',
    `serialized_unit_id` BIGINT COMMENT 'Foreign key linking to inventory.serialized_unit. Business justification: stock_adjustment.serial_number is a denormalized serial number reference. Normalizing to serialized_unit_id FK links serialized item adjustments to the serialized unit master.',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: stock_adjustment.storage_location is a denormalized location code. Normalizing to storage_location_id FK links each adjustment to the granular bin/rack location.',
    `warehouse_id` BIGINT COMMENT 'Foreign key linking to inventory.warehouse. Business justification: stock_adjustment.warehouse_number is a denormalized warehouse code. Normalizing to warehouse_id FK links each adjustment to the warehouse master.',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to asset.work_order. Business justification: Stock adjustments occur when spare parts are consumed during maintenance work orders. Inventory controllers adjust stock levels based on actual parts used in completed maintenance activities for accur',
    `abc_classification` STRING COMMENT 'ABC inventory classification of the SKU at the time of adjustment, indicating its relative value and management priority (A=high value/high attention, B=medium, C=low value/low attention). Used for prioritizing cycle count frequency and adjustment review thresholds.. Valid values are `A|B|C`',
    `adjusted_quantity` DECIMAL(18,2) COMMENT 'The net quantity change applied to the inventory position. Positive values indicate an inventory increase (surplus found); negative values indicate a decrease (shortage, write-off, or rejection). Expressed in the materials base unit of measure.',
    `adjustment_number` STRING COMMENT 'Business-facing document number assigned to the stock adjustment, used for cross-referencing with SAP MM inventory difference postings and audit trails. Follows the enterprise document numbering convention.. Valid values are `^ADJ-[0-9]{4}-[0-9]{8}$`',
    `adjustment_type` STRING COMMENT 'Classification of the inventory adjustment indicating the business reason category. Drives accounting treatment, approval workflow, and reporting segmentation. Aligned with SAP MM movement type categories.. Valid values are `count_variance|damage_write_off|quality_rejection|system_correction|obsolescence_write_off|theft_loss|transfer_correction|opening_balance`',
    `approval_date` DATE COMMENT 'The calendar date on which the inventory adjustment was formally approved by the authorized approver. Used for SLA compliance tracking and audit documentation.. Valid values are `^d{4}-d{2}-d{2}$`',
    `approval_threshold_amount` DECIMAL(18,2) COMMENT 'The monetary threshold value that triggered the approval requirement for this adjustment. Captures the applicable authorization limit at the time of submission, supporting audit and SOX compliance documentation.',
    `approver_name` STRING COMMENT 'Full name of the manager or authorized personnel who approved the inventory adjustment. Captured for audit trail and segregation of duties compliance. Not a direct personal identifier in the operational context.',
    `book_quantity_after` DECIMAL(18,2) COMMENT 'The system-recorded (book) inventory quantity for the SKU at the storage location immediately after the adjustment was posted. Confirms the resulting inventory position and supports reconciliation.',
    `book_quantity_before` DECIMAL(18,2) COMMENT 'The system-recorded (book) inventory quantity for the SKU at the storage location immediately before the adjustment was posted. Provides the baseline for variance calculation and audit trail.',
    `company_code` STRING COMMENT 'SAP company code representing the legal entity responsible for the inventory adjustment. Used for legal entity-level financial reporting, intercompany reconciliation, and statutory compliance.. Valid values are `^[A-Z0-9]{4}$`',
    `cost_center` STRING COMMENT 'The controlling cost center responsible for absorbing the financial impact of the inventory adjustment. Used for internal cost allocation and management reporting.. Valid values are `^[A-Z0-9]{4,10}$`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the plant or distribution center where the adjustment occurred. Supports multi-country regulatory compliance reporting and regional inventory analytics.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when the stock adjustment record was initially created in the system. Provides a precise audit trail timestamp for compliance and data lineage purposes.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code in which the financial impact amount and unit cost are expressed (e.g., USD, EUR, GBP). Supports multi-currency reporting for multinational operations.. Valid values are `^[A-Z]{3}$`',
    `document_date` DATE COMMENT 'The date the adjustment document was created or the physical event occurred (e.g., date of cycle count, date damage was discovered). May differ from the posting date when adjustments are processed with a delay.. Valid values are `^d{4}-d{2}-d{2}$`',
    `financial_impact_amount` DECIMAL(18,2) COMMENT 'The monetary value of the inventory adjustment calculated as adjusted quantity multiplied by unit cost. Represents the debit or credit to the inventory account and corresponding expense or income account. Negative values indicate a write-down.',
    `fiscal_period` STRING COMMENT 'The fiscal period (accounting period) within the fiscal year to which the adjustment is posted. Used for monthly inventory reconciliation and period-end financial close.. Valid values are `^(0[1-9]|1[0-6])$`',
    `fiscal_year` STRING COMMENT 'The fiscal year to which the inventory adjustment posting belongs. Used for period-end financial reporting, inventory reconciliation, and year-end closing activities.. Valid values are `^[0-9]{4}$`',
    `gl_account_code` STRING COMMENT 'The General Ledger (GL) account code to which the financial impact of the inventory adjustment is posted. Determined by SAP automatic account determination based on movement type and valuation class.. Valid values are `^[0-9]{6,10}$`',
    `inventory_category` STRING COMMENT 'Classification of the material by its role in the production process: raw material, Work In Progress (WIP), finished goods, Maintenance Repair and Operations (MRO), or semi-finished goods. Supports domain-specific inventory reporting.. Valid values are `raw_material|wip|finished_goods|mro|semi_finished|trading_goods|spare_parts`',
    `movement_type` STRING COMMENT 'SAP MM three-digit movement type code governing the inventory posting logic (e.g., 551 for scrapping, 701 for inventory difference posting). Determines the general ledger account determination and stock category impact.. Valid values are `^[0-9]{3}$`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility or distribution center where the inventory adjustment is being made. Supports multi-plant inventory management across global operations.. Valid values are `^[A-Z0-9]{4}$`',
    `posted_timestamp` TIMESTAMP COMMENT 'The exact date and time when the inventory adjustment was posted to the SAP inventory ledger and financial accounts. Marks the completion of the adjustment lifecycle and the point at which stock quantities were updated.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `posting_date` DATE COMMENT 'The accounting posting date on which the inventory adjustment was recorded in the financial ledger. Determines the fiscal period to which the financial impact is attributed. May differ from the physical count date.. Valid values are `^d{4}-d{2}-d{2}$`',
    `profit_center` STRING COMMENT 'The SAP profit center associated with the inventory adjustment for segment reporting and profitability analysis. Enables P&L impact attribution at the business unit level.. Valid values are `^[A-Z0-9]{4,10}$`',
    `reason_code` STRING COMMENT 'Standardized reason code explaining the specific cause of the inventory adjustment (e.g., CYCLE_COUNT_VAR, DAMAGE_INBOUND, QA_REJECT, SYS_ERR). Used for root cause analysis, CAPA tracking, and trend reporting.. Valid values are `^[A-Z0-9_]{2,20}$`',
    `reason_description` STRING COMMENT 'Free-text narrative providing additional context and explanation for the inventory adjustment beyond the standardized reason code. Captures specific circumstances, findings from cycle counts, or quality inspection outcomes.',
    `reference_document_number` STRING COMMENT 'The document number of the source business document that triggered the adjustment (e.g., physical inventory document number, cycle count document number, NCR number, quality inspection lot number). Enables cross-system traceability.',
    `reference_document_type` STRING COMMENT 'Type of the source business document that triggered or authorized the inventory adjustment (e.g., cycle count document, physical inventory document, Non-Conformance Report (NCR), quality inspection lot). Provides traceability to the originating business event.. Valid values are `cycle_count|physical_inventory|ncr|quality_inspection_lot|purchase_order|production_order|transfer_order|manual`',
    `requires_approval` BOOLEAN COMMENT 'Indicates whether this adjustment requires formal management approval before being posted to the inventory ledger. Typically triggered by financial impact thresholds or specific adjustment types such as write-offs.. Valid values are `true|false`',
    `reversal_document_number` STRING COMMENT 'The SAP material document number of the reversal posting that cancelled this adjustment. Populated only when reversal_indicator is true. Enables complete audit trail of correction activities.',
    `reversal_indicator` BOOLEAN COMMENT 'Flag indicating whether this stock adjustment has been reversed (cancelled after posting). A value of true means the adjustment has been negated by a subsequent reversal document, and the net inventory impact is zero.. Valid values are `true|false`',
    `source_system` STRING COMMENT 'Identifier of the operational system of record from which the stock adjustment originated (e.g., SAP S/4HANA MM, Infor WMS, Siemens Opcenter MES). Supports data lineage tracking in the lakehouse silver layer.. Valid values are `SAP_S4HANA|INFOR_WMS|SIEMENS_OPCENTER|MANUAL`',
    `status` STRING COMMENT 'Current workflow status of the stock adjustment record, tracking its lifecycle from initial creation through approval, financial posting, and potential reversal. Drives process control and reporting filters.. Valid values are `draft|pending_approval|approved|posted|rejected|reversed|cancelled`',
    `stock_type` STRING COMMENT 'Category of stock being adjusted, indicating the inventory valuation and availability status. Determines whether the adjustment affects unrestricted-use stock, quality inspection stock, or blocked stock.. Valid values are `unrestricted|quality_inspection|blocked|restricted|in_transit|consignment`',
    `unit_cost` DECIMAL(18,2) COMMENT 'The standard or moving average cost per unit of the material at the time of the adjustment, used to calculate the financial impact. Sourced from the SAP material valuation record.',
    `unit_of_measure` STRING COMMENT 'The base unit of measure in which the adjusted quantity is expressed (e.g., EA for each, KG for kilogram, M for meter). Aligned with SAP base unit of measure configuration.. Valid values are `EA|KG|LB|M|M2|M3|L|PC|BOX|PAL|ROL|SET|TON|FT|IN`',
    `valuation_method` STRING COMMENT 'The costing method applied to value the inventory adjustment (e.g., standard cost, moving average price, FIFO). Determines how the financial impact amount is calculated and which accounting entries are generated.. Valid values are `standard_cost|moving_average|fifo|lifo|weighted_average`',
    `created_by` STRING COMMENT 'The SAP user ID or system user identifier of the person who created the stock adjustment record. Supports segregation of duties auditing and traceability requirements.. Valid values are `^[A-Z0-9_]{3,20}$`',
    CONSTRAINT pk_stock_adjustment PRIMARY KEY(`stock_adjustment_id`)
) COMMENT 'Records approved inventory adjustments made to correct book stock quantities following cycle counts, physical inventories, quality holds, or write-offs. Captures adjustment number, SKU, storage location, adjustment type (count variance, damage write-off, quality rejection, system correction), adjusted quantity, reason code, financial impact, approver, approval date, and reference document. Aligned with SAP MM inventory difference posting.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`inventory`.`lot_batch` (
    `lot_batch_id` BIGINT COMMENT 'Unique system-generated surrogate key identifying a material lot or production batch record in the inventory domain. Serves as the primary key for all downstream joins and traceability references.',
    `compliance_reach_substance_declaration_id` BIGINT COMMENT 'Foreign key linking to compliance.reach_substance_declaration. Business justification: Each production batch requires REACH substance declaration for chemical safety compliance. EHS teams document substances of very high concern (SVHC) per EU REACH regulation for material traceability.',
    `component_id` BIGINT COMMENT 'Foreign key linking to engineering.component. Business justification: Lot/batch tracking links manufactured batches to component specifications for quality control, expiration management, and recall traceability. Production and QA teams use this for batch genealogy.',
    `inventory_sku_id` BIGINT COMMENT 'Foreign key linking to inventory.sku. Business justification: lot_batch.sku_code is a denormalized SKU code. Every lot/batch is for a specific SKU material. Normalizing to sku_id FK links the batch master to the SKU master for material traceability.',
    `order_id` BIGINT COMMENT 'Foreign key linking to production.production_order. Business justification: Lot/batch created from production order - normalize by replacing production_order_number text with FK',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: lot_batch.storage_location_code is a denormalized location code. Normalizing to storage_location_id FK links each batch to its current storage location for warehouse management.',
    `abc_classification` STRING COMMENT 'The ABC inventory classification of the material in this batch based on consumption value or criticality. A-class items represent high-value/high-consumption materials requiring tight control; B-class items are medium; C-class items are low-value/low-consumption; D-class items are obsolete or non-moving. Drives cycle counting frequency and safety stock policies.. Valid values are `A|B|C|D`',
    `batch_classification_class` STRING COMMENT 'The SAP classification class assigned to this batch, enabling batch-specific characteristic values (e.g., purity percentage, viscosity, tensile strength) to be stored as classification attributes. Supports batch search, selection, and quality characteristic reporting.. Valid values are `^[A-Z0-9_]{1,30}$`',
    `batch_number` STRING COMMENT 'Business-facing alphanumeric identifier assigned to a material lot or production batch. Corresponds to the SAP MM batch number (CHARG field) and is used for traceability, quality inspection, and FIFO/FEFO picking across the supply chain.. Valid values are `^[A-Z0-9-.]{1,20}$`',
    `batch_size_uom` STRING COMMENT 'The unit of measure used to express the original batch size at the time of production or receipt, which may differ from the current inventory unit of measure. Supports unit conversion tracking and production yield analysis.. Valid values are `^[A-Z]{1,6}$`',
    `batch_type` STRING COMMENT 'Classification of the batch origin indicating whether it was produced internally, purchased from a supplier, received on consignment, returned from a customer, created through rework, or designated as a quality sample.. Valid values are `production|purchased|consignment|returns|rework|sample`',
    `best_before_date` DATE COMMENT 'The date up to which the batch retains its optimal quality characteristics, distinct from the hard expiry date. Used for quality-sensitive materials where degraded-but-not-expired stock may be sold at discount or redirected. Supports FEFO picking and customer SLA compliance.. Valid values are `^d{4}-d{2}-d{2}$`',
    `certificate_of_analysis_number` STRING COMMENT 'The document number of the Certificate of Analysis (CoA) issued for this batch, confirming that the material meets specified quality standards and test results. Required for regulated industries and customer quality documentation packages.. Valid values are `^[A-Za-z0-9-./ ]{1,50}$`',
    `country_of_origin` STRING COMMENT 'The ISO 3166-1 alpha-3 country code indicating the country where the material in this batch was manufactured or substantially transformed. Required for customs declarations, import/export compliance, REACH/RoHS regulatory reporting, and customer certificate of origin documentation.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this batch master record was first created in the system. Used for audit trail, data lineage, and batch age analysis. Corresponds to SAP batch creation date and time (ERSDA/ERSZT).. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `expiry_date` DATE COMMENT 'The date after which this batch is no longer suitable for use, sale, or consumption. Drives FEFO (First Expired First Out) picking strategies, automatic batch blocking, and regulatory compliance for shelf-life-managed materials. Corresponds to SAP batch expiry date (VFDAT).. Valid values are `^d{4}-d{2}-d{2}$`',
    `goods_receipt_date` DATE COMMENT 'The date on which this batch was physically received into inventory via a goods receipt posting. For purchased batches, this is the date the material arrived at the plant. Used as the FIFO baseline date for purchased materials and for supplier lead time analysis.. Valid values are `^d{4}-d{2}-d{2}$`',
    `goods_receipt_number` STRING COMMENT 'The Goods Receipt Note (GRN) document number from SAP MM recording the inbound receipt of this batch into inventory. Used for purchased material batches to link the batch to the procurement event, purchase order, and supplier delivery.. Valid values are `^[0-9]{10}$`',
    `hazardous_material_flag` BOOLEAN COMMENT 'Indicates whether the material in this batch is classified as hazardous under applicable regulations (e.g., OSHA HazCom, REACH, RoHS, UN dangerous goods). When true, triggers special handling, storage, and transportation requirements including hazmat documentation and labeling.. Valid values are `true|false`',
    `inspection_lot_number` STRING COMMENT 'The SAP QM inspection lot number (PRUEFLOS) associated with the quality inspection triggered for this batch. Links the batch to its quality inspection results, usage decisions, and defect records in the Quality Management system.. Valid values are `^[0-9]{12}$`',
    `inspection_status` STRING COMMENT 'Current quality inspection status of the batch controlling its availability for use, picking, and shipment. Unrestricted batches are available for all movements; quality_hold and blocked batches are restricted pending inspection or disposition; restricted batches have limited usage; in_inspection batches are undergoing active QM evaluation. Aligned with SAP QM batch status.. Valid values are `unrestricted|quality_hold|blocked|restricted|in_inspection|released`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'The date and time when this batch master record was most recently updated. Tracks changes to batch attributes such as inspection status, quantity, or storage location for audit compliance and data freshness monitoring.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `manufacturing_date` DATE COMMENT 'The date on which this batch was manufactured or produced. Used as the baseline for shelf life calculations, FIFO/FEFO picking strategy, and regulatory traceability. Corresponds to SAP batch manufacturing date (HSDAT).. Valid values are `^d{4}-d{2}-d{2}$`',
    `material_type` STRING COMMENT 'Classification of the material in this batch according to its stage in the production lifecycle. Distinguishes raw materials, Work in Progress (WIP), finished goods, Maintenance Repair and Operations (MRO) stock, semi-finished goods, packaging materials, and spare parts.. Valid values are `raw_material|wip|finished_good|mro|semi_finished|packaging|spare_part`',
    `max_storage_temp_c` DECIMAL(18,2) COMMENT 'The maximum allowable storage temperature in degrees Celsius for this batch. Used in conjunction with minimum storage temperature to define the acceptable temperature range for warehouse compliance monitoring and cold chain management.. Valid values are `^-?[0-9]{1,3}(.[0-9]{1,2})?$`',
    `min_storage_temp_c` DECIMAL(18,2) COMMENT 'The minimum allowable storage temperature in degrees Celsius for this batch. Used to validate warehouse temperature zone compliance, trigger alerts for out-of-condition storage, and support regulatory documentation for temperature-sensitive materials.. Valid values are `^-?[0-9]{1,3}(.[0-9]{1,2})?$`',
    `original_batch_size` DECIMAL(18,2) COMMENT 'The total quantity of material in this batch at the time of initial creation (production completion or goods receipt). Used as the denominator for yield calculations, scrap rate analysis, and batch consumption tracking.. Valid values are `^[0-9]{1,14}(.[0-9]{1,4})?$`',
    `picking_strategy` STRING COMMENT 'The inventory picking strategy applied to this batch during warehouse order fulfillment. FIFO (First In First Out) prioritizes oldest batches; FEFO (First Expired First Out) prioritizes soonest-to-expire batches; LIFO (Last In First Out) is used in specific regulatory contexts; FMFO (First Manufactured First Out) is based on manufacturing date; manual allows operator discretion.. Valid values are `FIFO|FEFO|LIFO|FMFO|manual`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility or distribution center where this batch was produced or received. Determines the organizational unit for inventory valuation, quality management, and storage location assignment.. Valid values are `^[A-Z0-9]{4}$`',
    `quantity` DECIMAL(18,2) COMMENT 'The current on-hand quantity of material in this batch expressed in the base unit of measure. Reflects the net available quantity after all goods movements, consumption, and adjustments. Core field for inventory position reporting and MRP (Material Requirements Planning) calculations.. Valid values are `^[0-9]{1,14}(.[0-9]{1,4})?$`',
    `remaining_shelf_life_days` STRING COMMENT 'The number of days remaining before this batch reaches its expiry date, calculated at the time of the last inventory snapshot or transaction. Used for FEFO picking prioritization, customer minimum shelf life checks, and proactive disposition planning.. Valid values are `^[0-9]{1,5}$`',
    `restricted_substance_flag` BOOLEAN COMMENT 'Indicates whether the material in this batch contains substances restricted under REACH, RoHS, or other environmental regulations. When true, requires compliance documentation, customer disclosure, and may restrict sale in certain markets or regions.. Valid values are `true|false`',
    `retest_date` DATE COMMENT 'The date on which this batch is scheduled for re-inspection or retesting to confirm continued conformance to quality specifications. Used for materials with defined retest intervals (e.g., chemicals, raw materials) to prevent use of out-of-specification stock.. Valid values are `^d{4}-d{2}-d{2}$`',
    `shelf_life_days` STRING COMMENT 'The total shelf life of the material in this batch expressed in days, as defined in the material master. Used to calculate expiry dates when manufacturing date is known and to enforce minimum remaining shelf life rules for customer shipments.. Valid values are `^[0-9]{1,5}$`',
    `storage_condition_code` STRING COMMENT 'Code identifying the required storage conditions for this batch (e.g., ambient, refrigerated, frozen, controlled atmosphere, hazardous). Drives warehouse slotting, temperature zone assignment, and compliance with material safety data sheet (MSDS) requirements.. Valid values are `^[A-Z0-9]{1,10}$`',
    `supplier_batch_number` STRING COMMENT 'The batch or lot number assigned by the external supplier or vendor for purchased materials. Maintained alongside the internal batch number to enable end-to-end supply chain traceability, supplier quality investigations, and recall management. Corresponds to SAP batch field LICHA.. Valid values are `^[A-Za-z0-9-./ ]{1,40}$`',
    `supplier_code` STRING COMMENT 'The internal vendor/supplier code identifying the external party that supplied the material in this batch. Used for supplier quality performance tracking, CAPA (Corrective and Preventive Action) management, and procurement analytics.. Valid values are `^[A-Z0-9-]{1,20}$`',
    `unit_of_measure` STRING COMMENT 'The base unit of measure in which the batch quantity is expressed (e.g., KG, EA, L, M, PC). Aligns with the SAP material master base unit of measure (MEINS) and is required for all inventory transactions, MRP calculations, and reporting.. Valid values are `^[A-Z]{1,6}$`',
    `usage_decision` STRING COMMENT 'The quality management usage decision recorded for this batch following inspection. Determines whether the batch is accepted for unrestricted use, rejected for disposal, conditionally released with restrictions, sent for rework, scrapped, or pending a decision. Corresponds to SAP QM usage decision (VCODE).. Valid values are `accepted|rejected|conditional_release|rework_required|scrap|pending`',
    `valuation_currency` STRING COMMENT 'The ISO 4217 three-letter currency code in which the batch valuation price is expressed (e.g., USD, EUR, GBP). Supports multi-currency inventory valuation for multinational operations.. Valid values are `^[A-Z]{3}$`',
    `valuation_price` DECIMAL(18,2) COMMENT 'The unit price used to value the inventory in this batch for financial reporting and cost accounting purposes. May reflect standard cost, moving average price, or actual cost depending on the materials valuation method in SAP CO. Classified as confidential due to commercial sensitivity.. Valid values are `^[0-9]{1,14}(.[0-9]{1,4})?$`',
    `warehouse_bin` STRING COMMENT 'The specific warehouse bin or slot identifier within the storage location where this batch is physically stored. Enables precise put-away and picking instructions in the Warehouse Management System (WMS) and supports bin-level inventory accuracy.. Valid values are `^[A-Z0-9-]{1,20}$`',
    CONSTRAINT pk_lot_batch PRIMARY KEY(`lot_batch_id`)
) COMMENT 'Master record for material lots and production batches tracked through inventory. Captures batch number, SKU, manufacturing date, expiry date, shelf life remaining, supplier batch reference, country of origin, quality inspection status (unrestricted, quality hold, blocked, restricted), batch classification characteristics, and storage conditions. Supports FIFO/FEFO picking strategies and traceability requirements. Aligned with SAP MM batch master.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`inventory`.`reorder_policy` (
    `reorder_policy_id` BIGINT COMMENT 'Unique surrogate identifier for each reorder policy record in the inventory replenishment system. Serves as the primary key for the reorder_policy data product.',
    `component_id` BIGINT COMMENT 'Foreign key linking to engineering.component. Business justification: Reorder policies define min/max levels per component. Supply chain planners use component lifecycle states, approved manufacturers, and lead times to set optimal inventory parameters.',
    `inventory_sku_id` BIGINT COMMENT 'Foreign key linking to inventory.sku. Business justification: reorder_policy.sku_number is a denormalized SKU code. A reorder policy is defined per SKU at a plant/location. Normalizing to sku_id FK links the policy to the SKU master.',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: reorder_policy.storage_location_code is a denormalized location code. Reorder policies are defined at the storage location level. Normalizing to storage_location_id FK links the policy to the granular',
    `abc_classification` STRING COMMENT 'ABC inventory classification of the SKU based on consumption value or demand frequency. A = high-value/high-frequency, B = medium, C = low-value/low-frequency, D = dormant/obsolete. Drives differentiated replenishment strategies and cycle count frequencies.. Valid values are `A|B|C|D`',
    `average_daily_usage_qty` DECIMAL(18,2) COMMENT 'The average quantity of the SKU consumed or issued per calendar day at this location, based on historical consumption data. Used as the baseline for reorder point and safety stock calculations.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary values associated with this reorder policy (e.g., ordering cost, holding cost rate). Supports multi-currency operations across global plants.. Valid values are `^[A-Z]{3}$`',
    `demand_variability_std_dev` DECIMAL(18,2) COMMENT 'The standard deviation of demand during the replenishment lead time period, used in statistical safety stock calculations. Reflects the variability of consumption patterns for this SKU at this location.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `economic_order_qty` DECIMAL(18,2) COMMENT 'The Economic Order Quantity (EOQ) — the mathematically optimal order quantity that minimizes total inventory holding costs and ordering costs. Used as the target replenishment quantity in cost-optimized procurement strategies.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `effective_date` DATE COMMENT 'The date from which this reorder policy becomes active and drives replenishment decisions. Enables future-dated policy changes and seasonal parameter adjustments.. Valid values are `^d{4}-d{2}-d{2}$`',
    `expiry_date` DATE COMMENT 'The date on which this reorder policy expires and is no longer applicable. Used for time-bound policies such as seasonal replenishment strategies or temporary safety stock adjustments.. Valid values are `^d{4}-d{2}-d{2}$`',
    `fixed_lot_size_qty` DECIMAL(18,2) COMMENT 'The fixed quantity used for replenishment orders when the lot sizing procedure is set to fixed lot size. Overrides EOQ calculations and is typically aligned with supplier standard pack sizes or production batch sizes.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `goods_receipt_processing_days` STRING COMMENT 'The number of working days required to process a Goods Receipt Note (GRN) after physical delivery, including inspection, quality checks, and putaway. Contributes to total replenishment lead time calculation.. Valid values are `^[0-9]+$`',
    `holding_cost_rate_pct` DECIMAL(18,2) COMMENT 'The annual inventory holding cost expressed as a percentage of the unit value (e.g., 20.00 = 20% per year). Includes storage, insurance, obsolescence, and capital cost of inventory. Used in EOQ and total cost of ownership calculations.. Valid values are `^(100(.0{1,2})?|[0-9]{1,2}(.[0-9]{1,2})?)$`',
    `last_reviewed_date` DATE COMMENT 'The date on which the reorder policy parameters were last formally reviewed and validated by the inventory planning team. Supports governance and audit requirements for replenishment parameter maintenance.. Valid values are `^d{4}-d{2}-d{2}$`',
    `lot_sizing_procedure` STRING COMMENT 'Defines the lot sizing method used by MRP to calculate replenishment order quantities. Options include exact quantity, fixed lot size, Economic Order Quantity (EOQ), period lot sizing, lot-for-lot, and min/max replenishment.. Valid values are `exact_quantity|fixed_lot|eoq|period_lot|lot_for_lot|min_max|replenish_to_max`',
    `material_type` STRING COMMENT 'Classification of the SKU by material category: raw material, Work In Progress (WIP), finished good, Maintenance Repair and Operations (MRO), semi-finished, trading good, or packaging. Determines applicable replenishment rules and valuation methods.. Valid values are `raw_material|wip|finished_good|mro|semi_finished|trading_good|packaging`',
    `maximum_order_qty` DECIMAL(18,2) COMMENT 'The maximum quantity that can be ordered in a single replenishment order. Used to prevent over-ordering, manage storage capacity constraints, and control cash flow exposure.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `maximum_stock_level_qty` DECIMAL(18,2) COMMENT 'The maximum allowable inventory quantity for the SKU at this location. Replenishment orders are sized to bring stock up to but not exceed this level. Used in min/max replenishment strategies in Infor WMS.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `minimum_order_qty` DECIMAL(18,2) COMMENT 'The Minimum Order Quantity (MOQ) — the smallest quantity that can be ordered from a supplier or produced in a single replenishment run. Reflects supplier contract terms or production batch constraints.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `mrp_type` STRING COMMENT 'Defines the replenishment planning method for the SKU at this location. Determines how SAP MRP or Infor WMS triggers replenishment: reorder point (ROP), MRP-driven, consumption-based, Kanban, manual, or vendor-managed inventory (VMI).. Valid values are `reorder_point|mrp|consumption_based|kanban|manual|vendor_managed`',
    `next_review_date` DATE COMMENT 'The scheduled date for the next formal review of this reorder policy. Drives workflow alerts and ensures parameters remain aligned with current demand patterns and supply conditions.. Valid values are `^d{4}-d{2}-d{2}$`',
    `order_quantity_rounding` DECIMAL(18,2) COMMENT 'The rounding value applied to calculated replenishment quantities to align with supplier pack sizes, pallet quantities, or production batch increments. Ensures order quantities are practical multiples.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `ordering_cost_amount` DECIMAL(18,2) COMMENT 'The fixed cost incurred each time a replenishment order is placed, including administrative, processing, and supplier transaction costs. Used as an input to Economic Order Quantity (EOQ) calculations.. Valid values are `^[0-9]+(.[0-9]{1,2})?$`',
    `planned_delivery_time_days` STRING COMMENT 'The planned number of working days required for a supplier to deliver the material after purchase order creation. Distinct from total replenishment lead time as it excludes internal processing time.. Valid values are `^[0-9]+$`',
    `plant_code` STRING COMMENT 'SAP plant or facility code identifying the manufacturing plant, distribution center, or warehouse location where this reorder policy is in effect. Enables location-specific replenishment rules.. Valid values are `^[A-Z0-9]{1,10}$`',
    `policy_code` STRING COMMENT 'Business-facing alphanumeric code uniquely identifying the reorder policy, used for cross-system reference and reporting. Typically sourced from SAP MRP planning data or Infor WMS min/max configuration.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `policy_name` STRING COMMENT 'Descriptive name for the reorder policy, providing a human-readable label for reporting, dashboards, and business communication.',
    `policy_status` STRING COMMENT 'Current operational status of the reorder policy. Active policies drive automated replenishment triggers. Inactive or suspended policies are excluded from MRP runs. Obsolete policies are retained for audit history.. Valid values are `active|inactive|pending_review|suspended|obsolete`',
    `procurement_type` STRING COMMENT 'Indicates whether the SKU is replenished via external procurement (purchase from supplier), in-house production (manufacturing order), or both. Drives MRP planning logic in SAP S/4HANA.. Valid values are `external|in_house|both`',
    `record_created_timestamp` TIMESTAMP COMMENT 'The timestamp when this reorder policy record was first created in the data platform. Used for audit trail, data lineage, and change history tracking.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `record_updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this reorder policy record was most recently modified. Enables change detection, incremental data loads, and audit trail maintenance in the Databricks Silver Layer.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `reorder_point_qty` DECIMAL(18,2) COMMENT 'The Reorder Point (ROP) quantity — the inventory level at which a replenishment order is automatically triggered. When on-hand stock falls to or below this level, a procurement or production order is initiated.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `replenishment_lead_time_days` STRING COMMENT 'The total number of calendar days from placement of a replenishment order to receipt of goods at the storage location. Includes supplier lead time, transit time, and goods receipt processing time. Used to calculate the reorder point.. Valid values are `^[0-9]+$`',
    `review_cycle_days` STRING COMMENT 'The frequency in calendar days at which inventory levels are reviewed and replenishment decisions are made. Applicable to periodic review replenishment policies (P-system). A value of 0 indicates continuous review.. Valid values are `^[0-9]+$`',
    `safety_stock_qty` DECIMAL(18,2) COMMENT 'The minimum buffer stock quantity maintained to protect against demand variability and supply uncertainty. Represents the floor inventory level below which stock should not fall under normal operating conditions.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `seasonal_policy_flag` BOOLEAN COMMENT 'Indicates whether this reorder policy incorporates seasonal demand adjustments. When true, reorder point and safety stock parameters may vary by season or planning period.. Valid values are `true|false`',
    `service_level_target_pct` DECIMAL(18,2) COMMENT 'The target inventory service level expressed as a percentage (e.g., 95.00 = 95%). Represents the desired probability of fulfilling demand from available stock without a stockout. Used to statistically calculate safety stock requirements.. Valid values are `^(100(.0{1,2})?|[0-9]{1,2}(.[0-9]{1,2})?)$`',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this reorder policy was sourced: SAP S/4HANA MRP planning data, Infor WMS min/max configuration, or manually entered. Supports data lineage and reconciliation.. Valid values are `SAP_S4HANA|INFOR_WMS|MANUAL`',
    `special_procurement_type` STRING COMMENT 'Specifies a special procurement strategy such as consignment stock, subcontracting, inter-plant stock transfer, direct production, phantom assembly, or vendor-managed inventory (VMI). Extends the standard procurement type.. Valid values are `consignment|subcontracting|stock_transfer|direct_production|phantom|vendor_managed`',
    `unit_of_measure` STRING COMMENT 'The base unit of measure in which all quantity fields (reorder point, safety stock, MOQ, EOQ, etc.) are expressed for this SKU. Examples: EA (each), KG, L, M, PC, PAL.. Valid values are `^[A-Z]{2,10}$`',
    `xyz_classification` STRING COMMENT 'XYZ demand variability classification of the SKU. X = stable/predictable demand, Y = variable demand, Z = highly irregular/sporadic demand. Used in conjunction with ABC classification to optimize safety stock and replenishment strategy.. Valid values are `X|Y|Z`',
    CONSTRAINT pk_reorder_policy PRIMARY KEY(`reorder_policy_id`)
) COMMENT 'Defines reorder parameters and replenishment policies for each SKU at each plant or warehouse location. Captures reorder point (ROP), safety stock level, minimum order quantity (MOQ), maximum stock level, economic order quantity (EOQ), replenishment lead time, MRP type (reorder point, MRP, consumption-based), and review cycle. Drives automated replenishment triggers in SAP MRP and Infor WMS min/max replenishment.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`inventory`.`replenishment_order` (
    `replenishment_order_id` BIGINT COMMENT 'Unique system-generated surrogate identifier for each replenishment order record in the Infor WMS replenishment module. Serves as the primary key for the replenishment_order data product.',
    `created_by_employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Replenishment orders are created by material planners or inventory analysts. Tracks who initiated restocking decisions for accountability in inventory planning and supply chain performance analysis.',
    `employee_id` BIGINT COMMENT 'Employee or operator identifier assigned to execute the replenishment task. Used for labor tracking, productivity reporting, and accountability in warehouse operations.',
    `inventory_sku_id` BIGINT COMMENT 'Foreign key linking to inventory.sku. Business justification: replenishment_order.sku_code is a denormalized SKU code. Every replenishment order moves stock for a specific SKU. Normalizing to sku_id FK eliminates redundant descriptive columns.',
    `logistics_inbound_delivery_id` BIGINT COMMENT 'Foreign key linking to logistics.inbound_delivery. Business justification: Replenishment orders trigger inbound deliveries from suppliers or other warehouses. Inventory planning links replenishment to expected deliveries for stock availability forecasting.',
    `lot_batch_id` BIGINT COMMENT 'Foreign key linking to inventory.lot_batch. Business justification: replenishment_order.lot_number is a denormalized lot/batch reference. Normalizing to lot_batch_id FK enables batch-level traceability for replenishment movements.',
    `procurement_purchase_requisition_id` BIGINT COMMENT 'Foreign key linking to procurement.purchase_requisition. Business justification: Replenishment orders trigger purchase requisitions for external procurement. Links inventory replenishment signals to procurement process initiation.',
    `reorder_policy_id` BIGINT COMMENT 'Foreign key linking to inventory.reorder_policy. Business justification: Replenishment orders are generated by reorder policies (triggered when stock falls below reorder point). Adding reorder_policy_id FK links each replenishment order to the governing policy, enabling po',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: replenishment_order.source_location_code is a denormalized location code for the origin. Normalizing to source_storage_location_id FK with a descriptive prefix distinguishes it from the destination lo',
    `warehouse_id` BIGINT COMMENT 'Foreign key linking to inventory.warehouse. Business justification: replenishment_order.warehouse_code is a denormalized warehouse code. Normalizing to warehouse_id FK links each replenishment order to the warehouse master.',
    `abc_classification` STRING COMMENT 'ABC inventory classification of the SKU being replenished, indicating its relative consumption value and replenishment priority. A-class items are high-value/high-velocity; C-class items are low-value/low-velocity. Used for prioritization and cycle count scheduling.. Valid values are `A|B|C|D`',
    `actual_quantity` DECIMAL(18,2) COMMENT 'The actual quantity of the SKU physically moved and confirmed at the destination location upon completion of the replenishment task. Used for variance analysis against requested and confirmed quantities.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `cancellation_reason` STRING COMMENT 'Reason code explaining why the replenishment order was cancelled. Used for exception analysis, process improvement, and identifying systemic issues in replenishment triggering logic.. Valid values are `source_stockout|duplicate_order|demand_fulfilled|system_error|operator_error|location_change|other`',
    `cancelled_timestamp` TIMESTAMP COMMENT 'The date and time when the replenishment order was cancelled, if applicable. Populated only for orders with status cancelled. Used for exception reporting and root cause analysis.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `completed_timestamp` TIMESTAMP COMMENT 'The date and time when the replenishment order was fully completed and stock confirmed at the destination location. Used for cycle time measurement, SLA compliance, and inventory availability updates.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `confirmed_quantity` DECIMAL(18,2) COMMENT 'The quantity confirmed as available and allocated for replenishment at the source location. May differ from requested quantity if source stock is insufficient.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `destination_location_code` STRING COMMENT 'Warehouse location code identifying the target location where replenished stock must be delivered (e.g., forward pick face, kanban lane, production staging area). Corresponds to the Infor WMS location master.',
    `destination_location_type` STRING COMMENT 'Classification of the destination warehouse location to which stock is being moved. Supports analytics on replenishment demand by location type and operational zone.. Valid values are `pick_face|forward_pick|kanban_lane|production_staging|assembly_staging|packing_area`',
    `destination_on_hand_quantity` DECIMAL(18,2) COMMENT 'The on-hand stock quantity at the destination location at the time the replenishment order was created. Provides context for the replenishment trigger and supports inventory position reporting.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `is_partial_allowed` BOOLEAN COMMENT 'Indicates whether a partial fulfillment of the replenishment order is acceptable when the full requested quantity is not available at the source location. When false, the order must be fulfilled in full or held.. Valid values are `true|false`',
    `is_urgent` BOOLEAN COMMENT 'Boolean flag indicating whether the replenishment order has been escalated as urgent, typically due to an imminent or active stockout at the destination pick location. Triggers expedited handling by warehouse supervisors.. Valid values are `true|false`',
    `kanban_card_number` STRING COMMENT 'The kanban card or signal identifier that triggered this replenishment order, applicable when trigger_type is kanban. Enables traceability between physical kanban signals and digital replenishment records.',
    `license_plate_number` STRING COMMENT 'The License Plate Number (LPN) or handling unit identifier associated with the stock being replenished. Used in Infor WMS for unit-level tracking of pallets, totes, or containers during replenishment movements.',
    `max_quantity` DECIMAL(18,2) COMMENT 'The maximum stock level threshold at the destination location for min/max replenishment. The replenishment order quantity is typically calculated to bring stock up to this level.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `min_quantity` DECIMAL(18,2) COMMENT 'The minimum stock level threshold at the destination location that triggered the replenishment order (applicable for min/max trigger type). When on-hand quantity falls below this level, a replenishment order is generated.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `notes` STRING COMMENT 'Free-text field for warehouse operators or supervisors to record additional instructions, exceptions, or observations related to the replenishment order execution.',
    `order_number` STRING COMMENT 'Business-facing alphanumeric identifier for the replenishment order, used for tracking and communication across warehouse operations teams. Formatted as REP-{YEAR}-{SEQUENCE}.. Valid values are `^REP-[0-9]{4}-[0-9]{8}$`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing or distribution plant associated with the replenishment order. Enables cross-plant inventory reporting and MRP alignment.',
    `priority` STRING COMMENT 'Business priority level assigned to the replenishment order, used by warehouse management to sequence and expedite fulfillment. Critical priority indicates immediate action required to prevent stockout at pick location.. Valid values are `critical|high|medium|low`',
    `priority_score` STRING COMMENT 'Numeric priority score (1–100) assigned by the WMS to enable fine-grained sequencing of replenishment tasks when multiple orders share the same priority tier. Higher scores indicate greater urgency.. Valid values are `^[1-9][0-9]?$|^100$`',
    `replenishment_method` STRING COMMENT 'The inventory replenishment strategy applied to this order. Fixed quantity replenishes a set amount each time; fixed cycle replenishes on a schedule; two-bin and kanban are signal-driven; wave-pick is batch-driven by outbound order waves.. Valid values are `fixed_quantity|fixed_cycle|two_bin|kanban|wave_pick|dynamic`',
    `requested_quantity` DECIMAL(18,2) COMMENT 'The quantity of the SKU requested to be moved from the source location to the destination location as specified when the replenishment order was created.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `requested_timestamp` TIMESTAMP COMMENT 'The date and time when the replenishment order was created or triggered in the WMS. Serves as the start of the replenishment lifecycle and is used for lead time and aging analysis.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `required_by_timestamp` TIMESTAMP COMMENT 'The date and time by which the replenishment must be completed to prevent a stockout at the destination pick location. Used for SLA compliance monitoring and escalation triggers.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `safety_stock_quantity` DECIMAL(18,2) COMMENT 'The safety stock level maintained at the destination location to buffer against demand variability and replenishment lead time uncertainty. Informs replenishment urgency and priority assignment.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `source_location_type` STRING COMMENT 'Classification of the source warehouse location from which stock is being moved. Used for operational routing and analytics on replenishment flow patterns.. Valid values are `bulk_storage|reserve_storage|receiving_staging|cross_dock|overflow|supplier_dock`',
    `source_on_hand_quantity` DECIMAL(18,2) COMMENT 'The on-hand stock quantity available at the source location at the time the replenishment order was created. Used to assess feasibility of fulfilling the requested quantity and for inventory position analysis.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `started_timestamp` TIMESTAMP COMMENT 'The date and time when the warehouse operator began executing the replenishment task (first scan or task acceptance). Used to measure task execution time and operator productivity.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `status` STRING COMMENT 'Current lifecycle status of the replenishment order. Tracks progression from open (created, not yet started) through in-progress (movement underway) to completed (stock moved to destination) or cancelled/on-hold states.. Valid values are `open|in_progress|completed|cancelled|on_hold|partially_completed`',
    `storage_type_code` STRING COMMENT 'Infor WMS storage type code defining the physical storage method (e.g., pallet rack, floor storage, carousel, automated storage and retrieval system) applicable to the replenishment movement.',
    `task_number` STRING COMMENT 'The Infor WMS warehouse task identifier assigned to the physical replenishment movement instruction. Used by warehouse operators on handheld devices or voice-directed systems to execute the replenishment.',
    `trigger_type` STRING COMMENT 'Indicates the mechanism that initiated the replenishment order. Min/max triggers fire when stock falls below minimum threshold; kanban triggers are signal-card driven; manual orders are created by warehouse staff; demand-driven triggers are based on forecasted pick demand.. Valid values are `min_max|kanban|manual|demand_driven|wave|system_generated`',
    `unit_of_measure` STRING COMMENT 'The unit of measure in which the replenishment quantities (requested, confirmed, actual) are expressed. Aligned with the SKUs base unit of measure in the material master.. Valid values are `EA|CS|PL|KG|LB|M|M2|M3|L|GAL|BOX|ROLL|DRUM`',
    `wave_number` STRING COMMENT 'The outbound picking wave number associated with this replenishment order when triggered by a wave-pick process. Links replenishment activity to the outbound order fulfillment wave for operational coordination.',
    CONSTRAINT pk_replenishment_order PRIMARY KEY(`replenishment_order_id`)
) COMMENT 'Tracks internal replenishment requests and warehouse replenishment orders generated to move stock from reserve storage to pick locations or from bulk storage to forward pick areas. Captures replenishment order number, trigger type (min/max, kanban, manual), source location, destination location, SKU, requested quantity, replenishment status (open, in-progress, completed), priority, and completion timestamp. Aligned with Infor WMS replenishment module.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`inventory`.`putaway_task` (
    `putaway_task_id` BIGINT COMMENT 'Unique system-generated identifier for each putaway task record in the warehouse management system. Serves as the primary key for the putaway_task data product.',
    `employee_id` BIGINT COMMENT 'Employee or user identifier of the warehouse operator assigned to execute the putaway task. Used for labor tracking, productivity reporting, and accountability.',
    `equipment_id` BIGINT COMMENT 'Identifier of the material handling equipment (e.g., forklift, reach truck, conveyor) assigned to execute the putaway task. Supports equipment utilization tracking and maintenance scheduling.',
    `inventory_sku_id` BIGINT COMMENT 'Foreign key linking to inventory.sku. Business justification: putaway_task.sku_code is a denormalized SKU code. Every putaway task directs a specific SKU to a storage location. Normalizing to sku_id FK eliminates redundant descriptive columns.',
    `lot_batch_id` BIGINT COMMENT 'Foreign key linking to inventory.lot_batch. Business justification: putaway_task.batch_number is a denormalized batch reference. Normalizing to lot_batch_id FK enables batch-level traceability for putaway operations.',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: putaway_task.confirmed_storage_bin and suggested_storage_bin are denormalized location references. Normalizing to storage_location_id FK links the putaway task to the confirmed storage location master',
    `warehouse_id` BIGINT COMMENT 'Foreign key linking to inventory.warehouse. Business justification: putaway_task.warehouse_number is a denormalized warehouse code. Normalizing to warehouse_id FK links each putaway task to the warehouse master.',
    `assigned_operator_name` STRING COMMENT 'Full name of the warehouse operator assigned to the putaway task. Included for operational reporting and task management visibility without requiring a join to the workforce system.',
    `assigned_timestamp` TIMESTAMP COMMENT 'Date and time when the putaway task was assigned to a warehouse operator. Used to measure queue wait time between task creation and assignment.',
    `bin_override_reason` STRING COMMENT 'Reason code explaining why the warehouse operator placed the material in a bin different from the WMS-suggested bin. Supports quality audits, slotting optimization, and WMS strategy tuning.. Valid values are `bin_full|bin_damaged|bin_blocked|weight_limit|hazmat_restriction|operator_preference|system_error|other`',
    `completion_timestamp` TIMESTAMP COMMENT 'Date and time when the putaway task was confirmed as completed in the WMS, indicating the material has been physically placed in the confirmed storage bin.',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the plant or distribution center where the putaway task is executed. Supports multi-country operations and regional compliance reporting.. Valid values are `^[A-Z]{3}$`',
    `due_timestamp` TIMESTAMP COMMENT 'Target date and time by which the putaway task must be completed to meet operational commitments such as production material availability or perishable goods handling windows.',
    `grn_number` STRING COMMENT 'Reference to the Goods Receipt Note (GRN) that triggered the creation of this putaway task. Links the putaway activity to the inbound goods receipt event recorded in SAP S/4HANA MM.',
    `handling_unit_type` STRING COMMENT 'Type of physical handling unit or packaging in which the material is being put away (e.g., pallet, carton, drum). Influences equipment selection and storage bin capacity validation.. Valid values are `pallet|carton|drum|crate|roll|bag|tote|container`',
    `hazmat_class` STRING COMMENT 'UN/DOT hazardous materials classification for the material being put away. Determines storage zone restrictions, segregation requirements, and compliance with OSHA and EPA hazardous materials storage regulations.. Valid values are `1|2|3|4|5|6|7|8|9|none`',
    `inbound_delivery_number` STRING COMMENT 'Reference number of the inbound delivery document associated with this putaway task. Provides traceability from the putaway task back to the supplier delivery and purchase order.',
    `infor_wms_task_code` STRING COMMENT 'Native task identifier from the Infor WMS source system. Used for cross-system reconciliation, audit trails, and data lineage between the lakehouse silver layer and the operational WMS.',
    `inventory_category` STRING COMMENT 'Classification of the material being put away by inventory type: raw material, Work In Progress (WIP), finished good, Maintenance Repair and Operations (MRO), packaging, or semi-finished. Drives storage zone assignment and valuation rules.. Valid values are `raw_material|wip|finished_good|mro|packaging|semi_finished`',
    `is_bin_overridden` BOOLEAN COMMENT 'Flag indicating whether the warehouse operator placed the material in a storage bin different from the WMS-suggested bin. True when confirmed_storage_bin differs from suggested_storage_bin.. Valid values are `true|false`',
    `license_plate_number` STRING COMMENT 'License Plate Number (LPN) or handling unit identifier associated with the goods being put away. Used in license-plate-managed warehouses to track physical handling units through the putaway process.',
    `notes` STRING COMMENT 'Free-text notes or comments entered by the warehouse operator or supervisor regarding the putaway task. May include special handling instructions, discrepancy observations, or exception details.',
    `plant_code` STRING COMMENT 'Code identifying the manufacturing plant or distribution center where the putaway task is being executed. Supports multi-site operations across the enterprise.. Valid values are `^[A-Z0-9]{2,6}$`',
    `priority` STRING COMMENT 'Business priority level assigned to the putaway task, used to sequence work assignments for warehouse operators. Critical and high priority tasks are typically associated with production-urgent materials or perishable goods.. Valid values are `critical|high|medium|low`',
    `putaway_strategy` STRING COMMENT 'The putaway strategy applied by the WMS to determine the suggested storage bin. Strategies include fixed bin assignment, nearest empty bin, zone-based routing, FIFO/FEFO sequencing, ABC classification-based placement, and weight-based slotting.. Valid values are `fixed_bin|nearest_empty|zone_based|chaotic|fifo|fefo|abc_class|weight_based|product_family`',
    `quantity` DECIMAL(18,2) COMMENT 'The quantity of the material to be put away as specified in the putaway task. Expressed in the base unit of measure for the SKU.',
    `sap_transfer_order_number` STRING COMMENT 'SAP S/4HANA Warehouse Management transfer order number corresponding to this putaway task. Enables reconciliation between Infor WMS putaway tasks and SAP WM transfer orders for financial and inventory postings.',
    `start_timestamp` TIMESTAMP COMMENT 'Date and time when the warehouse operator began executing the putaway task (e.g., scanned the task or confirmed start on the WMS terminal). Used for actual cycle time measurement.',
    `status` STRING COMMENT 'Current lifecycle status of the putaway task. Tracks progression from task creation through assignment, execution, and completion or cancellation.. Valid values are `created|assigned|in_progress|completed|cancelled|on_hold|partially_completed`',
    `storage_section` STRING COMMENT 'The logical section or zone within the warehouse storage type where the bin is located. Used for zone-based putaway strategies and warehouse slotting optimization.',
    `storage_type` STRING COMMENT 'The type of storage area or structure where the material is being put away (e.g., bulk floor, pallet rack, shelf, cold storage, hazardous materials zone). Drives putaway strategy selection.. Valid values are `bulk|rack|shelf|floor|cold_storage|hazmat|high_bay|mezzanine|automated`',
    `task_created_timestamp` TIMESTAMP COMMENT 'Date and time when the putaway task was created in the WMS, typically triggered automatically upon goods receipt confirmation. Used for cycle time analysis and SLA monitoring.',
    `task_number` STRING COMMENT 'Human-readable business identifier for the putaway task, used by warehouse operators and supervisors to reference and track the task across systems and physical documents.. Valid values are `^PUT-[0-9]{4}-[0-9]{8}$`',
    `unit_of_measure` STRING COMMENT 'The unit of measure in which the putaway quantity is expressed (e.g., EA for each, KG for kilogram, PAL for pallet). Aligns with SAP S/4HANA base unit of measure configuration.. Valid values are `EA|KG|LB|L|M|M2|M3|PAL|BOX|ROLL|BAG|DRUM|CAN|PC`',
    `volume_m3` DECIMAL(18,2) COMMENT 'Total volume of the goods being put away, expressed in cubic meters. Used for bin capacity utilization validation and warehouse space planning.',
    `weight_kg` DECIMAL(18,2) COMMENT 'Total weight of the goods being put away, expressed in kilograms. Used for bin weight capacity validation, equipment load planning, and logistics reporting.',
    CONSTRAINT pk_putaway_task PRIMARY KEY(`putaway_task_id`)
) COMMENT 'Records warehouse putaway tasks generated when goods are received and need to be directed to storage locations. Captures task number, inbound delivery or GRN reference, SKU, batch, quantity, suggested storage location, confirmed storage location, putaway strategy applied (fixed bin, nearest empty, zone-based), task status, assigned operator, start time, and completion time. Aligned with Infor WMS putaway task management.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`inventory`.`pick_task` (
    `pick_task_id` BIGINT COMMENT 'Unique surrogate identifier for each warehouse pick task record in the Silver layer lakehouse. Serves as the primary key for all downstream joins and lineage tracking.',
    `employee_id` BIGINT COMMENT 'Employee identifier of the warehouse picker assigned to execute this pick task. Used for labor productivity tracking, task accountability, and workforce analytics. Sourced from Kronos Workforce Central and SAP HR.',
    `inventory_sku_id` BIGINT COMMENT 'Foreign key linking to inventory.sku. Business justification: pick_task.sku_number is a denormalized SKU code. Every pick task fulfills demand for a specific SKU. Normalizing to sku_id FK eliminates redundant descriptive columns.',
    `lot_batch_id` BIGINT COMMENT 'Foreign key linking to inventory.lot_batch. Business justification: pick_task.batch_number is a denormalized batch reference. Normalizing to lot_batch_id FK enables batch-level traceability for pick operations, supporting FEFO/FIFO picking strategies.',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: pick_task.source_storage_bin is a denormalized location reference for the pick source. Normalizing to storage_location_id FK links the pick task to the source storage location master record.',
    `warehouse_id` BIGINT COMMENT 'Foreign key linking to inventory.warehouse. Business justification: pick_task.warehouse_number is a denormalized warehouse code. Normalizing to warehouse_id FK links each pick task to the warehouse master.',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to asset.work_order. Business justification: Pick tasks are generated to retrieve spare parts from warehouse for maintenance work orders. Warehouse operators pick materials based on work order requirements, linking inventory fulfillment to asset',
    `actual_start_timestamp` TIMESTAMP COMMENT 'The actual date and time at which the picker began executing the pick task, as recorded by the WMS upon task acceptance or first scan. Used for cycle time analysis and labor productivity measurement.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `assigned_picker_name` STRING COMMENT 'Full name of the warehouse picker assigned to this task. Retained for operational reporting and shift supervisor visibility. Classified as confidential as it identifies an employee in the context of their work performance.',
    `completion_timestamp` TIMESTAMP COMMENT 'The date and time at which the pick task was fully confirmed and closed by the warehouse operator. Used to calculate actual pick cycle time, measure throughput, and assess on-time delivery performance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `confirmed_quantity` DECIMAL(18,2) COMMENT 'The actual quantity confirmed as picked by the warehouse operator upon task completion. May differ from pick_quantity due to short picks, partial picks, or inventory discrepancies. Used for goods issue posting and inventory reconciliation.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the warehouse or distribution center where the pick task is executed. Supports multi-country inventory reporting, regulatory compliance segmentation, and cross-border logistics analytics.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time at which the pick task record was created in the source WMS system. Used for data lineage, audit trail, and task age analysis.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `destination_storage_bin` STRING COMMENT 'The target storage bin or staging area to which the picked material must be delivered (e.g., outbound staging lane, production line drop zone, goods issue area). Used for pick-to-stage and pick-to-belt operations.',
    `due_timestamp` TIMESTAMP COMMENT 'The deadline by which the pick task must be completed to meet the outbound delivery or production staging schedule. Used for SLA compliance monitoring and escalation triggering.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `goods_issue_document_number` STRING COMMENT 'The SAP material document number generated upon goods issue posting for this pick task. Provides the financial audit trail linking the physical pick to the inventory accounting entry and enables reconciliation between WMS and ERP.',
    `goods_issue_posting_date` DATE COMMENT 'The date on which the goods issue (GI) inventory movement was posted in SAP MM following confirmation of the pick task. Represents the financial and inventory valuation date for the stock reduction. Critical for period-end inventory closing and COGS recognition.. Valid values are `^d{4}-d{2}-d{2}$`',
    `infor_wms_task_code` STRING COMMENT 'Native task identifier from the Infor WMS source system. Preserved for system-of-record traceability, reconciliation with the WMS operational database, and audit trail purposes.',
    `inventory_category` STRING COMMENT 'Classification of the material being picked by its inventory category within the supply chain. Distinguishes raw materials, work-in-progress (WIP), finished goods, MRO (Maintenance, Repair and Operations) stock, and packaging materials for inventory valuation and reporting segmentation.. Valid values are `RAW_MATERIAL|WIP|FINISHED_GOODS|MRO|SEMI_FINISHED|PACKAGING|SPARE_PART`',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The date and time of the most recent update to the pick task record in the source system. Used for incremental data loading, change detection, and Silver layer merge operations in the Databricks lakehouse.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `outbound_delivery_number` STRING COMMENT 'Reference to the outbound delivery document (e.g., SAP SD outbound delivery) that triggered this pick task. Applicable when the pick task fulfills a customer shipment or distribution center transfer.',
    `pick_device_type` STRING COMMENT 'The type of picking technology or device used by the warehouse operator to execute this pick task. Supports productivity benchmarking across picking methods, technology ROI analysis, and ergonomics assessments.. Valid values are `RF_SCANNER|VOICE_DIRECTED|PICK_TO_LIGHT|PAPER|MOBILE_DEVICE|AUTOMATED_CONVEYOR`',
    `pick_quantity` DECIMAL(18,2) COMMENT 'The system-requested quantity of the SKU to be picked for this task, expressed in the base unit of measure. Represents the planned pick quantity as generated by the WMS wave release or transfer order.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `pick_strategy` STRING COMMENT 'The inventory rotation and batch selection strategy applied when determining which stock to pick. FIFO (First In First Out), FEFO (First Expired First Out), and LIFO (Last In First Out) are standard strategies. FEFO is mandatory for perishable or expiry-managed materials. Drives compliance with shelf-life and traceability requirements.. Valid values are `FIFO|FEFO|LIFO|LEFO|FEFO_BATCH|MANUAL`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing plant or distribution center where the pick task is executed. Enables multi-plant inventory reporting and cross-plant fulfillment analysis.. Valid values are `^[A-Z0-9]{4}$`',
    `production_order_number` STRING COMMENT 'Reference to the manufacturing production order for which materials are being staged. Applicable when the pick task fulfills a production material staging request rather than an outbound customer delivery.',
    `sap_transfer_order_item` STRING COMMENT 'The line item number within the SAP WM transfer order corresponding to this pick task. Enables precise mapping between WMS pick tasks and individual SAP WM transfer order items for goods issue reconciliation.',
    `scheduled_start_timestamp` TIMESTAMP COMMENT 'The planned date and time at which the pick task is scheduled to begin execution. Used for wave planning, labor scheduling, and on-time fulfillment SLA measurement.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `short_pick_flag` BOOLEAN COMMENT 'Indicates whether the pick task resulted in a short pick, meaning the confirmed quantity was less than the requested pick quantity due to insufficient stock at the source bin. Triggers downstream exception handling, inventory investigation, and potential order splitting.. Valid values are `true|false`',
    `short_pick_reason_code` STRING COMMENT 'Standardized reason code explaining why a short pick occurred. Populated only when short_pick_flag is true. Used for root cause analysis, inventory accuracy improvement, and CAPA (Corrective and Preventive Action) processes.. Valid values are `STOCK_NOT_FOUND|BIN_EMPTY|DAMAGED_STOCK|QUALITY_HOLD|SYSTEM_ERROR|WRONG_BATCH|OTHER`',
    `source_storage_section` STRING COMMENT 'The storage section within the source storage type from which the pick is to be executed. Provides finer-grained location segmentation for optimized pick routing and slotting analysis.',
    `source_storage_type` STRING COMMENT 'The storage type code within the warehouse from which the material is to be picked (e.g., bulk storage, high-rack, picking zone, floor storage). Drives equipment selection and routing logic.',
    `status` STRING COMMENT 'Current lifecycle status of the pick task. Tracks progression from task creation through release, active picking, partial or full confirmation, and terminal states such as cancellation or short pick. Used for real-time warehouse floor visibility and SLA monitoring.. Valid values are `CREATED|RELEASED|IN_PROGRESS|PARTIALLY_CONFIRMED|CONFIRMED|CANCELLED|ON_HOLD|SHORT_PICK`',
    `stock_type` STRING COMMENT 'The SAP stock type of the inventory being picked, indicating its usability status. Unrestricted stock is available for immediate use; quality inspection stock is pending QM release; blocked stock is not available for use. Ensures only authorized stock is issued.. Valid values are `UNRESTRICTED|QUALITY_INSPECTION|BLOCKED|RESTRICTED|RETURNS`',
    `task_number` STRING COMMENT 'Business-facing alphanumeric identifier for the pick task as assigned by the Warehouse Management System (WMS). Used by warehouse operators and supervisors to reference and track individual picking assignments on the shop floor.. Valid values are `^PT-[0-9]{10}$`',
    `task_type` STRING COMMENT 'Classification of the pick task by its fulfillment purpose. Distinguishes between outbound customer delivery picks, production material staging picks, internal warehouse transfers, bin replenishment picks, return processing, and quality sample picks.. Valid values are `OUTBOUND_DELIVERY|PRODUCTION_STAGING|INTERNAL_TRANSFER|REPLENISHMENT|RETURN|SAMPLE`',
    `transfer_order_number` STRING COMMENT 'SAP Warehouse Management (WM) transfer order number associated with this pick task. Represents the goods issue (GI) movement instruction within the SAP WM module, enabling traceability between WMS pick tasks and ERP inventory movements.',
    `unit_of_measure` STRING COMMENT 'The base unit of measure in which pick and confirmed quantities are expressed (e.g., EA, KG, L, M, PC). Aligned with SAP base unit of measure and ISO 80000 measurement standards.. Valid values are `^[A-Z]{2,6}$`',
    `wave_number` STRING COMMENT 'Identifier of the wave release batch to which this pick task belongs. Waves group multiple pick tasks for coordinated release to the warehouse floor, enabling efficient labor and equipment allocation.',
    CONSTRAINT pk_pick_task PRIMARY KEY(`pick_task_id`)
) COMMENT 'Records warehouse picking tasks generated to fulfill outbound deliveries, production material staging, or internal transfers. Captures task number, outbound delivery or production order reference, SKU, batch, pick quantity, confirmed quantity, source storage location, pick strategy (FIFO, FEFO, LIFO), task status, wave number, assigned picker, start time, and completion time. Aligned with Infor WMS pick task and SAP WM transfer order (GI).';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`inventory`.`abc_classification` (
    `abc_classification_id` BIGINT COMMENT 'Unique surrogate identifier for each ABC/XYZ inventory classification record per SKU and plant/warehouse combination in the Databricks Silver Layer.',
    `component_id` BIGINT COMMENT 'Foreign key linking to engineering.component. Business justification: ABC classification prioritizes inventory management by component value and velocity. Inventory planners use this with component BOMs and usage data for cycle count frequency and safety stock.',
    `inventory_sku_id` BIGINT COMMENT 'Foreign key linking to inventory.sku. Business justification: abc_classification.sku_number is a denormalized SKU code. ABC/XYZ classification is performed per SKU. Normalizing to sku_id FK links the classification to the SKU master.',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: abc_classification.storage_location is a denormalized location code. Normalizing to storage_location_id FK links the classification to the granular storage location master.',
    `warehouse_id` BIGINT COMMENT 'Foreign key linking to inventory.warehouse. Business justification: abc_classification.warehouse_number is a denormalized warehouse code. ABC classification is performed at the warehouse level. Normalizing to warehouse_id FK links the classification to the warehouse m',
    `abc_class` STRING COMMENT 'ABC inventory classification indicator: A = high-value or high-velocity items (typically top 10-20% of SKUs driving 70-80% of consumption value), B = medium-value/velocity items, C = low-value or slow-moving items. Aligned with SAP MM ABC indicator field.. Valid values are `A|B|C`',
    `abc_class_threshold_a` DECIMAL(18,2) COMMENT 'The cumulative value percentage threshold used to define the boundary between A and B class items in this classification run (e.g., 0.80 = top 80% of cumulative consumption value = Class A).',
    `abc_class_threshold_b` DECIMAL(18,2) COMMENT 'The cumulative value percentage threshold used to define the boundary between B and C class items in this classification run (e.g., 0.95 = items between 80% and 95% of cumulative value = Class B).',
    `analysis_period_end_date` DATE COMMENT 'The end date of the historical data window used to calculate the ABC/XYZ classification, defining the boundary of the consumption or demand data analyzed.',
    `analysis_period_start_date` DATE COMMENT 'The start date of the historical data window used to calculate the ABC/XYZ classification (e.g., beginning of the 12-month rolling period analyzed for consumption value or demand frequency).',
    `approval_date` DATE COMMENT 'The date on which the ABC/XYZ classification (or manual override) was formally approved by the responsible inventory manager or supply chain planner.',
    `approved_by` STRING COMMENT 'Name or employee ID of the inventory manager or supply chain planner who approved the ABC/XYZ classification, particularly required when a manual override is applied.',
    `class_changed_flag` BOOLEAN COMMENT 'Indicates whether the ABC or XYZ class has changed from the previous classification run. True = class change detected, triggering review of replenishment parameters, safety stock, and cycle count frequency.. Valid values are `true|false`',
    `classification_basis` STRING COMMENT 'The metric or criterion used to determine the ABC classification: consumption value (spend-based), turnover frequency (how often the item moves), issue quantity (volume of goods issued), revenue contribution, or demand frequency.. Valid values are `CONSUMPTION_VALUE|TURNOVER_FREQUENCY|ISSUE_QUANTITY|REVENUE_CONTRIBUTION|DEMAND_FREQUENCY`',
    `classification_date` DATE COMMENT 'The date on which the ABC/XYZ classification was calculated and assigned to the SKU at the plant/warehouse. Used to track classification currency and trigger review cycles.',
    `classification_method` STRING COMMENT 'Indicates whether the ABC/XYZ classification was determined by an automated system run (e.g., SAP MM ABC analysis job), manually assigned by a planner, or via a hybrid approach combining system output with manual override.. Valid values are `AUTOMATED|MANUAL|HYBRID`',
    `classification_timestamp` TIMESTAMP COMMENT 'Precise date and time when the ABC/XYZ classification record was created or last updated in the system, supporting audit trail and data lineage requirements.',
    `combined_class` STRING COMMENT 'Concatenated ABC and XYZ classification code (e.g., AX, BZ) representing the combined inventory management segment for the SKU. Used to drive differentiated replenishment, storage, and cycle counting strategies.. Valid values are `AX|AY|AZ|BX|BY|BZ|CX|CY|CZ`',
    `company_code` STRING COMMENT 'SAP company code identifying the legal entity or business unit responsible for the inventory at the plant/warehouse, used for financial reporting and inventory valuation alignment.',
    `consumption_quantity` DECIMAL(18,2) COMMENT 'Total quantity of the SKU consumed or issued during the analysis period, expressed in the base unit of measure. Used for quantity-based ABC classification.',
    `consumption_value` DECIMAL(18,2) COMMENT 'Total consumption value (quantity issued multiplied by unit cost) for the SKU during the analysis period, expressed in the local currency. This is the primary metric for ABC classification when basis is CONSUMPTION_VALUE.',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the plant or warehouse location where this ABC/XYZ classification applies, supporting multi-country reporting and regional inventory optimization.. Valid values are `[A-Z]{3}`',
    `cumulative_value_pct` DECIMAL(18,2) COMMENT 'The cumulative percentage of total consumption value represented by this SKU and all higher-ranked SKUs in the ABC analysis, used to determine class boundaries (e.g., A class = top 80% of cumulative value).',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the consumption value and inventory valuation amounts (e.g., USD, EUR, GBP).. Valid values are `[A-Z]{3}`',
    `cycle_count_frequency` STRING COMMENT 'The recommended cycle counting frequency for this SKU derived from its ABC classification: A-class items typically counted more frequently (e.g., monthly or quarterly), C-class items less frequently (e.g., annually).. Valid values are `WEEKLY|MONTHLY|QUARTERLY|SEMI_ANNUAL|ANNUAL`',
    `demand_coefficient_of_variation` DECIMAL(18,2) COMMENT 'Statistical coefficient of variation (standard deviation divided by mean) of demand during the analysis period, used as the primary metric for XYZ classification. Low CV = X class (stable), high CV = Z class (irregular).',
    `inventory_category` STRING COMMENT 'Category of inventory stock being classified: raw materials, Work In Progress (WIP), finished goods, Maintenance Repair and Operations (MRO), spare parts, or packaging materials.. Valid values are `RAW_MATERIAL|WIP|FINISHED_GOODS|MRO|SPARE_PART|PACKAGING`',
    `issue_frequency` STRING COMMENT 'Number of goods issue transactions for the SKU during the analysis period. Used as the basis for turnover frequency classification and XYZ demand regularity assessment.',
    `manual_override_flag` BOOLEAN COMMENT 'Indicates whether the ABC or XYZ class was manually overridden by a planner or inventory manager, deviating from the system-calculated classification. True = manual override applied.. Valid values are `true|false`',
    `material_group` STRING COMMENT 'SAP material group code categorizing the SKU into a commodity or product family, used for aggregated ABC analysis reporting.',
    `next_review_date` DATE COMMENT 'The scheduled date for the next ABC/XYZ classification review for this SKU at the plant/warehouse, calculated based on the classification date and review period.',
    `override_reason` STRING COMMENT 'Free-text justification provided by the planner or inventory manager when manually overriding the system-calculated ABC or XYZ classification (e.g., strategic item, new product ramp-up, seasonal adjustment).',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing or distribution facility where this ABC/XYZ classification applies.',
    `previous_abc_class` STRING COMMENT 'The ABC classification assigned to this SKU in the prior classification run, enabling detection of class changes and trend analysis over time.. Valid values are `A|B|C`',
    `previous_xyz_class` STRING COMMENT 'The XYZ demand variability classification assigned to this SKU in the prior classification run, used to identify demand pattern shifts.. Valid values are `X|Y|Z`',
    `replenishment_policy` STRING COMMENT 'The recommended inventory replenishment policy for this SKU based on its ABC/XYZ classification (e.g., AX items use continuous review with tight safety stock; CZ items may use periodic review or manual ordering).. Valid values are `CONTINUOUS_REVIEW|PERIODIC_REVIEW|JIT|KANBAN|MRP|MANUAL`',
    `review_period` STRING COMMENT 'The scheduled frequency at which the ABC/XYZ classification for this SKU is reviewed and potentially updated. Drives the cadence of re-running the classification analysis.. Valid values are `MONTHLY|QUARTERLY|SEMI_ANNUAL|ANNUAL`',
    `source_system` STRING COMMENT 'The operational system of record from which this ABC/XYZ classification record was sourced (e.g., SAP S/4HANA MM, Infor WMS, or manually entered).. Valid values are `SAP_S4HANA|INFOR_WMS|MANUAL`',
    `status` STRING COMMENT 'Current status of the ABC/XYZ classification record: ACTIVE = current valid classification, INACTIVE = no longer applicable (SKU discontinued), UNDER_REVIEW = pending reclassification, SUPERSEDED = replaced by a newer classification run.. Valid values are `ACTIVE|INACTIVE|UNDER_REVIEW|SUPERSEDED`',
    `storage_strategy` STRING COMMENT 'The recommended warehouse storage strategy for this SKU based on its ABC classification: A-class items stored in prime/ergonomic locations for fast picking, C-class items in remote or bulk storage.. Valid values are `PRIME_LOCATION|STANDARD|BULK|REMOTE|AUTOMATED`',
    `unit_of_measure` STRING COMMENT 'The base unit of measure for the SKU (e.g., EA, KG, L, M, PC) in which consumption quantity and stock quantities are expressed.',
    `value_rank` STRING COMMENT 'Ordinal rank of the SKU within the ABC analysis sorted by descending consumption value or classification basis metric. Rank 1 = highest value SKU.',
    `xyz_class` STRING COMMENT 'XYZ demand variability classification: X = stable and predictable demand (low coefficient of variation), Y = variable demand with identifiable trends or seasonality, Z = irregular or sporadic demand (high coefficient of variation). Used in conjunction with ABC class for replenishment policy decisions.. Valid values are `X|Y|Z`',
    CONSTRAINT pk_abc_classification PRIMARY KEY(`abc_classification_id`)
) COMMENT 'Stores the ABC/XYZ inventory classification results for each SKU at each plant or warehouse, used to prioritize cycle counting frequency, storage strategies, and replenishment policies. Captures SKU, plant/warehouse, ABC class (A=high value/velocity, B=medium, C=low), XYZ class (X=stable demand, Y=variable, Z=irregular), classification basis (consumption value, turnover frequency), classification date, and review period. Aligned with SAP MM ABC indicator and inventory optimization best practices.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`inventory`.`inventory_valuation` (
    `inventory_valuation_id` BIGINT COMMENT 'Unique surrogate identifier for each inventory valuation record in the silver layer lakehouse. Serves as the primary key for the inventory_valuation data product.',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: Inventory valuations are calculated and frozen per fiscal period for financial reporting. Period-end close process requires accurate period assignment for audit trails.',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Inventory valuation balances must map to balance sheet GL accounts for financial statement preparation. Finance teams reconcile these accounts monthly during period close.',
    `inventory_sku_id` BIGINT COMMENT 'Foreign key linking to inventory.sku. Business justification: inventory_valuation.sku_number is a denormalized SKU code. Inventory valuation is performed per SKU at plant level. Normalizing to sku_id FK eliminates redundant descriptive columns and links valuatio',
    `abc_classification` STRING COMMENT 'The ABC inventory classification of the material based on consumption value or strategic importance. A = High value/high priority, B = Medium value/medium priority, C = Low value/low priority. Used for inventory control prioritization, cycle counting frequency, and safety stock policy.. Valid values are `A|B|C`',
    `base_unit_of_measure` STRING COMMENT 'The base unit of measure in which the material stock quantity is managed and the valuation price is expressed (e.g., EA, KG, L, M, PC). Corresponds to SAP MARA.MEINS. Required for accurate stock value calculation.. Valid values are `^[A-Z]{2,3}$`',
    `class` STRING COMMENT 'SAP valuation class (BKLAS) that determines the general ledger accounts updated during inventory movements. Groups materials with similar accounting treatment (e.g., raw materials, finished goods, WIP, MRO). Critical for COGS and balance sheet posting.. Valid values are `^[A-Z0-9]{1,4}$`',
    `company_code` STRING COMMENT 'The SAP company code representing the legal entity or organizational unit responsible for the inventory valuation. Used for financial consolidation, intercompany reconciliation, and statutory reporting across multinational operations.. Valid values are `^[A-Z0-9]{1,4}$`',
    `cost_estimate_number` STRING COMMENT 'The SAP product cost estimate number (from CO-PC) that was used to calculate or release the current standard price. Links the inventory valuation to the underlying cost estimate for traceability and variance analysis. Corresponds to SAP KEKO.KALNR.. Valid values are `^[0-9]{1,12}$`',
    `currency_code` STRING COMMENT 'The ISO 4217 three-letter currency code in which the inventory valuation amounts (standard price, moving average price, total stock value) are expressed. Corresponds to the local currency of the company code or valuation area (e.g., USD, EUR, CNY).. Valid values are `^[A-Z]{3}$`',
    `date` DATE COMMENT 'The business date as of which the inventory valuation snapshot is captured. For period-end closing, this is the last day of the fiscal period. For on-demand valuations, this is the date the valuation was requested or extracted.. Valid values are `^d{4}-d{2}-d{2}$`',
    `exchange_rate` DECIMAL(18,2) COMMENT 'The foreign exchange rate applied to translate the local currency inventory value to the group currency as of the valuation date. Used for multi-currency financial consolidation and reporting.',
    `fiscal_period` STRING COMMENT 'The fiscal period (month) within the fiscal year to which this valuation record belongs (01–12 for standard periods, up to 16 for special periods). Corresponds to SAP MBEW.LFMON. Used for period-end inventory closing and financial reporting.. Valid values are `^(0[1-9]|1[0-6])$`',
    `fiscal_year` STRING COMMENT 'The fiscal year to which this inventory valuation record belongs. Used for period-end closing, financial reporting, and year-over-year inventory analysis. Aligns with the companys fiscal calendar.. Valid values are `^d{4}$`',
    `future_planned_price` DECIMAL(18,2) COMMENT 'The planned standard price for the next cost estimate or future period, staged for release. Corresponds to SAP MBEW.ZKPRS (future price field). Used in standard cost roll and cost estimate release planning.',
    `future_price_valid_from_date` DATE COMMENT 'The date from which the future planned price becomes effective. Used to schedule standard cost releases at the start of a new fiscal period or cost estimate period. Corresponds to SAP MBEW.ZKDAT.. Valid values are `^d{4}-d{2}-d{2}$`',
    `gl_account_code` STRING COMMENT 'The general ledger account code to which the inventory value is posted on the balance sheet. Determined by the valuation class and account determination configuration. Used for financial reconciliation between MM and FI modules.. Valid values are `^[0-9]{1,10}$`',
    `group_currency_code` STRING COMMENT 'The ISO 4217 three-letter currency code for the corporate group reporting currency used in consolidated financial statements (e.g., USD, EUR). Enables multi-currency inventory valuation reporting across global operations.. Valid values are `^[A-Z]{3}$`',
    `inventory_category` STRING COMMENT 'The category of inventory being valued, classifying the material by its stage in the production lifecycle. Raw Material (RM), Work In Progress (WIP), Finished Goods (FG), Maintenance Repair and Operations (MRO), Semi-Finished, Trading Goods, or Spare Parts. Used for balance sheet sub-classification and COGS analysis.. Valid values are `raw_material|wip|finished_goods|mro|semi_finished|trading_goods|spare_parts`',
    `last_price_change_date` DATE COMMENT 'The date on which the standard price or moving average price was last changed for this material at the valuation area. Corresponds to SAP MBEW.LAEPR. Used for price variance analysis, audit trails, and identifying stale standard costs.. Valid values are `^d{4}-d{2}-d{2}$`',
    `lowest_value_devaluation_pct` DECIMAL(18,2) COMMENT 'The percentage devaluation applied to the inventory under the lowest value principle (LVP) for balance sheet reporting. Reflects write-downs for slow-moving, obsolete, or damaged stock. Corresponds to SAP MBEW.ABWKZ / devaluation indicator logic. Required for IFRS IAS 2 net realizable value (NRV) assessment.',
    `method` STRING COMMENT 'The accounting valuation method applied to determine the cost of inventory. Standard Cost uses a predetermined cost; Moving Average Price recalculates with each receipt; FIFO (First-In First-Out) and LIFO (Last-In First-Out) are layer-based methods. Determines COGS and balance sheet inventory value.. Valid values are `standard_cost|moving_average_price|fifo|lifo|weighted_average`',
    `moving_average_price` DECIMAL(18,2) COMMENT 'The current weighted moving average cost per unit of measure, recalculated after each goods receipt or invoice verification when price control is V. Corresponds to SAP MBEW.VERPR. Reflects the most current average procurement cost.',
    `net_realizable_value` DECIMAL(18,2) COMMENT 'The estimated selling price of the inventory in the ordinary course of business less the estimated costs of completion and the estimated costs necessary to make the sale. Required under IFRS IAS 2 to test whether inventory should be written down below cost. Used for period-end impairment assessment.',
    `plant_code` STRING COMMENT 'The SAP plant code representing the manufacturing facility or distribution center where the inventory is held and valued. Corresponds to MBEW.BWKEY (valuation area) when valuation is at plant level.. Valid values are `^[A-Z0-9]{1,4}$`',
    `previous_standard_price` DECIMAL(18,2) COMMENT 'The standard price that was in effect before the most recent price change. Corresponds to SAP MBEW.ZKPRS. Used for price variance analysis, standard cost roll comparison, and audit of cost changes during period-end closing.',
    `price_control_indicator` STRING COMMENT 'Indicates the inventory valuation method applied to the material. S = Standard Price (fixed standard cost used for all movements); V = Moving Average Price (price recalculated with each goods receipt). Corresponds to SAP MBEW.VPRSV. Drives how inventory is valued on the balance sheet.. Valid values are `S|V`',
    `price_unit` DECIMAL(18,2) COMMENT 'The quantity unit basis for which the standard price or moving average price is expressed (e.g., price per 1 unit, per 100 units, per 1000 units). Corresponds to SAP MBEW.PEINH. Essential for correct per-unit cost calculation.',
    `record_timestamp` TIMESTAMP COMMENT 'The timestamp at which this inventory valuation record was extracted from the source system and loaded into the silver layer lakehouse. Used for data freshness tracking, incremental load processing, and audit trail.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `snapshot_type` STRING COMMENT 'Indicates whether this valuation record was captured as part of a scheduled period-end closing, year-end closing, or an on-demand/ad-hoc valuation request. Used to distinguish official financial closing snapshots from operational queries.. Valid values are `period_end|on_demand|year_end|interim`',
    `source_system` STRING COMMENT 'The operational system of record from which this inventory valuation record was sourced. Primarily SAP S/4HANA MM (MBEW table), but may include Infor WMS for warehouse-level stock positions or manual adjustments. Used for data lineage and reconciliation.. Valid values are `SAP_S4HANA|INFOR_WMS|MANUAL`',
    `special_stock_indicator` STRING COMMENT 'Indicates whether the inventory belongs to a special stock category. SAP special stock types include: E = Sales Order Stock, K = Consignment Stock at Customer, O = Parts Provided to Vendor, Q = Project Stock, V = Consignment Stock from Vendor, W = Vendor Managed Inventory. Empty for standard unrestricted stock.. Valid values are `E|K|O|Q|V|W||`',
    `standard_price` DECIMAL(18,2) COMMENT 'The predetermined fixed cost per unit of measure for the material when price control is S (Standard Price). Used for all inventory movements and variance analysis. Corresponds to SAP MBEW.STPRS. Expressed in the local currency of the valuation area.',
    `total_stock_quantity` DECIMAL(18,2) COMMENT 'The total quantity of valuated stock on hand for the material at the plant/valuation area as of the valuation date. Corresponds to SAP MBEW.LBKUM. Used to calculate total stock value (total_stock_quantity × price).',
    `total_stock_value` DECIMAL(18,2) COMMENT 'The total financial value of the valuated stock at the plant level, calculated as total_stock_quantity × (standard_price or moving_average_price) / price_unit. Corresponds to SAP MBEW.SALK3 (standard price) or MBEW.VERPR-based value. Used for balance sheet inventory reporting and period-end closing.',
    `total_value_group_currency` DECIMAL(18,2) COMMENT 'The total inventory value translated into the group (corporate) reporting currency for consolidated financial statements. Supports multinational consolidation and group-level balance sheet reporting. Derived from local currency value using the applicable exchange rate.',
    `total_value_local_currency` DECIMAL(18,2) COMMENT 'The total inventory value expressed in the local (company code) currency. Corresponds to SAP MBEW.SALK3 for standard price or the MAP-based value. Used for local statutory financial reporting and balance sheet preparation.',
    `type` STRING COMMENT 'SAP split valuation type (BWTAR) used when a single material is valuated differently based on origin, quality, or batch. For example, externally procured vs. internally produced stock may carry different values. Empty if split valuation is not active.. Valid values are `^[A-Z0-9_]{0,10}$`',
    CONSTRAINT pk_inventory_valuation PRIMARY KEY(`inventory_valuation_id`)
) COMMENT 'Captures the financial valuation of inventory positions by SKU, plant, and valuation class at period-end and on-demand. Records valuation method (standard cost, moving average price, FIFO, LIFO), standard price, moving average price, total stock value, currency, valuation date, price control indicator, and last price change date. Supports COGS calculation, balance sheet inventory reporting, and period-end closing. Aligned with SAP MM material valuation (MBEW).';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`inventory`.`wip_stock` (
    `wip_stock_id` BIGINT COMMENT 'Unique surrogate identifier for each WIP stock record in the silver layer lakehouse. Serves as the primary key for the wip_stock data product.',
    `component_id` BIGINT COMMENT 'Foreign key linking to engineering.component. Business justification: WIP stock tracks in-process components on the production floor. Manufacturing execution systems need component specifications and BOPs to route work and validate assembly operations.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: WIP inventory is held at specific production cost centers for departmental cost tracking and overhead allocation. Essential for manufacturing cost control and reporting.',
    `inventory_sku_id` BIGINT COMMENT 'Foreign key linking to inventory.sku. Business justification: wip_stock.sku_number is a denormalized SKU code. WIP stock tracks the finished good or semi-finished material being produced. Normalizing to sku_id FK links WIP records to the SKU master.',
    `lot_batch_id` BIGINT COMMENT 'Foreign key linking to inventory.lot_batch. Business justification: wip_stock.batch_number is a denormalized batch reference. WIP inventory is often batch-managed. Normalizing to lot_batch_id FK enables batch-level traceability for WIP.',
    `order_id` BIGINT COMMENT 'Foreign key linking to production.production_order. Business justification: WIP stock tied to production order - normalize by replacing production_order_number text with FK',
    `ot_system_id` BIGINT COMMENT 'Foreign key linking to technology.ot_system. Business justification: WIP stock is tracked and controlled by MES (Manufacturing Execution System) on the shop floor. Production teams need to identify which OT system manages real-time WIP visibility and material flow cont',
    `production_order_cost_id` BIGINT COMMENT 'Foreign key linking to finance.production_order_cost. Business justification: Work-in-process inventory must link to production order costs for accurate WIP valuation and variance calculation. Cost accounting uses this for manufacturing cost analysis.',
    `rd_project_id` BIGINT COMMENT 'Foreign key linking to research.rd_project. Business justification: WIP for prototype builds and pilot runs is tracked separately by R&D project. Manufacturing operations segregate R&D WIP from production WIP for cost accounting and project budget tracking.',
    `sales_order_id` BIGINT COMMENT 'Foreign key linking to order.sales_order. Business justification: WIP stock allocated to sales order - normalize by replacing sales_order_number text with FK',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: wip_stock.storage_location_code is a denormalized location code. WIP inventory is staged at specific storage locations on the shop floor. Normalizing to storage_location_id FK links WIP records to the',
    `run_id` BIGINT COMMENT 'Identifier of the SAP CO WIP calculation run that generated or last updated this WIP stock record. Provides audit traceability for period-end WIP postings and financial close processes.. Valid values are `^[A-Z0-9-]{1,30}$`',
    `abc_classification` STRING COMMENT 'ABC inventory classification of the material being produced, indicating its relative value and management priority (A=high value, B=medium, C=low). Drives WIP monitoring frequency and management attention.. Valid values are `A|B|C`',
    `actual_completion_date` DATE COMMENT 'The date on which the production order was actually fully confirmed and all WIP was converted to finished goods or settled. Populated upon order completion; null while order is open.. Valid values are `^d{4}-d{2}-d{2}$`',
    `company_code` STRING COMMENT 'SAP FI company code representing the legal entity responsible for the production order and WIP valuation. Supports multi-entity financial consolidation and statutory reporting.. Valid values are `^[A-Z0-9]{4}$`',
    `confirmed_quantity` DECIMAL(18,2) COMMENT 'The quantity of the production order that has been confirmed as completed at the current or previous operations. Used to calculate remaining WIP and track production progress.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the plant where WIP stock is held. Supports multi-country regulatory compliance, customs reporting, and regional WIP analysis.. Valid values are `^[A-Z]{3}$`',
    `expected_completion_date` DATE COMMENT 'The planned or revised expected date by which the production order is expected to be fully confirmed and WIP converted to finished goods. Critical for delivery commitment and ATP calculations.. Valid values are `^d{4}-d{2}-d{2}$`',
    `fiscal_period` STRING COMMENT 'The fiscal period (posting period) within the fiscal year for which WIP is calculated and reported. Used for period-end WIP balance sheet postings in SAP CO.. Valid values are `^(0[1-9]|1[0-6])$`',
    `fiscal_year` STRING COMMENT 'The fiscal year in which the WIP stock record is relevant for financial reporting and period-end WIP calculation. Aligns with SAP FI fiscal year variant.. Valid values are `^[0-9]{4}$`',
    `goods_issue_date` DATE COMMENT 'The date on which raw materials or components were issued from inventory to the production order, initiating the WIP position. Corresponds to SAP goods issue posting date.. Valid values are `^d{4}-d{2}-d{2}$`',
    `group_currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the corporate group reporting currency (e.g., USD, EUR). Used for consolidated WIP valuation across all plants and regions.. Valid values are `^[A-Z]{3}$`',
    `last_confirmation_timestamp` TIMESTAMP COMMENT 'The date and time of the most recent operation confirmation posted against the production order in SAP PP or Siemens Opcenter MES. Tracks real-time production progress.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `local_currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the plants local currency used in WIP valuation (e.g., USD, EUR, CNY). Required for multi-currency financial reporting.. Valid values are `^[A-Z]{3}$`',
    `make_to_strategy` STRING COMMENT 'Manufacturing strategy governing the production order: Make-To-Order (MTO), Make-To-Stock (MTS), Engineer-To-Order (ETO), or Assemble-To-Order (ATO). Determines how WIP is linked to customer demand.. Valid values are `MTO|MTS|ETO|ATO`',
    `mrp_controller` STRING COMMENT 'The MRP controller code responsible for the material being produced. Used to assign WIP monitoring and exception management responsibilities to the correct planner.. Valid values are `^[A-Z0-9]{1,3}$`',
    `operation_description` STRING COMMENT 'Human-readable description of the routing operation step where WIP resides (e.g., Welding, Assembly, Painting). Supports shop floor reporting and WIP analysis.',
    `operation_number` STRING COMMENT 'The routing operation step number (e.g., 0010, 0020) at which WIP is currently positioned within the production order. Identifies the specific manufacturing step where materials are in progress.. Valid values are `^[0-9]{4}$`',
    `order_quantity` DECIMAL(18,2) COMMENT 'The total planned quantity of the production order. Used to calculate completion percentage and remaining WIP quantity against the original order target.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility where the WIP stock resides. Enables multi-plant WIP reporting and inventory valuation by plant.. Valid values are `^[A-Z0-9]{4}$`',
    `production_order_type` STRING COMMENT 'SAP order type classification indicating the nature of the production order (e.g., PP01 standard production, PP02 repetitive, PI01 process industry). Drives cost collection and settlement rules.. Valid values are `PP01|PP02|PP03|PI01|PI02|PM01|REM`',
    `production_scheduler` STRING COMMENT 'The production scheduler or planner code responsible for managing the production order. Supports accountability tracking and workload distribution in production planning.. Valid values are `^[A-Z0-9]{1,8}$`',
    `production_start_date` DATE COMMENT 'The scheduled or actual start date of the production order. Used for WIP aging analysis, lead time calculation, and production scheduling performance reporting.. Valid values are `^d{4}-d{2}-d{2}$`',
    `profit_center_code` STRING COMMENT 'SAP CO profit center assigned to the production order. Enables WIP reporting and profitability analysis at the profit center level for management accounting.. Valid values are `^[A-Z0-9]{4,10}$`',
    `scrap_quantity` DECIMAL(18,2) COMMENT 'Quantity of material scrapped during the production process at the current operation. Impacts WIP valuation and is used for scrap rate analysis and quality reporting.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `status` STRING COMMENT 'Current status of the WIP stock record reflecting the production orders progress. Drives WIP reporting, financial period-end closing, and inventory position accuracy.. Valid values are `open|partially_confirmed|fully_confirmed|technically_completed|closed|cancelled`',
    `unit_of_measure` STRING COMMENT 'Base unit of measure for the WIP quantity (e.g., EA, KG, L, M, PC). Aligns with the material master unit of measure in SAP.. Valid values are `^[A-Z]{2,5}$`',
    `valuation_method` STRING COMMENT 'The inventory valuation method applied to calculate WIP value (e.g., standard cost, moving average, actual cost). Determines how WIP is valued on the balance sheet.. Valid values are `standard_cost|moving_average|actual_cost|fifo|lifo`',
    `wip_quantity` DECIMAL(18,2) COMMENT 'The quantity of material currently in progress at the specified operation step, expressed in the base unit of measure. Represents materials issued to production but not yet confirmed as finished goods.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `wip_value_group_currency` DECIMAL(18,2) COMMENT 'The financial value of WIP inventory translated to the corporate group reporting currency. Supports consolidated financial reporting across multinational operations.. Valid values are `^-?[0-9]+(.[0-9]{1,2})?$`',
    `wip_value_local_currency` DECIMAL(18,2) COMMENT 'The financial value of WIP inventory in the plants local currency, calculated using SAP CO WIP calculation (actual or standard cost). Used for balance sheet reporting and inventory valuation.. Valid values are `^-?[0-9]+(.[0-9]{1,2})?$`',
    `work_center_code` STRING COMMENT 'SAP work center identifier where the current operation is being performed. Represents the machine, production line, or labor group executing the operation.. Valid values are `^[A-Z0-9]{1,8}$`',
    CONSTRAINT pk_wip_stock PRIMARY KEY(`wip_stock_id`)
) COMMENT 'Tracks Work-In-Progress (WIP) inventory at the production order and operation level, capturing materials that have been issued to production but not yet confirmed as finished goods. Records production order reference, operation step, WIP quantity, WIP valuation, plant, cost center, WIP status (open, partially confirmed, fully confirmed), and expected completion date. Bridges the inventory and production domains for accurate WIP reporting. Aligned with SAP PP/CO WIP calculation.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`inventory`.`quarantine_hold` (
    `quarantine_hold_id` BIGINT COMMENT 'Unique system-generated identifier for each quarantine or quality hold record in the inventory management system.',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Quality holds on inventory batches often relate to specific customer orders or customer-reported defects. Tracking the affected customer account is essential for notification, replacement, and quality',
    `employee_id` BIGINT COMMENT 'Employee ID of the quality authority (e.g., Quality Engineer, QA Manager) who approved the disposition decision and authorized release or scrapping of the quarantined inventory.',
    `capa_record_id` BIGINT COMMENT 'Foreign key linking to compliance.capa_record. Business justification: Releasing quarantined inventory requires completed CAPA (Corrective and Preventive Action). Quality managers link holds to CAPA records to track resolution before material disposition decisions.',
    `compliance_audit_finding_id` BIGINT COMMENT 'Foreign key linking to compliance.audit_finding. Business justification: Quarantine holds often result from audit findings identifying non-conforming material. Quality teams place inventory on hold pending investigation and corrective action from compliance audits.',
    `component_id` BIGINT COMMENT 'Foreign key linking to engineering.component. Business justification: Quarantine holds isolate non-conforming inventory. Quality engineers reference component specifications, DFMEAs, and material specs to disposition quarantined parts for rework, scrap, or return.',
    `equipment_id` BIGINT COMMENT 'Foreign key linking to asset.equipment. Business justification: Quarantine holds can be placed on inventory due to equipment failures or contamination. Quality teams link quarantined stock to the specific equipment that caused the quality issue for root cause anal',
    `incident_id` BIGINT COMMENT 'Foreign key linking to hse.incident. Business justification: Inventory quarantine holds are often triggered by safety incidents (contamination, spills, exposure events). Quality and HSE teams must link quarantined stock to originating incident for investigation',
    `initiated_by_employee_id` BIGINT COMMENT 'Employee ID of the person who initiated the quarantine hold (e.g., quality inspector, receiving clerk, production supervisor). Supports accountability and audit trail.',
    `inventory_sku_id` BIGINT COMMENT 'Foreign key linking to inventory.sku. Business justification: quarantine_hold.sku_number is a denormalized SKU code. Every quarantine hold is placed on a specific SKU. Normalizing to sku_id FK links the hold to the SKU master.',
    `logistics_inbound_delivery_id` BIGINT COMMENT 'Foreign key linking to logistics.inbound_delivery. Business justification: Quality control places received goods on quarantine hold pending inspection. Manufacturing tracks which inbound delivery triggered the hold for quality traceability and supplier performance.',
    `lot_batch_id` BIGINT COMMENT 'Foreign key linking to inventory.lot_batch. Business justification: quarantine_hold.batch_number is a denormalized batch reference. Normalizing to lot_batch_id FK enables batch-level traceability for quality holds.',
    `ncr_id` BIGINT COMMENT 'Foreign key linking to quality.ncr. Business justification: Quarantine hold triggered by NCR - normalize by replacing ncr_number text with FK to quality.ncr',
    `procurement_purchase_order_id` BIGINT COMMENT 'Foreign key linking to procurement.purchase_order. Business justification: Quarantine hold references purchase order - normalize by replacing purchase_order_number text with FK',
    `rd_test_plan_id` BIGINT COMMENT 'Foreign key linking to research.rd_test_plan. Business justification: Inventory is quarantined pending R&D test completion for new materials, supplier changes, or quality issues. Warehouse cannot release stock until R&D validates and approves via test plan.',
    `serialized_unit_id` BIGINT COMMENT 'Foreign key linking to inventory.serialized_unit. Business justification: quarantine_hold.serial_number is a denormalized serial number reference. Normalizing to serialized_unit_id FK links serialized item holds to the serialized unit master for unit-level quality traceabil',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: quarantine_hold.storage_location is a denormalized location code. Normalizing to storage_location_id FK links each quarantine hold to the granular storage location.',
    `warehouse_id` BIGINT COMMENT 'Foreign key linking to inventory.warehouse. Business justification: quarantine_hold.warehouse_number is a denormalized warehouse code. Normalizing to warehouse_id FK links each quarantine hold to the warehouse master.',
    `actual_release_date` DATE COMMENT 'Actual calendar date on which the quarantine hold was resolved and the inventory was released, scrapped, returned, or otherwise dispositioned.. Valid values are `^d{4}-d{2}-d{2}$`',
    `authorized_by_name` STRING COMMENT 'Full name of the employee who authorized the disposition decision. Retained for audit trail and regulatory compliance reporting.',
    `capa_reference_number` STRING COMMENT 'Reference number of the Corrective and Preventive Action (CAPA) record initiated as a result of this quarantine hold. Links quality hold management to the broader quality improvement process.',
    `company_code` STRING COMMENT 'SAP company code of the legal entity responsible for the quarantined inventory. Required for financial posting of scrap, rework costs, and vendor debit memos.. Valid values are `^[A-Z0-9]{4}$`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the plant or facility where the quarantine hold is active. Supports multi-country regulatory compliance and regional reporting.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp when the quarantine hold record was first created in the data platform. Used for audit trail and data lineage tracking.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the hold value and valuation price (e.g., USD, EUR, CNY). Supports multi-currency financial reporting for multinational operations.. Valid values are `^[A-Z]{3}$`',
    `disposition_decision` STRING COMMENT 'Final disposition decision made by the quality authority for the quarantined inventory. Drives downstream actions such as stock release, rework order creation, scrap posting, or vendor return.. Valid values are `accept|accept_with_deviation|rework|scrap|return_to_vendor|regrade|destroy|pending`',
    `disposition_notes` STRING COMMENT 'Free-text notes documenting the rationale, conditions, or instructions associated with the disposition decision, including any deviations or special handling requirements.',
    `expected_release_date` DATE COMMENT 'Planned date by which the quarantine hold is expected to be resolved and the inventory released or dispositioned. Used for production planning, ATP calculations, and supply chain impact assessment.. Valid values are `^d{4}-d{2}-d{2}$`',
    `hold_quantity` DECIMAL(18,2) COMMENT 'Quantity of the SKU/material placed under quarantine hold, expressed in the base unit of measure. Represents the total blocked stock quantity pending disposition.',
    `hold_reason` STRING COMMENT 'Detailed narrative description of the specific reason the inventory was placed on hold, providing context beyond the hold type classification for quality investigation and reporting.',
    `hold_reason_code` STRING COMMENT 'Standardized short code representing the hold reason, used for categorization, reporting, and integration with SAP QM defect codes and Infor WMS hold reason configuration.',
    `hold_reference_number` STRING COMMENT 'Business-facing alphanumeric reference number assigned to the quarantine hold, used for cross-system tracking and communication with quality, procurement, and operations teams.. Valid values are `^QH-[A-Z0-9]{2,10}-[0-9]{6,12}$`',
    `hold_start_date` DATE COMMENT 'Calendar date on which the inventory was officially placed under quarantine hold. Used for aging analysis, SLA tracking, and regulatory compliance reporting.. Valid values are `^d{4}-d{2}-d{2}$`',
    `hold_start_timestamp` TIMESTAMP COMMENT 'Precise date and time when the quarantine hold was initiated in the system, including timezone offset. Used for exact duration calculations and audit trail.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `hold_type` STRING COMMENT 'Classification of the quarantine hold indicating the primary reason category for blocking the stock. Drives the disposition workflow and responsible team assignment.. Valid values are `quality_inspection|customer_return|regulatory_hold|damage_hold|supplier_deviation|engineering_change|environmental_hold|customs_hold`',
    `hold_value` DECIMAL(18,2) COMMENT 'Total financial value of the quarantined inventory (hold quantity × valuation price) in the local currency. Used for financial exposure reporting and management escalation thresholds.',
    `initiating_document_number` STRING COMMENT 'Reference number of the source document (NCR number, GRN number, complaint ID, etc.) that triggered the quarantine hold, enabling cross-document traceability.',
    `initiating_document_type` STRING COMMENT 'Type of source document that triggered the quarantine hold (e.g., Non-Conformance Report, Goods Receipt Note, customer complaint). Establishes the business context and traceability chain.. Valid values are `NCR|GRN|customer_complaint|inspection_lot|deviation_report|regulatory_notice|internal_audit|supplier_notification`',
    `inspection_lot_number` STRING COMMENT 'SAP QM inspection lot number linked to this quarantine hold, enabling direct traceability to the quality inspection results and usage decision in SAP.',
    `inventory_category` STRING COMMENT 'Category of the quarantined inventory indicating its stage in the production lifecycle (raw material, WIP, finished goods, MRO, etc.). Drives reporting segmentation and disposition workflows.. Valid values are `raw_material|wip|finished_goods|mro|semi_finished|packaging|spare_part`',
    `last_updated_timestamp` TIMESTAMP COMMENT 'System timestamp of the most recent update to the quarantine hold record. Supports change tracking, SLA monitoring, and data freshness validation.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing or distribution facility where the quarantined inventory is physically located.. Valid values are `^[A-Z0-9]{4}$`',
    `regulatory_reference` STRING COMMENT 'Reference to the specific regulatory requirement, standard, or authority notice that triggered or governs the hold (e.g., REACH Article 33, RoHS Directive, OSHA citation). Applicable for regulatory holds.',
    `release_authorization_number` STRING COMMENT 'Reference number of the formal authorization document approving the disposition decision and release of the quarantine hold. Required for regulated industries and audit compliance.',
    `released_quantity` DECIMAL(18,2) COMMENT 'Quantity of the held inventory that was approved for release back to unrestricted stock following inspection or disposition. May be less than the original hold quantity if partial disposition occurred.',
    `return_to_vendor_quantity` DECIMAL(18,2) COMMENT 'Quantity of the held inventory to be returned to the originating supplier. Initiates the vendor return process in SAP MM and may trigger supplier corrective action.',
    `rework_quantity` DECIMAL(18,2) COMMENT 'Quantity of the held inventory directed to rework operations to bring it into conformance with specifications. Triggers rework production order creation in SAP PP/MES.',
    `scrapped_quantity` DECIMAL(18,2) COMMENT 'Quantity of the held inventory that was dispositioned as scrap following inspection. Used for scrap rate reporting, COGS impact analysis, and waste tracking.',
    `source_system` STRING COMMENT 'Identifier of the operational system of record from which this quarantine hold record originated (e.g., SAP QM, Infor WMS, Siemens Opcenter MES). Supports data lineage and reconciliation.. Valid values are `SAP_QM|INFOR_WMS|OPCENTER_MES|MANUAL|SALESFORCE_CRM`',
    `status` STRING COMMENT 'Current lifecycle status of the quarantine hold record, tracking progression from initial hold through inspection, disposition decision, and final resolution.. Valid values are `open|under_inspection|pending_disposition|disposition_approved|released|scrapped|returned_to_vendor|reworked|escalated|closed`',
    `stock_type` STRING COMMENT 'SAP stock type classification of the quarantined inventory (e.g., blocked stock, quality inspection stock). Determines how the stock is treated in MRP and availability checks.. Valid values are `blocked|quality_inspection|restricted|unrestricted`',
    `supplier_number` STRING COMMENT 'SAP vendor/supplier number associated with the quarantined material, applicable when the hold is related to incoming goods from a specific supplier. Enables supplier quality performance tracking.',
    `unit_of_measure` STRING COMMENT 'Base unit of measure for the hold quantity (e.g., EA for each, KG for kilogram, L for liter). Aligns with SAP base UoM for the material.. Valid values are `EA|KG|LB|L|ML|M|M2|M3|PC|BOX|PAL|ROL|SET|TON`',
    `valuation_price` DECIMAL(18,2) COMMENT 'Unit valuation price of the quarantined material at the time of hold creation, used to calculate the financial exposure of the blocked stock for inventory valuation and financial reporting.',
    CONSTRAINT pk_quarantine_hold PRIMARY KEY(`quarantine_hold_id`)
) COMMENT 'Manages inventory items placed under quality hold, quarantine, or blocked stock status pending inspection, disposition, or regulatory clearance. Captures hold reference number, SKU, batch, quantity, storage location, hold type (quality inspection, customer return, regulatory hold, damage hold), hold reason, initiating document (NCR, GRN, customer complaint), hold start date, expected release date, disposition decision (accept, rework, scrap, return to vendor), and release authorization. Aligned with SAP QM usage decision and Infor WMS hold management.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`inventory`.`serialized_unit` (
    `serialized_unit_id` BIGINT COMMENT 'Unique surrogate identifier for each serialized unit record in the inventory system. Serves as the primary key for the serialized_unit data product in the Databricks Silver Layer.',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Serialized units (motors, drives, controllers) are tracked to specific customer accounts for warranty, service history, and recall management. Critical for installed base management in industrial manu',
    `component_id` BIGINT COMMENT 'Foreign key linking to engineering.component. Business justification: Serialized units track individual instances of engineered components with unique serial numbers. Quality and traceability teams use this for warranty claims, recalls, and compliance tracking.',
    `equipment_id` BIGINT COMMENT 'Foreign key linking to asset.equipment. Business justification: Serialized unit becomes equipment/asset when installed - normalize by replacing equipment_number text with FK to asset.equipment',
    `iiot_platform_id` BIGINT COMMENT 'Foreign key linking to technology.iiot_platform. Business justification: Serialized units with embedded sensors stream telemetry data to IIoT platforms. Smart manufacturing requires linking physical serialized assets to their digital twin platform for predictive maintenanc',
    `inventory_sku_id` BIGINT COMMENT 'Foreign key linking to inventory.sku. Business justification: serialized_unit.sku_number is a denormalized SKU code. Every serialized unit is an instance of a specific SKU. Normalizing to sku_id FK links the serialized unit master to the SKU master.',
    `lot_batch_id` BIGINT COMMENT 'Foreign key linking to inventory.lot_batch. Business justification: serialized_unit.batch_number is a denormalized batch reference. Normalizing to lot_batch_id FK links each serialized unit to its production batch for full genealogy traceability.',
    `order_id` BIGINT COMMENT 'Foreign key linking to production.production_order. Business justification: Serialized unit produced from production order - normalize by replacing production_order_number text with FK',
    `procurement_purchase_order_id` BIGINT COMMENT 'Foreign key linking to procurement.purchase_order. Business justification: Serialized unit received from purchase order - normalize by replacing purchase_order_number text with FK',
    `sales_order_id` BIGINT COMMENT 'Foreign key linking to order.sales_order. Business justification: Serialized unit allocated to sales order - normalize by replacing sales_order_number text with FK',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: serialized_unit.storage_location_code is a denormalized location code. Normalizing to storage_location_id FK links each serialized unit to its current granular storage location.',
    `warehouse_id` BIGINT COMMENT 'Foreign key linking to inventory.warehouse. Business justification: serialized_unit.warehouse_number is a denormalized warehouse code. Normalizing to warehouse_id FK links each serialized unit to its current warehouse location.',
    `abc_classification` STRING COMMENT 'The ABC inventory classification of the SKU associated with this serialized unit, indicating its relative value and management priority. A-class items are high-value/high-priority; C-class are low-value/low-priority.. Valid values are `A|B|C`',
    `company_code` STRING COMMENT 'The SAP company code representing the legal entity that owns this serialized unit for financial accounting and inventory valuation purposes. Supports intercompany and multi-entity reporting.. Valid values are `^[A-Z0-9]{4}$`',
    `country_code` STRING COMMENT 'The ISO 3166-1 alpha-3 country code of the country where this serialized unit is currently located. Supports multi-country inventory reporting, regulatory compliance, and cross-border logistics.. Valid values are `^[A-Z]{3}$`',
    `country_of_origin` STRING COMMENT 'The ISO 3166-1 alpha-3 country code indicating the country where this serialized unit was manufactured. Required for customs declarations, import/export compliance, and RoHS/REACH regulatory reporting.. Valid values are `^[A-Z]{3}$`',
    `customer_delivery_number` STRING COMMENT 'The SAP SD outbound delivery document number associated with the shipment of this serialized unit to a customer. Enables end-to-end traceability from inventory to customer delivery.. Valid values are `^[A-Z0-9]{1,10}$`',
    `goods_receipt_date` DATE COMMENT 'The date on which this serialized unit was received into inventory via a goods receipt posting. Marks the start of inventory ownership and is used for aging analysis and FIFO/FEFO valuation.. Valid values are `^d{4}-d{2}-d{2}$`',
    `hazardous_material` BOOLEAN COMMENT 'Indicates whether this serialized unit is classified as a hazardous material requiring special handling, storage, or transportation procedures. Drives compliance with OSHA, EPA, and transport regulations.. Valid values are `true|false`',
    `infor_wms_serial_code` STRING COMMENT 'The unique serial unit identifier assigned by the Infor WMS system for warehouse operations tracking. Used for reconciliation between SAP MM serial number records and Infor WMS operational data.. Valid values are `^[A-Z0-9-]{1,50}$`',
    `inspection_status` STRING COMMENT 'The current quality inspection status of this serialized unit. Indicates whether the unit has passed, failed, or is pending quality inspection before being released to unrestricted stock.. Valid values are `not_required|pending|in_progress|accepted|rejected|conditionally_accepted`',
    `inventory_category` STRING COMMENT 'Classification of the serialized unit by inventory category: raw material, work in progress (WIP), finished good, maintenance repair and operations (MRO), spare part, or semi-finished. Supports inventory segmentation and valuation reporting.. Valid values are `raw_material|wip|finished_good|mro|spare_part|semi_finished`',
    `last_movement_date` DATE COMMENT 'The date of the most recent inventory movement (goods issue, goods receipt, transfer, or stock change) recorded for this serialized unit. Used for slow-moving inventory analysis and dormancy detection.. Valid values are `^d{4}-d{2}-d{2}$`',
    `last_movement_timestamp` TIMESTAMP COMMENT 'The precise date and time of the most recent inventory movement for this serialized unit. Provides sub-day precision for operational tracking, audit trails, and MES integration.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}[+-]d{2}:d{2}$`',
    `manufacturing_date` DATE COMMENT 'The date on which this serialized unit was manufactured or assembled. Used for age-based quality analysis, warranty calculations, shelf-life tracking, and regulatory compliance reporting.. Valid values are `^d{4}-d{2}-d{2}$`',
    `movement_type_code` STRING COMMENT 'The SAP movement type code (e.g., 101 for goods receipt, 261 for goods issue to production order, 311 for stock transfer) associated with the last inventory movement of this serialized unit.. Valid values are `^[0-9]{3}$`',
    `plant_code` STRING COMMENT 'The SAP plant code representing the manufacturing facility or distribution center where this serialized unit currently resides or was last recorded. Aligns with SAP organizational structure.. Valid values are `^[A-Z0-9]{4}$`',
    `quality_inspection_lot` STRING COMMENT 'The SAP QM inspection lot number associated with this serialized unit if it is currently under quality inspection. Links the unit to its quality management workflow and usage decision.. Valid values are `^[0-9]{12}$`',
    `reach_compliant` BOOLEAN COMMENT 'Indicates whether this serialized unit complies with the EU REACH regulation governing the use of chemical substances. Required for product safety, regulatory reporting, and EU market access.. Valid values are `true|false`',
    `rohs_compliant` BOOLEAN COMMENT 'Indicates whether this serialized unit complies with the EU RoHS Directive restricting the use of hazardous substances in electrical and electronic equipment. Required for CE marking and EU market access.. Valid values are `true|false`',
    `serial_number` STRING COMMENT 'The unique alphanumeric serial number assigned to an individual physical unit, enabling unit-level traceability throughout its lifecycle. Corresponds to the SAP MM serial number (SERNR) field.. Valid values are `^[A-Z0-9-]{1,30}$`',
    `status` STRING COMMENT 'Current lifecycle status of the serialized unit indicating its operational disposition. Drives inventory availability, traceability workflows, and reporting. Aligned with SAP MM serial number status management.. Valid values are `in_stock|issued_to_production|shipped|returned|scrapped|in_transit|quality_hold|reserved|decommissioned`',
    `stock_type` STRING COMMENT 'The SAP stock type classification indicating the usability of the serialized unit for production or sales. Unrestricted stock is available for use; quality inspection and blocked stock are restricted pending resolution.. Valid values are `unrestricted|quality_inspection|blocked|restricted`',
    `storage_bin` STRING COMMENT 'The specific bin or slot within the warehouse storage location where this serialized unit is physically placed. Provides the most granular location detail for picking and putaway operations.. Valid values are `^[A-Z0-9-]{1,18}$`',
    `supplier_number` STRING COMMENT 'The vendor or supplier number identifying the external party that supplied this serialized unit. Used for supplier quality management, traceability, and PPAP compliance.. Valid values are `^[A-Z0-9]{1,10}$`',
    `valuation_currency` STRING COMMENT 'The ISO 4217 three-letter currency code in which the valuation price of this serialized unit is expressed. Supports multi-currency inventory valuation in multinational operations.. Valid values are `^[A-Z]{3}$`',
    `valuation_method` STRING COMMENT 'The inventory valuation method applied to this serialized unit for cost accounting purposes. Standard price uses a fixed planned cost; moving average price reflects actual procurement costs.. Valid values are `standard_price|moving_average_price|fifo|fefo`',
    `valuation_price` DECIMAL(18,2) COMMENT 'The unit valuation price of this serialized unit used for inventory accounting. May reflect standard price or moving average price depending on the valuation method configured in SAP MM.. Valid values are `^d+(.d{1,4})?$`',
    `warranty_expiry_date` DATE COMMENT 'The date on which the warranty for this serialized unit expires. Drives after-sales service eligibility checks, warranty claim processing, and customer service SLA management.. Valid values are `^d{4}-d{2}-d{2}$`',
    `warranty_start_date` DATE COMMENT 'The date on which the manufacturer or supplier warranty for this serialized unit becomes effective. Used to determine warranty coverage windows for after-sales service and claims management.. Valid values are `^d{4}-d{2}-d{2}$`',
    CONSTRAINT pk_serialized_unit PRIMARY KEY(`serialized_unit_id`)
) COMMENT 'Master record for individually serialized inventory items tracked at the unit level rather than quantity level. Captures serial number, SKU, batch, current storage location, plant, serial number status (in stock, issued to production, shipped, returned, scrapped), manufacturing date, warranty start date, and last movement date. Supports traceability for high-value components, electrification equipment, and automation systems. Aligned with SAP MM serial number management.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`inventory`.`mro_stock` (
    `mro_stock_id` BIGINT COMMENT 'Unique system-generated surrogate key identifying each MRO stock record in the inventory data product.',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: MRO (Maintenance, Repair, Operations) stock is often held on-site at customer facilities under vendor-managed inventory agreements. Manufacturer tracks ownership and replenishment responsibility by cu',
    `component_id` BIGINT COMMENT 'Foreign key linking to engineering.component. Business justification: MRO stock contains maintenance parts and tooling components. Maintenance teams need engineering specifications, approved manufacturers, and material specs for equipment repair and preventive maintenan',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Maintenance, repair, and operations inventory consumption is charged to maintenance cost centers. Facilities management tracks MRO spending by department for budget control.',
    `inventory_sku_id` BIGINT COMMENT 'Foreign key linking to inventory.sku. Business justification: mro_stock.item_code is a denormalized SKU/item code. MRO items (spare parts, consumables, tools) are managed as SKUs in the inventory domain. Normalizing to sku_id FK links MRO stock records to the SK',
    `it_asset_id` BIGINT COMMENT 'Foreign key linking to technology.it_asset. Business justification: MRO stock includes IT hardware spares (servers, PLCs, HMIs). Maintenance teams need to link MRO inventory items to IT asset records for warranty tracking, configuration management, and replacement pla',
    `reorder_policy_id` BIGINT COMMENT 'Foreign key linking to inventory.reorder_policy. Business justification: MRO stock items have reorder points, minimum/maximum stock levels, and lot sizes that are governed by reorder policies. Adding reorder_policy_id FK links each MRO item to its governing replenishment p',
    `spare_part_id` BIGINT COMMENT 'Foreign key linking to asset.spare_part. Business justification: MRO (Maintenance, Repair, Operations) stock items are spare parts for equipment maintenance. Warehouse teams need to track which spare part each MRO stock item represents for maintenance work order fu',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: mro_stock.storage_location_code is a denormalized location code. Normalizing to storage_location_id FK links each MRO stock record to the granular storage location master.',
    `warehouse_id` BIGINT COMMENT 'Foreign key linking to inventory.warehouse. Business justification: mro_stock.warehouse_number is a denormalized warehouse code. Normalizing to warehouse_id FK links each MRO stock record to the warehouse master.',
    `abc_classification` STRING COMMENT 'ABC inventory classification of the MRO item based on consumption value and criticality. A = high value/high criticality, B = medium, C = low value/low criticality. Drives cycle count frequency and stocking policy.. Valid values are `A|B|C`',
    `batch_management_flag` BOOLEAN COMMENT 'Indicates whether the MRO item is managed at batch level for traceability purposes (e.g., lubricants with lot numbers, calibrated tools with certification batches).. Valid values are `true|false`',
    `company_code` STRING COMMENT 'SAP FI company code representing the legal entity responsible for the financial valuation of this MRO stock. Supports multi-entity financial reporting and intercompany transactions.. Valid values are `^[A-Z0-9]{4}$`',
    `cost_center` STRING COMMENT 'SAP CO cost center to which MRO consumption costs are charged when items are issued for maintenance work orders. Enables maintenance cost allocation and OPEX tracking.. Valid values are `^[A-Z0-9]{6,10}$`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the plant or facility where this MRO stock record is maintained. Supports multi-country regulatory compliance and reporting.. Valid values are `^[A-Z]{3}$`',
    `criticality_rating` STRING COMMENT 'Criticality classification of the MRO item based on its impact on production continuity and equipment availability. Critical items cause production stoppage if unavailable; non-critical items have acceptable workarounds or lead times.. Valid values are `critical|non_critical`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the unit cost and inventory valuation of the MRO item (e.g., USD, EUR, GBP).. Valid values are `^[A-Z]{3}$`',
    `current_quantity` DECIMAL(18,2) COMMENT 'Current physical on-hand quantity of the MRO item in the storeroom or warehouse location. Represents unrestricted usable stock available for maintenance work orders.. Valid values are `^d+(.d{1,4})?$`',
    `equipment_applicability` STRING COMMENT 'Description or list of equipment types, asset classes, or functional locations for which this MRO item is applicable. Supports maintenance planning and spare parts management in Maximo EAM.',
    `functional_location_code` STRING COMMENT 'SAP PM or Maximo EAM functional location code identifying the plant area or system where this MRO item is primarily used (e.g., production line, utility system, HVAC).',
    `hazardous_material_flag` BOOLEAN COMMENT 'Indicates whether the MRO item is classified as a hazardous material requiring special handling, storage, and disposal procedures in compliance with OSHA, EPA, and REACH/RoHS regulations.. Valid values are `true|false`',
    `hazmat_class` STRING COMMENT 'Hazardous material classification for the MRO item per UN/DOT/GHS standards. Drives storage segregation, handling procedures, and regulatory reporting requirements.. Valid values are `flammable|corrosive|toxic|oxidizer|compressed_gas|explosive|radioactive|environmental_hazard|not_applicable`',
    `item_category` STRING COMMENT 'Business classification of the MRO item type. Drives procurement strategy, stocking policy, and maintenance planning. Aligned with Maximo EAM item classification taxonomy.. Valid values are `spare_part|consumable|tool|indirect_material|safety_item|lubricant|electrical|instrumentation|fastener|gasket_seal`',
    `item_description_long` STRING COMMENT 'Extended technical description of the MRO item including specifications, dimensions, and application details to support procurement and maintenance technicians.',
    `last_goods_receipt_date` DATE COMMENT 'Date of the most recent goods receipt posting for this MRO item. Used to assess replenishment recency and supplier delivery performance.. Valid values are `^d{4}-d{2}-d{2}$`',
    `last_usage_date` DATE COMMENT 'Date on which the MRO item was last issued from stock for a maintenance work order or operational use. Used to identify slow-moving or obsolete MRO inventory.. Valid values are `^d{4}-d{2}-d{2}$`',
    `lot_size_qty` DECIMAL(18,2) COMMENT 'Standard replenishment order quantity for the MRO item. Represents the fixed or economic order quantity used when triggering a purchase requisition or purchase order.. Valid values are `^d+(.d{1,4})?$`',
    `manufacturer_name` STRING COMMENT 'Name of the original equipment manufacturer (OEM) for the MRO item. Used for warranty validation, technical support, and approved vendor list management.',
    `manufacturer_part_number` STRING COMMENT 'Original equipment manufacturer (OEM) part number for the MRO item. Critical for identifying exact replacement parts and cross-referencing across suppliers.',
    `material_group` STRING COMMENT 'SAP MM material group code used to classify MRO items into procurement and reporting categories (e.g., bearings, lubricants, electrical components, tools).. Valid values are `^[A-Z0-9]{2,9}$`',
    `maximo_item_number` STRING COMMENT 'Item number as maintained in the Maximo EAM spare parts catalog. Enables cross-system reconciliation between SAP MM material master and Maximo EAM storeroom inventory.. Valid values are `^[A-Z0-9-]{1,30}$`',
    `maximum_stock_level` DECIMAL(18,2) COMMENT 'Maximum quantity of the MRO item to be held in stock. Prevents over-stocking and excess capital tie-up. Used in min-max replenishment strategy.. Valid values are `^d+(.d{1,4})?$`',
    `minimum_stock_level` DECIMAL(18,2) COMMENT 'Minimum quantity of the MRO item that must be maintained in stock at all times to prevent stockout during replenishment lead time. Equivalent to safety stock in SAP MRP.. Valid values are `^d+(.d{1,4})?$`',
    `planned_delivery_days` STRING COMMENT 'Expected number of calendar days from purchase order placement to goods receipt for this MRO item. Used in MRP calculations to determine reorder timing and safety stock levels.. Valid values are `^[0-9]{1,4}$`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility or distribution center where this MRO stock record is maintained. Enables multi-plant inventory visibility.. Valid values are `^[A-Z0-9]{4}$`',
    `preferred_supplier_name` STRING COMMENT 'Business name of the preferred supplier for this MRO item. Provides human-readable supplier identification for reporting and operational use.',
    `preferred_supplier_number` STRING COMMENT 'SAP vendor account number or Ariba supplier ID of the preferred supplier for this MRO item. Used to streamline procurement and maintain supplier performance tracking.. Valid values are `^[A-Z0-9]{6,12}$`',
    `reorder_point` DECIMAL(18,2) COMMENT 'Stock level at which a replenishment order is triggered for the MRO item. When current quantity falls to or below this level, procurement action is initiated.. Valid values are `^d+(.d{1,4})?$`',
    `serial_number_management` STRING COMMENT 'Defines the serial number tracking requirement for the MRO item. Critical spare parts (e.g., motors, pumps, PLCs) may require serial number tracking for warranty and maintenance history.. Valid values are `no_serial_number|serial_number_at_goods_receipt|serial_number_at_goods_issue|serial_number_required`',
    `shelf_life_days` STRING COMMENT 'Maximum number of days the MRO item can be stored before it expires or degrades below usable quality (e.g., lubricants, adhesives, O-rings, batteries). Zero or null indicates no shelf life restriction.. Valid values are `^[0-9]{1,5}$`',
    `slow_moving_indicator` BOOLEAN COMMENT 'Flag indicating that the MRO item has not been consumed within a defined threshold period (typically 12-24 months). Triggers review for potential write-off, return to supplier, or reclassification.. Valid values are `true|false`',
    `status` STRING COMMENT 'Current lifecycle status of the MRO stock record. Active = in regular use; Inactive = temporarily not in use; Obsolete = no longer required; Blocked = procurement or usage restricted; Phase-out = being discontinued.. Valid values are `active|inactive|obsolete|blocked|under_review|phase_out`',
    `stocking_strategy` STRING COMMENT 'Defines how the MRO item is sourced and held. Stocked = maintained in warehouse inventory; Non-stocked = procured on demand; Consignment = supplier-owned stock held on-site.. Valid values are `stocked|non_stocked|consignment`',
    `supplier_part_number` STRING COMMENT 'The suppliers own part number or catalog number for this MRO item. Used for purchase order creation and supplier communication.',
    `unit_cost` DECIMAL(18,2) COMMENT 'Standard or moving average cost per unit of the MRO item used for inventory valuation and financial reporting. Aligned with SAP MM valuation price.. Valid values are `^d+(.d{1,4})?$`',
    `unit_of_measure` STRING COMMENT 'Base unit of measure for the MRO item quantity (e.g., EA = Each, PC = Piece, KG = Kilogram, L = Liter). Aligns with SAP MM base unit of measure.. Valid values are `EA|PC|KG|L|M|M2|M3|SET|BOX|ROLL|PAIR|PKG`',
    `valuation_method` STRING COMMENT 'Method used to value the MRO item in inventory. Standard Price uses a fixed planned cost; Moving Average Price recalculates cost with each goods receipt.. Valid values are `standard_price|moving_average_price`',
    CONSTRAINT pk_mro_stock PRIMARY KEY(`mro_stock_id`)
) COMMENT 'Manages Maintenance, Repair, and Operations (MRO) inventory including spare parts, consumables, tools, and indirect materials used for equipment maintenance and plant operations. Captures MRO item code, description, equipment applicability, criticality rating (critical, non-critical), stocking strategy (stocked, non-stocked, consignment), current quantity, minimum stock level, preferred supplier, lead time, and last usage date. Aligned with SAP MM MRO material type and Maximo EAM spare parts catalog.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`inventory`.`physical_inventory` (
    `physical_inventory_id` BIGINT COMMENT 'Unique surrogate identifier for each physical inventory count event record in the lakehouse silver layer.',
    `employee_id` BIGINT COMMENT 'Employee identifier of the inventory controller or warehouse manager responsible for organizing and overseeing the physical inventory count event.',
    `warehouse_id` BIGINT COMMENT 'Foreign key linking to inventory.warehouse. Business justification: physical_inventory.warehouse_number is a denormalized warehouse code. A full physical inventory count is scoped to a specific warehouse facility. Normalizing to warehouse_id FK links the count event t',
    `actual_count_date` DATE COMMENT 'The actual calendar date on which the physical inventory count was performed. May differ from planned_count_date due to operational delays or rescheduling.',
    `adjustment_document_number` STRING COMMENT 'SAP material document number generated when inventory variance adjustments are posted to the general ledger following the physical inventory count. Provides traceability from count to financial posting.',
    `adjustment_posted_flag` BOOLEAN COMMENT 'Indicates whether the inventory variance adjustment document has been financially posted to the general ledger in SAP FI/MM following completion and approval of the physical inventory count.. Valid values are `true|false`',
    `approval_required_flag` BOOLEAN COMMENT 'Indicates whether the physical inventory variance adjustments require formal management approval before financial posting. Driven by variance value thresholds and internal controls policy.. Valid values are `true|false`',
    `approval_status` STRING COMMENT 'Current approval workflow status for the physical inventory variance adjustments: not_required (below threshold), pending (awaiting approver action), approved (authorized for posting), rejected (returned for investigation).. Valid values are `not_required|pending|approved|rejected`',
    `approval_timestamp` TIMESTAMP COMMENT 'Date and time when the physical inventory variance adjustments were formally approved for financial posting. Provides audit trail for internal controls compliance.',
    `approved_by` STRING COMMENT 'Name or employee identifier of the manager or inventory controller who approved the physical inventory variance adjustments for financial posting.',
    `company_code` STRING COMMENT 'SAP company code representing the legal entity responsible for the inventory valuation and financial posting of variances identified during the physical inventory.',
    `count_end_timestamp` TIMESTAMP COMMENT 'Precise date and time when all physical inventory counting activities were completed. Used to calculate count duration and for audit trail purposes.',
    `count_method` STRING COMMENT 'The method used to perform the physical inventory count: manual (paper-based or visual count), scanner (barcode/QR scanner via WMS), rfid (Radio Frequency Identification automated reading), or automated (conveyor/sensor-based counting).. Valid values are `manual|scanner|rfid|automated`',
    `count_start_timestamp` TIMESTAMP COMMENT 'Precise date and time when the physical inventory counting activity commenced on the shop floor or warehouse. Used for duration tracking and audit trail.',
    `count_type` STRING COMMENT 'Classification of the physical inventory count scope: full_count (wall-to-wall count of all stock), partial_count (selected storage locations or material groups), or spot_check (targeted verification of specific SKUs or bins).. Valid values are `full_count|partial_count|spot_check`',
    `counted_sku_count` STRING COMMENT 'Number of distinct SKUs that have been physically counted as of the current status. Enables tracking of count completion progress against total_sku_count.',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the plant or warehouse location where the physical inventory is conducted. Supports multi-country regulatory compliance and regional reporting.. Valid values are `^[A-Z]{3}$`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the currency in which inventory variance values and financial postings are expressed (e.g., USD, EUR, GBP).. Valid values are `^[A-Z]{3}$`',
    `document_number` STRING COMMENT 'The SAP MM physical inventory document number that uniquely identifies the physical inventory event in the source ERP system. Aligns with SAP transaction MI01/MI04.',
    `fiscal_period` STRING COMMENT 'The fiscal accounting period (month) within the fiscal year in which the physical inventory is conducted and variance postings are made.. Valid values are `^(0[1-9]|1[0-2])$`',
    `fiscal_year` STRING COMMENT 'The fiscal year in which the physical inventory count event is conducted and financially posted. Used for period-end inventory valuation and financial reporting.. Valid values are `^[0-9]{4}$`',
    `goods_movements_blocked` BOOLEAN COMMENT 'Indicates whether all goods movements (goods receipts, goods issues, transfers) are blocked in the system for the scope of this physical inventory to prevent stock changes during counting.. Valid values are `true|false`',
    `infor_wms_count_code` STRING COMMENT 'Reference identifier from the Infor WMS system for the corresponding physical inventory count task. Enables cross-system traceability between SAP MM physical inventory document and WMS count execution.',
    `inventory_category` STRING COMMENT 'The category of inventory stock included in the physical inventory scope: raw materials, work-in-progress (WIP), finished goods, maintenance-repair-operations (MRO), semi-finished goods, spare parts, or all categories.. Valid values are `raw_material|wip|finished_goods|mro|semi_finished|spare_parts|all`',
    `notes` STRING COMMENT 'Free-text field for capturing operational notes, exceptions, special circumstances, or instructions related to the physical inventory count event (e.g., system outage during count, partial area exclusions).',
    `planned_count_date` DATE COMMENT 'The scheduled calendar date on which the physical inventory count is planned to be executed. Used for resource planning and production freeze scheduling.',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing plant or distribution center where the physical inventory count is being conducted.',
    `posting_date` DATE COMMENT 'The accounting posting date on which inventory variance adjustments are financially posted to the general ledger. Determines the fiscal period impact of inventory differences.',
    `production_freeze_required` BOOLEAN COMMENT 'Indicates whether production activities in the plant or warehouse must be frozen (halted) during the physical inventory count to ensure accurate stock snapshot. Critical for wall-to-wall full counts.. Valid values are `true|false`',
    `recount_sku_count` STRING COMMENT 'Number of SKUs flagged for recount due to variances exceeding the tolerance threshold. Tracks the scope of the recount phase within the physical inventory event.',
    `responsible_employee_name` STRING COMMENT 'Full name of the inventory controller or warehouse manager responsible for the physical inventory count event. Retained for reporting and audit trail purposes.',
    `status` STRING COMMENT 'Current lifecycle status of the physical inventory count event: created (document created, counting not started), counting (active count in progress), recounting (recount triggered by variance), completed (all counts recorded), posted (variance adjustments financially posted), cancelled (event cancelled before completion).. Valid values are `created|counting|recounting|completed|posted|cancelled`',
    `total_sku_count` STRING COMMENT 'Total number of distinct SKUs (Stock Keeping Units) included in the scope of this physical inventory event. Represents the universe of materials to be counted.',
    `total_variance_value` DECIMAL(18,2) COMMENT 'Total financial value of all inventory variances identified during the physical inventory count, expressed in the document currency. Represents the aggregate financial impact of stock differences requiring GL adjustment.',
    `variance_sku_count` STRING COMMENT 'Number of SKUs where the physically counted quantity differs from the book quantity beyond the defined tolerance threshold. Drives recount and adjustment decisions.',
    `variance_threshold_pct` DECIMAL(18,2) COMMENT 'The percentage tolerance threshold above which a counted quantity variance triggers a recount or mandatory adjustment. Defined per inventory policy and used to classify items as within or exceeding tolerance.',
    CONSTRAINT pk_physical_inventory PRIMARY KEY(`physical_inventory_id`)
) COMMENT 'Manages full physical inventory count events (annual or periodic wall-to-wall counts) at the warehouse or plant level. Captures physical inventory document number, warehouse/plant scope, count type (full count, partial count, spot check), planned count date, actual count date, count status (created, counting, completed, posted), total SKUs in scope, counted SKUs, variance count, total variance value, and approval status. Distinct from cycle_count which manages continuous rolling counts. Aligned with SAP MM physical inventory document.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`inventory`.`consignment_stock` (
    `consignment_stock_id` BIGINT COMMENT 'Unique surrogate identifier for each consignment stock record in the silver layer lakehouse. Serves as the primary key for all downstream joins and lineage tracking.',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Consignment stock is owned by supplier/customer and stored at manufacturers location until consumed. Manufacturing tracks which account owns the consignment inventory for billing and liability purpos',
    `channel_partner_id` BIGINT COMMENT 'Foreign key linking to sales.channel_partner. Business justification: Consignment stock is held at channel partner locations until sold. Manufacturing tracks which partner holds which inventory for billing triggers, stock ownership transfer, and replenishment decisions.',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Consignment inventory requires separate GL account tracking as its supplier-owned until consumed. Finance uses this for off-balance-sheet inventory reporting and liability recognition.',
    `inventory_sku_id` BIGINT COMMENT 'Foreign key linking to inventory.sku. Business justification: consignment_stock.sku_number is a denormalized SKU code. Consignment stock is vendor-owned inventory for specific SKUs. Normalizing to sku_id FK links consignment records to the SKU master.',
    `lot_batch_id` BIGINT COMMENT 'Foreign key linking to inventory.lot_batch. Business justification: consignment_stock.batch_number is a denormalized batch reference. Normalizing to lot_batch_id FK enables batch-level traceability for consignment inventory.',
    `plan_id` BIGINT COMMENT 'Foreign key linking to billing.billing_plan. Business justification: Consignment inventory is billed only upon consumption or sale. Billing plans define when consignment stock transitions from supplier-owned to customer-owned and triggers invoicing.',
    `procurement_supplier_id` BIGINT COMMENT 'Foreign key linking to procurement.supplier. Business justification: Consignment stock is owned by specific suppliers until consumption. Tracks supplier-owned inventory for settlement and liability management.',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: consignment_stock.storage_location_code is a denormalized location code. Normalizing to storage_location_id FK links each consignment stock record to the granular storage location.',
    `warehouse_id` BIGINT COMMENT 'Foreign key linking to inventory.warehouse. Business justification: consignment_stock.warehouse_number is a denormalized warehouse code. Normalizing to warehouse_id FK links each consignment stock record to the warehouse master.',
    `abc_classification` STRING COMMENT 'ABC inventory classification of the consignment material based on consumption value (A = high value/high priority, B = medium, C = low value/low priority). Used to prioritize settlement processing and consignment stock monitoring.. Valid values are `A|B|C`',
    `company_code` STRING COMMENT 'SAP company code representing the legal entity responsible for the consignment stock. Used for financial liability reporting, intercompany settlement, and compliance with local GAAP/IFRS requirements.',
    `consignment_agreement_number` STRING COMMENT 'Reference number of the consignment agreement or scheduling agreement in SAP MM that governs the terms under which the vendor supplies stock on consignment. Links to the purchasing info record or outline agreement.',
    `consignment_quantity` DECIMAL(18,2) COMMENT 'Current quantity of vendor-owned consignment stock on hand at the company premises. Represents the total received quantity less any consumed or returned quantities. Expressed in the base unit of measure.',
    `consignment_record_number` STRING COMMENT 'Business-facing document number assigned by SAP MM to uniquely identify the consignment stock record. Used for cross-referencing with SAP material documents and vendor settlement transactions.',
    `consumed_quantity` DECIMAL(18,2) COMMENT 'Cumulative quantity of consignment stock that has been consumed or transferred to own stock since the consignment agreement began. Triggers financial liability and is the basis for vendor settlement invoicing.',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the plant or facility where the consignment stock is held. Supports multi-country regulatory compliance, customs reporting, and cross-border consignment tracking.. Valid values are `^[A-Z]{3}$`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code in which the consignment unit price and settlement values are denominated (e.g., USD, EUR, GBP). Supports multi-currency financial reporting for multinational operations.. Valid values are `^[A-Z]{3}$`',
    `expiry_date` DATE COMMENT 'Date on which the consignment agreement expires. After this date, the vendor may reclaim unsettled stock or the agreement must be renewed. Used for contract lifecycle management and proactive settlement processing.. Valid values are `^d{4}-d{2}-d{2}$`',
    `goods_receipt_number` STRING COMMENT 'SAP material document number generated when the consignment stock was received at the plant. Provides the audit trail from vendor delivery to consignment stock posting. Aligns with GRN terminology in procurement.',
    `hazardous_material_flag` BOOLEAN COMMENT 'Indicates whether the consignment stock contains hazardous materials subject to special storage, handling, and regulatory reporting requirements. Relevant for OSHA, EPA, REACH, and RoHS compliance.. Valid values are `true|false`',
    `last_movement_date` DATE COMMENT 'Date of the most recent inventory movement (consumption, return, or transfer) against this consignment stock record. Used for slow-moving stock analysis, aging reports, and vendor settlement prioritization.. Valid values are `^d{4}-d{2}-d{2}$`',
    `last_settlement_date` DATE COMMENT 'Date on which the most recent consignment settlement run was executed for this record in SAP MM (transaction MRKO). Used to track settlement frequency and identify overdue settlement obligations.. Valid values are `^d{4}-d{2}-d{2}$`',
    `material_group` STRING COMMENT 'SAP material group code classifying the consignment material into a commodity category (e.g., raw materials, electronic components, MRO supplies). Used for spend analysis, reporting, and procurement category management.',
    `maximum_consignment_quantity` DECIMAL(18,2) COMMENT 'Maximum quantity of consignment stock the vendor is authorized to hold at the company premises as defined in the consignment agreement. Used to monitor compliance with agreement terms and trigger replenishment or return actions.',
    `minimum_consignment_quantity` DECIMAL(18,2) COMMENT 'Minimum quantity of consignment stock that must be maintained at the company premises as per the consignment agreement. Triggers replenishment requests to the vendor when the on-hand quantity falls below this threshold.',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing or distribution facility where the consignment stock is physically held. Determines the organizational unit for MRP, valuation, and settlement.',
    `purchase_info_record_number` STRING COMMENT 'SAP purchasing info record number that defines the vendor-material relationship for consignment, including consignment price and conditions. Used during settlement to determine financial liability.',
    `purchasing_organization` STRING COMMENT 'SAP purchasing organization responsible for negotiating and managing the consignment agreement with the vendor. Determines the procurement terms and conditions applicable to the consignment arrangement.',
    `receipt_date` DATE COMMENT 'Date on which the consignment stock was physically received at the company premises and posted in SAP MM. Marks the start of the consignment holding period and is used for aging analysis and settlement scheduling.. Valid values are `^d{4}-d{2}-d{2}$`',
    `returned_quantity` DECIMAL(18,2) COMMENT 'Quantity of consignment stock returned to the vendor without consumption. Reduces the consignment balance and is posted via SAP movement type 122 (return to vendor from consignment).',
    `settlement_document_number` STRING COMMENT 'SAP financial document number generated by the consignment settlement run (MRKO) for the most recent settlement. Provides the audit trail linking consignment consumption to accounts payable postings.',
    `settlement_status` STRING COMMENT 'Current settlement processing status of the consignment stock record in SAP MM. Indicates whether the consumed quantities have been financially settled with the vendor via the consignment settlement run (MRKO).. Valid values are `open|partially_settled|fully_settled|cancelled|pending_approval`',
    `slow_moving_indicator` BOOLEAN COMMENT 'Flag indicating that the consignment stock has not been consumed within the defined slow-moving threshold period. Triggers review actions such as vendor return, renegotiation of consignment terms, or write-down assessment.. Valid values are `true|false`',
    `stock_status` STRING COMMENT 'Current operational status of the consignment stock record. Indicates whether the stock is available for consumption, blocked for quality inspection, in transit, or has been returned or cancelled.. Valid values are `active|blocked|quality_inspection|in_transit|returned|expired|cancelled`',
    `stock_type` STRING COMMENT 'SAP stock type classification indicating the usability of the consignment stock (e.g., unrestricted = available for consumption, quality_inspection = under QM hold, blocked = not available). Determines whether the stock can be consumed and settled.. Valid values are `unrestricted|quality_inspection|blocked|restricted`',
    `storage_bin` STRING COMMENT 'Specific bin or slot within the warehouse where the consignment stock is located. Enables precise physical location tracking for picking, replenishment, and cycle counting.',
    `total_consignment_value` DECIMAL(18,2) COMMENT 'Total financial value of the current consignment stock on hand, calculated as consignment quantity multiplied by unit price. Represents the maximum potential financial liability to the vendor and is used for balance sheet disclosure and financial reporting.',
    `unit_of_measure` STRING COMMENT 'Base unit of measure in which the consignment quantity is expressed (e.g., EA = Each, KG = Kilogram, L = Liter). Aligns with the SAP material master base UoM for consistent valuation and settlement.. Valid values are `EA|KG|L|M|M2|M3|PC|ST|TO|G|MM|CM|FT|LB|GAL`',
    `unit_price` DECIMAL(18,2) COMMENT 'Agreed price per unit of measure for the consignment material as defined in the SAP purchasing info record or consignment agreement. Used to calculate financial liability upon consumption and for settlement invoice verification.',
    `valuation_method` STRING COMMENT 'Method used to value the consignment stock for financial liability reporting. Typically based on the purchasing info record price, but may use standard or moving average price depending on company configuration.. Valid values are `standard_price|moving_average_price|info_record_price`',
    `vendor_code` STRING COMMENT 'SAP vendor account number identifying the vendor who owns the consignment stock. The vendor retains financial ownership until the material is consumed or transferred.',
    `vendor_name` STRING COMMENT 'Legal name of the vendor supplying the consignment stock. Used for settlement reporting, financial liability disclosure, and vendor performance analysis.',
    CONSTRAINT pk_consignment_stock PRIMARY KEY(`consignment_stock_id`)
) COMMENT 'Tracks vendor-owned consignment inventory held at the companys premises but not yet financially owned until consumed or transferred. Captures consignment stock record ID, vendor, SKU, batch, consignment location, consignment quantity, unit price, consignment agreement reference, receipt date, consumption quantity to date, and settlement status. Supports consignment settlement processing in SAP MM and enables accurate financial liability reporting.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`inventory`.`handling_unit` (
    `handling_unit_id` BIGINT COMMENT 'Unique surrogate identifier for the handling unit record in the lakehouse silver layer. Serves as the primary key for all downstream joins and references.',
    `equipment_id` BIGINT COMMENT 'Foreign key linking to asset.equipment. Business justification: Handling units (pallets, containers) are moved by specific material handling equipment like forklifts. Warehouse systems track which equipment is assigned to or last handled each unit for operational ',
    `lot_batch_id` BIGINT COMMENT 'Foreign key linking to inventory.lot_batch. Business justification: handling_unit.batch_number is a denormalized batch reference. Normalizing to lot_batch_id FK enables batch-level traceability for physical handling units.',
    `serialized_unit_id` BIGINT COMMENT 'Foreign key linking to inventory.serialized_unit. Business justification: handling_unit.serial_number is a denormalized serial number reference. Normalizing to serialized_unit_id FK links handling units containing serialized items to the serialized unit master.',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: handling_unit.storage_location_code is a denormalized location code. Normalizing to storage_location_id FK links each handling unit to its current granular storage location.',
    `warehouse_id` BIGINT COMMENT 'Foreign key linking to inventory.warehouse. Business justification: handling_unit.warehouse_number is a denormalized warehouse code. Normalizing to warehouse_id FK links each handling unit (pallet/carton) to the warehouse master.',
    `company_code` STRING COMMENT 'SAP company code representing the legal entity responsible for the inventory contained in this handling unit. Required for intercompany stock transfers, financial valuation, and IFRS/GAAP inventory reporting.. Valid values are `^[A-Z0-9]{4}$`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the facility where the handling unit is currently located. Supports multi-country operations, customs compliance, and cross-border inventory reporting.. Valid values are `^[A-Z]{3}$`',
    `creation_timestamp` TIMESTAMP COMMENT 'Date and time when the handling unit record was first created in the WMS or ERP system. Used for aging analysis, audit trails, and compliance with inventory record-keeping requirements.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `goods_receipt_number` STRING COMMENT 'Reference to the Goods Receipt Note (GRN) document that created or received this handling unit into inventory. Links the HU to the inbound delivery and purchase order for procurement traceability.. Valid values are `^[A-Z0-9-]{1,20}$`',
    `gross_weight_kg` DECIMAL(18,2) COMMENT 'Total gross weight of the handling unit including packaging material, contents, and any dunnage, expressed in kilograms. Used for transport planning, load optimization, and compliance with carrier weight limits.. Valid values are `^[0-9]{1,9}(.[0-9]{1,3})?$`',
    `hazmat_class` STRING COMMENT 'UN/DOT hazardous materials classification code for the contents of the handling unit. Mandatory for storage zone assignment, transport documentation, and regulatory compliance with dangerous goods regulations.. Valid values are `^(1|2|3|4|5|6|7|8|9|N/A)(.([1-9])?)?$`',
    `height_mm` DECIMAL(18,2) COMMENT 'Outer height dimension of the handling unit in millimeters. Critical for stacking height compliance, racking clearance validation, and automated storage and retrieval system (AS/RS) compatibility.. Valid values are `^[0-9]{1,7}(.[0-9]{1,2})?$`',
    `hu_number` STRING COMMENT 'External business identifier for the handling unit, typically the Serial Shipping Container Code (SSCC-18) barcode or WMS license plate number. Used for scanning, tracking, and cross-system identification across SAP WM and Infor WMS.. Valid values are `^[0-9]{18}$|^[A-Z0-9-]{6,30}$`',
    `inbound_delivery_number` STRING COMMENT 'SAP inbound delivery document number associated with the receipt of this handling unit. Provides traceability back to the supplier shipment, advance shipping notice (ASN), and purchase order.. Valid values are `^[0-9]{10}$`',
    `infor_wms_lp_code` STRING COMMENT 'Native license plate identifier assigned by Infor WMS to this handling unit. Used for direct system integration, WMS API calls, and reconciliation between the lakehouse silver layer and the Infor WMS operational system.. Valid values are `^[A-Z0-9-]{1,30}$`',
    `inventory_category` STRING COMMENT 'Business classification of the inventory contents within the handling unit. Distinguishes raw materials, work-in-progress (WIP), finished goods, and MRO (Maintenance, Repair, and Operations) stock for financial reporting and warehouse zoning.. Valid values are `raw_material|wip|finished_goods|mro|packaging|semi_finished|spare_part|returnable_packaging`',
    `is_mixed` BOOLEAN COMMENT 'Indicates whether the handling unit contains more than one distinct SKU. Mixed handling units require special putaway strategies and may be restricted in certain storage zones or automated systems.. Valid values are `true|false`',
    `label_printed_flag` BOOLEAN COMMENT 'Indicates whether the GS1 logistics label or license plate label has been printed and applied to the handling unit. Prevents duplicate label printing and ensures scan-readiness before putaway or shipment.. Valid values are `true|false`',
    `last_movement_timestamp` TIMESTAMP COMMENT 'Date and time of the most recent physical movement or status change of the handling unit within the warehouse. Used for dwell time analysis, slow-moving inventory identification, and warehouse efficiency reporting.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `length_mm` DECIMAL(18,2) COMMENT 'Outer length dimension of the handling unit in millimeters. Used for storage slot assignment, transport load planning, and automated conveyor system compatibility checks.. Valid values are `^[0-9]{1,7}(.[0-9]{1,2})?$`',
    `max_stack_count` STRING COMMENT 'Maximum number of identical handling units that may be stacked on top of each other. Used by WMS putaway strategies and warehouse safety rules to prevent overloading and structural collapse.. Valid values are `^[1-9][0-9]*$`',
    `max_stacking_height_mm` DECIMAL(18,2) COMMENT 'Maximum allowable stacking height for this handling unit type in millimeters, including the unit itself. Enforced by WMS putaway rules to prevent structural damage and ensure worker safety compliance.. Valid values are `^[0-9]{1,7}(.[0-9]{1,2})?$`',
    `net_weight_kg` DECIMAL(18,2) COMMENT 'Net weight of the contents within the handling unit excluding packaging material, expressed in kilograms. Used for inventory valuation, customs declarations, and material planning.. Valid values are `^[0-9]{1,9}(.[0-9]{1,3})?$`',
    `outbound_delivery_number` STRING COMMENT 'SAP outbound delivery document number to which this handling unit has been assigned for shipment. Links the HU to the sales order, shipping point, and carrier booking for order fulfillment traceability.. Valid values are `^[0-9]{10}$`',
    `packaging_material_type` STRING COMMENT 'Classification of the physical packaging unit type used to group and transport inventory. Determines stacking rules, weight limits, and handling equipment requirements in the warehouse.. Valid values are `pallet|carton|container|crate|drum|tote|bag|roll|bundle|spool|intermediate_bulk_container|other`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing or distribution facility where the handling unit is currently located or was created. Aligns with SAP S/4HANA organizational structure.. Valid values are `^[A-Z0-9]{4}$`',
    `sap_hu_number` STRING COMMENT 'Native handling unit number assigned by SAP WM/EWM to this physical packaging unit. Used for reconciliation between the lakehouse silver layer and SAP S/4HANA WM/EWM operational records.. Valid values are `^[A-Z0-9]{10,20}$`',
    `shipped_timestamp` TIMESTAMP COMMENT 'Date and time when the handling unit was confirmed as shipped and goods issue was posted. Triggers inventory deduction, billing, and outbound logistics milestone updates in SAP SD and Infor WMS.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `sku_count` STRING COMMENT 'Number of distinct SKU (Stock Keeping Unit) line items contained within the handling unit. A value greater than 1 indicates a mixed handling unit, which may require special putaway or picking rules.. Valid values are `^[0-9]+$`',
    `sscc` STRING COMMENT 'GS1-standard 18-digit Serial Shipping Container Code assigned to the handling unit for global supply chain identification and EDI interchange. Enables traceability across shipping partners and logistics providers.. Valid values are `^[0-9]{18}$`',
    `status` STRING COMMENT 'Current operational lifecycle status of the handling unit. Drives warehouse execution workflows including putaway, picking, shipping, and inventory visibility in WMS and ERP.. Valid values are `in_stock|in_transit|shipped|empty|blocked|in_picking|in_putaway|staged|disposed|returned`',
    `stock_type` STRING COMMENT 'SAP inventory stock type classification for the contents of the handling unit. Determines whether the stock is available for use, under quality inspection, blocked, or in a special stock category.. Valid values are `unrestricted|quality_inspection|blocked|restricted|consignment|returns`',
    `tare_weight_kg` DECIMAL(18,2) COMMENT 'Weight of the empty packaging material (pallet, carton, container) without contents, expressed in kilograms. Calculated as gross weight minus net weight; used for carrier billing reconciliation and packaging cost tracking.. Valid values are `^[0-9]{1,7}(.[0-9]{1,3})?$`',
    `temperature_zone` STRING COMMENT 'Required temperature storage zone for the handling unit contents. Drives putaway routing to climate-controlled storage areas and ensures product integrity for temperature-sensitive materials.. Valid values are `ambient|chilled|frozen|controlled_room_temp|heated|ultra_low`',
    `total_quantity` DECIMAL(18,2) COMMENT 'Total quantity of all items contained within the handling unit expressed in the base unit of measure. For single-SKU HUs, equals the quantity of that SKU; for mixed HUs, represents the aggregate item count.. Valid values are `^[0-9]{1,12}(.[0-9]{1,3})?$`',
    `transfer_order_number` STRING COMMENT 'WMS transfer order or warehouse task number associated with the current or most recent movement of this handling unit within the warehouse. Used to track putaway, replenishment, and internal transfer operations.. Valid values are `^[A-Z0-9-]{1,20}$`',
    `unit_of_measure` STRING COMMENT 'Base unit of measure for the total quantity of contents within the handling unit (e.g., EA, KG, L, M, PAL). Aligns with SAP base UoM configuration and GS1 unit of measure codes.. Valid values are `^[A-Z]{2,6}$`',
    `volume_m3` DECIMAL(18,2) COMMENT 'Total outer volume of the handling unit in cubic meters, derived from length, width, and height dimensions. Used for storage capacity planning, freight volume billing, and warehouse space utilization reporting.. Valid values are `^[0-9]{1,6}(.[0-9]{1,4})?$`',
    `width_mm` DECIMAL(18,2) COMMENT 'Outer width dimension of the handling unit in millimeters. Used for storage slot assignment, transport load planning, and automated conveyor system compatibility checks.. Valid values are `^[0-9]{1,7}(.[0-9]{1,2})?$`',
    CONSTRAINT pk_handling_unit PRIMARY KEY(`handling_unit_id`)
) COMMENT 'Represents physical packaging units (pallets, cartons, containers, crates) used to group and track inventory during storage and movement. Captures handling unit number (SSCC/license plate), packaging material type, gross weight, net weight, dimensions, stacking height, contained SKUs and quantities, current storage location, and handling unit status (in stock, in transit, shipped, empty). Supports license plate management in Infor WMS and SAP WM HU management.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`inventory`.`snapshot` (
    `snapshot_id` BIGINT COMMENT 'Unique surrogate identifier for each inventory snapshot record in the Databricks Silver Layer. Serves as the primary key for the inventory_snapshot data product.',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: Inventory snapshots are captured at fiscal period boundaries for financial reporting and audit requirements. Period-end close process requires point-in-time inventory positions.',
    `abc_classification` STRING COMMENT 'ABC inventory classification of the SKU at the time of snapshot, based on consumption value or turnover frequency. A-items are high-value/high-velocity; C-items are low-value/low-velocity. Used for cycle counting prioritization and safety stock optimization.. Valid values are `A|B|C|D`',
    `batch_number` STRING COMMENT 'Lot or batch identifier for batch-managed materials at the time of snapshot. Enables traceability of inventory by production lot, supplier batch, or expiry date for quality and regulatory compliance.',
    `below_safety_stock_flag` BOOLEAN COMMENT 'Indicates whether the unrestricted quantity at the time of snapshot is below the defined safety stock level. Used for supply risk dashboards and exception-based inventory management reporting.. Valid values are `true|false`',
    `blocked_quantity` DECIMAL(18,2) COMMENT 'Quantity of the SKU that is blocked from use due to quality rejection, damage, or administrative hold at the time of snapshot. Requires a Corrective and Preventive Action (CAPA) or disposition decision before release.',
    `company_code` STRING COMMENT 'SAP S/4HANA company code representing the legal entity that owns the inventory. Used for intercompany inventory reconciliation, financial consolidation, and statutory reporting.. Valid values are `^[A-Z0-9]{4}$`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the plant or distribution center where the inventory is held. Supports multi-country regulatory reporting, customs compliance, and geographic inventory analysis.. Valid values are `^[A-Z]{3}$`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code in which the valuation amount and price per unit are expressed. Supports multi-currency reporting for multinational operations.. Valid values are `^[A-Z]{3}$`',
    `date` DATE COMMENT 'The calendar date on which the inventory position was captured. Used for period-end financial closing, historical trending, and regulatory reporting. Aligns with fiscal period boundaries in SAP S/4HANA.. Valid values are `^d{4}-d{2}-d{2}$`',
    `fiscal_period` STRING COMMENT 'The fiscal posting period (01–16) within the fiscal year to which this snapshot belongs. Supports monthly financial close cycles and period-over-period inventory analysis in SAP S/4HANA.. Valid values are `^(0[1-9]|1[0-6])$`',
    `fiscal_year` STRING COMMENT 'The fiscal year to which this inventory snapshot belongs, as defined in SAP S/4HANA FI/CO configuration. Used for financial period closing and year-end inventory valuation reporting.. Valid values are `^d{4}$`',
    `in_transit_quantity` DECIMAL(18,2) COMMENT 'Quantity of the SKU that has been goods-issued from the source location but not yet goods-receipted at the destination at the time of snapshot. Relevant for interplant stock transfers and inbound deliveries.',
    `infor_wms_snapshot_ref` STRING COMMENT 'Reference identifier from Infor WMS for the corresponding inventory snapshot or stock count record. Used for cross-system reconciliation between SAP S/4HANA and Infor WMS inventory positions.',
    `inventory_category` STRING COMMENT 'Business category of the inventory indicating ownership and allocation. Distinguishes own stock from customer consignment, project-specific stock, and sales order stock for accurate financial reporting.. Valid values are `own_stock|consignment|project_stock|sales_order_stock|returnable_packaging|pipeline`',
    `material_description` STRING COMMENT 'Short description of the SKU/material at the time of snapshot. Denormalized for historical accuracy so that description changes after the snapshot date do not alter historical records.',
    `material_type` STRING COMMENT 'Classification of the inventory item by its role in the manufacturing process. Distinguishes raw materials, Work In Progress (WIP), finished goods, and Maintenance Repair and Operations (MRO) stock for financial and operational reporting.. Valid values are `raw_material|semi_finished|finished_good|wip|mro|trading_good|packaging|spare_part|consumable`',
    `notes` STRING COMMENT 'Free-text field for capturing additional context about the snapshot, such as reasons for manual triggers, known discrepancies, or regulatory reporting notes. Used by inventory planners and auditors.',
    `plant_code` STRING COMMENT 'SAP S/4HANA plant identifier representing the manufacturing facility or distribution center where the inventory is held. Used for multi-plant inventory analysis and intercompany reporting.. Valid values are `^[A-Z0-9]{4}$`',
    `quality_inspection_quantity` DECIMAL(18,2) COMMENT 'Quantity of the SKU held in quality inspection stock pending QM usage decision at the time of snapshot. Not available for consumption until released by Quality Assurance.',
    `quantity_on_hand` DECIMAL(18,2) COMMENT 'Total physical quantity of the SKU present at the plant/storage location at the time of snapshot, regardless of stock type. Represents the gross inventory position before any reservations or holds.',
    `reorder_point_quantity` DECIMAL(18,2) COMMENT 'Stock level at which a replenishment order should be triggered for the SKU at the plant level, as configured in SAP S/4HANA MRP. Enables assessment of whether the snapshot position requires immediate replenishment action.',
    `reserved_quantity` DECIMAL(18,2) COMMENT 'Quantity of the SKU that has been reserved against production orders, sales orders, or transfer orders at the time of snapshot. Reduces the Available to Promise (ATP) quantity for demand fulfillment.',
    `safety_stock_quantity` DECIMAL(18,2) COMMENT 'Minimum buffer stock quantity defined for the SKU at the plant level at the time of snapshot. Used to assess whether current on-hand quantity is above or below the safety stock threshold for supply risk analysis.',
    `sap_material_document` STRING COMMENT 'SAP S/4HANA material document number associated with the last inventory movement prior to the snapshot. Provides traceability back to the originating goods movement transaction in the system of record.',
    `sku_number` STRING COMMENT 'The material/SKU number identifying the specific inventory item being snapshotted. Corresponds to the SAP S/4HANA material number (MATNR) and Infor WMS item code. Links to the inventory.sku master.',
    `slow_moving_flag` BOOLEAN COMMENT 'Indicates whether the SKU has been classified as slow-moving at the time of snapshot based on consumption velocity thresholds. Used for inventory write-down risk assessment and working capital optimization.. Valid values are `true|false`',
    `source_system` STRING COMMENT 'Operational system of record from which the inventory snapshot data was extracted. Identifies whether the snapshot originated from SAP S/4HANA MM, Infor WMS, or was manually entered, supporting data lineage and reconciliation.. Valid values are `SAP_S4HANA|INFOR_WMS|MANUAL`',
    `status` STRING COMMENT 'Lifecycle status of the snapshot record. Active records represent the current valid snapshot; superseded records have been replaced by a corrected snapshot; voided records were cancelled before use in financial reporting.. Valid values are `active|superseded|voided|under_review`',
    `stock_type` STRING COMMENT 'Classification of the inventory stock by its usability status at the time of snapshot. Unrestricted stock is available for use; quality inspection stock is pending QM release; blocked stock is not available for use. Aligns with SAP S/4HANA stock type categories.. Valid values are `unrestricted|quality_inspection|blocked|restricted|in_transit|consignment|returns|vendor_consignment`',
    `storage_location_code` STRING COMMENT 'SAP S/4HANA storage location identifier within the plant where the inventory is physically stored. Enables granular location-level inventory analysis and reconciliation with Infor WMS.. Valid values are `^[A-Z0-9]{4}$`',
    `timestamp` TIMESTAMP COMMENT 'Precise date and time at which the inventory snapshot was taken. Enables sub-day precision for intraday snapshots and audit trail purposes. Stored in ISO 8601 format with timezone offset.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `trigger` STRING COMMENT 'The business event or schedule that initiated the inventory snapshot. Distinguishes between automated period-end captures, manual triggers by planners, and regulatory-driven snapshots required for compliance reporting.. Valid values are `period_end_daily|period_end_weekly|period_end_monthly|period_end_quarterly|period_end_annual|manual|regulatory|financial_close|audit|ad_hoc`',
    `unit_of_measure` STRING COMMENT 'Base unit of measure in which all quantity fields are expressed for this snapshot record. Aligns with the SAP S/4HANA material master base unit of measure (MEINS).. Valid values are `EA|KG|G|LB|L|ML|M|M2|M3|FT|IN|PC|PAL|BOX|ROL|SET|HR|MIN`',
    `unrestricted_quantity` DECIMAL(18,2) COMMENT 'Quantity of the SKU that is freely available for use, sale, or transfer without any quality or business holds at the time of snapshot. Used for Available to Promise (ATP) calculations and supply planning.',
    `valuation_amount` DECIMAL(18,2) COMMENT 'Total monetary value of the on-hand inventory quantity at the time of snapshot, calculated using the applicable valuation method (standard price or moving average price). Used for balance sheet inventory valuation and financial period closing.',
    `valuation_method` STRING COMMENT 'Inventory costing method applied to determine the monetary value of stock at the time of snapshot. Standard Price is typical for manufactured goods; Moving Average Price for purchased materials. Governs financial reporting under IFRS IAS 2 and GAAP ASC 330.. Valid values are `standard_price|moving_average_price|fifo|lifo|weighted_average`',
    `valuation_price_per_unit` DECIMAL(18,2) COMMENT 'Unit cost used to calculate the total valuation amount at the time of snapshot. Reflects either the standard price or moving average price depending on the valuation method configured for the material.',
    `warehouse_number` STRING COMMENT 'Warehouse Management System (WMS) warehouse number corresponding to the physical warehouse facility. Used for WMS-level inventory reconciliation between SAP S/4HANA WM and Infor WMS.',
    CONSTRAINT pk_snapshot PRIMARY KEY(`snapshot_id`)
) COMMENT 'Periodic point-in-time snapshot of inventory positions captured at period-end (daily, weekly, monthly) for historical trending, financial period closing, and regulatory reporting. Records snapshot date, SKU, plant, storage location, stock type, quantity on hand, quantity reserved, quantity in transit, valuation amount, and snapshot trigger (period-end, manual, regulatory). Enables historical inventory analysis without querying live transactional stock positions.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`inventory`.`sku_pricing` (
    `sku_pricing_id` BIGINT COMMENT 'Primary key for the sku_pricing association',
    `inventory_sku_id` BIGINT COMMENT 'Foreign key linking to the specific SKU to which these negotiated pricing terms apply',
    `pricing_agreement_id` BIGINT COMMENT 'Foreign key linking to the parent pricing agreement that governs this SKU-specific pricing term',
    `agreed_price` DECIMAL(18,2) COMMENT 'The negotiated net unit price for the product or product group covered by this agreement. Applicable when agreement_type is customer_specific_price or contract_price. Expressed in the agreement currency. Null when the agreement is discount-based rather than price-based. [Moved from pricing_agreement: This attribute represents the negotiated price for a specific SKU within the agreement. In the M:N model, this becomes contract_price in the association, as each SKU can have a different negotiated price under the same agreement.]',
    `contract_price` DECIMAL(18,2) COMMENT 'The specific negotiated net unit price for this SKU under this pricing agreement. Overrides standard list price and is customer-specific.',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp when this SKU pricing line was added to the pricing agreement.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code in which the contract_price is denominated for this SKU.',
    `effective_date` DATE COMMENT 'The date from which this specific SKU pricing becomes effective within the broader pricing agreement. May differ from the agreement-level valid_from if SKUs are added mid-term.',
    `expiry_date` DATE COMMENT 'The date after which this specific SKU pricing is no longer valid. May differ from the agreement-level valid_to if SKUs are removed or repriced mid-term.',
    `lead_time_days` STRING COMMENT 'The committed delivery lead time in days for this SKU under this pricing agreement. Represents the service level commitment tied to the negotiated pricing.',
    `minimum_order_quantity` DECIMAL(18,2) COMMENT 'The minimum quantity that must be ordered for this specific SKU to qualify for the negotiated pricing. SKU-level MOQ that may differ from agreement-level MOQ.',
    `modified_timestamp` TIMESTAMP COMMENT 'System timestamp when this SKU pricing line was last modified.',
    `price_unit` STRING COMMENT 'The unit of measure to which the agreed price applies, aligned with SAP S/4HANA condition record pricing unit. For example, EA (each), KG (kilogram), M (meter). Ensures correct price calculation per sales order line item. [Moved from pricing_agreement: This is SKU-specific and should move to the association as price_unit_of_measure, since different SKUs within the same agreement may be priced in different units (EA vs KG vs M).]. Valid values are `EA|PC|KG|M|M2|M3|L|SET|BOX|PAL|LOT`',
    `price_unit_of_measure` STRING COMMENT 'The unit of measure to which the contract_price applies for this SKU (e.g., EA, KG, M). Must be convertible to the SKUs base_unit_of_measure.',
    `scope_description` STRING COMMENT 'Human-readable description of the product or product group scope covered by this pricing agreement, e.g., Automation Drive Series – 400V Range or All Switchgear Products. Supports business reporting and contract review. [Moved from pricing_agreement: When scope_type is SKU, this is a denormalized copy of the SKU description. The association model provides direct access to sku.description via the FK relationship, eliminating the need for this denormalized field.]',
    `scope_reference` STRING COMMENT 'The specific identifier of the product, product group, material group, or product hierarchy node to which this pricing agreement applies. Populated based on scope_type. For example, a SAP material number, product group code, or hierarchy node ID. [Moved from pricing_agreement: When scope_type is SKU, this attribute contains the SKU identifier and should be replaced by the sku_id foreign key in the association. The association model makes this attribute redundant for SKU-level pricing.]',
    `status` STRING COMMENT 'Current lifecycle status of this specific SKU pricing line. Controls whether this SKU-customer pricing combination is currently applicable in order processing.',
    `volume_tier` STRING COMMENT 'The volume tier or bracket that applies to this SKU within the pricing agreement (e.g., Tier 1: 0-1000 units, Tier 2: 1001-5000 units). Determines applicable pricing and rebate levels.',
    CONSTRAINT pk_sku_pricing PRIMARY KEY(`sku_pricing_id`)
) COMMENT 'This association product represents the Contract between pricing_agreement and sku. It captures the specific negotiated pricing terms, volume commitments, and commercial conditions that apply to each SKU within a customer pricing agreement. Each record links one pricing_agreement to one sku with attributes that define the unique commercial terms for that specific customer-SKU combination.. Existence Justification: In industrial manufacturing, customer pricing agreements routinely cover multiple SKUs (motors, drives, control panels, sensors) with SKU-specific negotiated prices, volume tiers, and lead times. A single OEM customer may have one master pricing agreement covering 50-200 different SKUs, each with unique pricing based on volume commitments, manufacturing complexity, and competitive positioning. Conversely, a high-volume SKU like a standard motor may have different negotiated prices across 20+ customer agreements based on each customers strategic importance and volume commitments.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`inventory`.`warehouse_carrier_agreement` (
    `warehouse_carrier_agreement_id` BIGINT COMMENT 'Unique system-generated surrogate identifier for each warehouse-carrier service agreement record',
    `carrier_id` BIGINT COMMENT 'Foreign key linking to the approved freight carrier providing services under this agreement',
    `warehouse_id` BIGINT COMMENT 'Foreign key linking to the warehouse facility where this carrier service agreement applies',
    `contract_terms` STRING COMMENT 'Reference to the specific contract terms, addendums, or master service agreement clauses that govern this warehouse-carrier relationship, including liability limits, insurance requirements, and performance penalties. This attribute was explicitly identified in the detection phase as relationship-specific data.',
    `created_date` TIMESTAMP COMMENT 'System timestamp when this warehouse-carrier agreement record was created in the TMS',
    `effective_date` DATE COMMENT 'The date when this warehouse-carrier service agreement became effective and operational, used for historical tracking and rate/SLA version control. This attribute was explicitly identified in the detection phase as relationship-specific data.',
    `expiration_date` DATE COMMENT 'The date when this warehouse-carrier service agreement expires or requires renewal, triggering contract renegotiation workflows',
    `last_modified_date` TIMESTAMP COMMENT 'System timestamp when this warehouse-carrier agreement record was last updated',
    `minimum_shipment_volume` STRING COMMENT 'The minimum number of shipments per month committed from this warehouse to this carrier to maintain negotiated rates and service levels',
    `pickup_schedule` STRING COMMENT 'The agreed-upon pickup schedule for this carrier at this warehouse facility, specifying days of week and time windows when the carrier will collect outbound shipments (e.g., Mon-Fri 3:00PM, Daily 5:00PM, Tue/Thu 2:00PM). This attribute was explicitly identified in the detection phase as relationship-specific data.',
    `preferred_status` BOOLEAN COMMENT 'Indicates whether this carrier has preferred status for shipments from this warehouse, used in TMS carrier selection logic to prioritize this carrier when multiple options are available. This attribute was explicitly identified in the detection phase as relationship-specific data.',
    `rate_discount` DECIMAL(18,2) COMMENT 'The percentage discount off standard carrier rates negotiated specifically for shipments from this warehouse facility, reflecting volume commitments or strategic partnership terms. This attribute was explicitly identified in the detection phase as relationship-specific data.',
    `service_level_agreement` STRING COMMENT 'The negotiated service level commitment for shipments from this warehouse using this carrier, defining delivery speed expectations (e.g., same-day, next-day, 2-day, ground, freight). This attribute was explicitly identified in the detection phase as relationship-specific data.',
    `status` STRING COMMENT 'Current operational status of this warehouse-carrier agreement, controlling whether this carrier option is available for shipment planning from this warehouse',
    CONSTRAINT pk_warehouse_carrier_agreement PRIMARY KEY(`warehouse_carrier_agreement_id`)
) COMMENT 'This association product represents the operational service agreement between a warehouse facility and an approved freight carrier. It captures the negotiated terms, service levels, pickup schedules, and performance commitments that govern outbound shipping operations from each warehouse-carrier combination. Each record links one warehouse to one carrier with relationship-specific attributes including SLA terms, preferred carrier status, rate discounts, pickup schedules, and contract effective dates that exist only in the context of this specific warehouse-carrier pairing.. Existence Justification: In industrial manufacturing logistics operations, warehouses maintain service agreements with multiple carriers to support different shipping requirements (express vs. ground, domestic vs. international, LTL vs. FTL), and carriers service multiple warehouse facilities across the distribution network. Each warehouse-carrier pairing has its own negotiated terms including pickup schedules, rate discounts, SLA commitments, and preferred status that are actively managed by logistics teams and used daily in TMS carrier selection and route planning.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`inventory`.`consumption` (
    `consumption_id` BIGINT COMMENT 'Unique surrogate identifier for each equipment-SKU consumption relationship record',
    `equipment_id` BIGINT COMMENT 'Foreign key linking to the equipment that consumes the SKU',
    `inventory_sku_id` BIGINT COMMENT 'Foreign key linking to the SKU consumed by the equipment',
    `created_date` TIMESTAMP COMMENT 'Timestamp when this consumption relationship record was created in the system',
    `criticality_level` STRING COMMENT 'Criticality classification of this SKU for this specific equipment. A SKU may be critical for one machine but low criticality for another. Drives safety stock and expedite decisions.',
    `first_usage_date` DATE COMMENT 'Date this equipment-SKU consumption relationship was first established, typically when the equipment was commissioned or when a new consumable was introduced.',
    `last_usage_date` DATE COMMENT 'Most recent date this SKU was consumed or issued for use by this equipment. Used to identify obsolete consumption relationships and optimize inventory.',
    `lead_time_days` STRING COMMENT 'Expected lead time in days to replenish this SKU for this equipment, accounting for procurement, receiving, and internal logistics to the equipment location. May differ from standard SKU lead time due to location-specific factors.',
    `maintenance_plan_reference` STRING COMMENT 'Reference to the maintenance plan or preventive maintenance task that drives consumption of this SKU (e.g., PM-12345). Links consumption to scheduled maintenance activities.',
    `preferred_stock_level` DECIMAL(18,2) COMMENT 'Target inventory level for this SKU at or near this equipment location, in base unit of measure. Calculated based on consumption rate, lead time, and criticality. Used for equipment-specific inventory optimization.',
    `rate` DECIMAL(18,2) COMMENT 'Average consumption rate of this SKU by this equipment, measured in base unit of measure per operating hour or cycle. Used for predictive ordering calculations.',
    `rate_uom` STRING COMMENT 'Unit of measure for the consumption rate (e.g., liters per hour, pieces per cycle)',
    `status` STRING COMMENT 'Current status of this consumption relationship. ACTIVE = currently consuming, INACTIVE = temporarily not in use, OBSOLETE = equipment upgraded or SKU replaced, PLANNED = future consumption expected.',
    `updated_date` TIMESTAMP COMMENT 'Timestamp when this consumption relationship record was last updated',
    CONSTRAINT pk_consumption PRIMARY KEY(`consumption_id`)
) COMMENT 'This association product represents the operational consumption relationship between equipment and SKUs. It captures the consumption patterns, criticality, and inventory planning parameters for each equipment-SKU pairing. Each record links one equipment asset to one SKU with attributes that exist only in the context of this consumption relationship, enabling predictive maintenance ordering and equipment-specific inventory optimization.. Existence Justification: In manufacturing operations, equipment consumes multiple different SKUs (hydraulic oil, lubricants, filters, spare parts, consumables), and each SKU is consumed by multiple pieces of equipment across the plant. Maintenance planners and reliability engineers actively manage these consumption relationships as operational entities, tracking consumption rates, criticality levels, preferred stock levels, and lead times for each equipment-SKU pairing to enable predictive ordering and equipment-specific inventory optimization.';

